window.COURSE_LANG["c16-fire-sprinkler"] = window.COURSE_LANG["c16-fire-sprinkler"] || {};
window.COURSE_LANG["c16-fire-sprinkler"]["ru"] = [
  {id:1, q:"Классический «треугольник огня» представляет три элемента, которые должны присутствовать для горения. В каком наборе они перечислены правильно?", opts:["Давление, скорость и плотность","Вода, воздух и электричество","Дым, пламя и зола","Топливо, кислород (окислитель) и тепло"], re:"Треугольник огня — это топливо, окислитель (обычно кислород) и тепло; уберите любой из них, и горение прекратится. Это основа пожаротушения. Источник: основы науки о пожаре NFPA; обзор тетраэдра огня WFCA."},
  {id:2, q:"«Тетраэдр огня» добавляет четвёртый элемент к треугольнику огня. Что это за четвёртый элемент?", opts:["Самоподдерживающаяся химическая цепная реакция","Только искра воспламенения","Источник топлива под давлением","Замкнутое пространство"], re:"Тетраэдр добавляет неингибированную химическую цепную реакцию к топливу, кислороду и теплу. Такие агенты, как чистые агенты/галон, действуют, прерывая эту реакцию. Источник: WFCA 'Fire Tetrahedron Explained'; тетраэдр огня Firetrace."},
  {id:3, q:"Спринклерная система пожаротушения на водной основе тушит или контролирует пожар главным образом за счёт какого основного механизма?", opts:["Охлаждение — отведение тепла от огня и поверхности топлива","Перекрытие доступа кислорода к топливу пенным покрытием","Добавление кислорода для разбавления дыма","Электрическое прерывание пламени"], re:"Высокая теплоёмкость и теплота парообразования воды делают охлаждение (отведение тепла) её доминирующим способом тушения; она также обеспечивает некоторое смачивание/предварительное смачивание поверхности. Источник: основы науки о пожаре NFPA; методы тушения тетраэдра огня."},
  {id:4, q:"Приблизительно какой процент кислорода содержит обычный воздух, от которого зависит горение?", opts:["Около 5 процентов","Около 50 процентов","Около 21 процента","Около 78 процентов"], re:"Воздух содержит примерно 21% кислорода (и ~78% азота); большинство пламенного горения подавляется, когда кислород падает ниже ~15-16%. Источник: тетраэдр огня WFCA (кислород ~21%, пожарам нужен минимум ~16%)."},
  {id:5, q:"Какой из трёх способов теплопередачи НАИБОЛЕЕ ответственен за перенос горячих газов пожара к термочувствительному элементу спринклера на потолке и его срабатывание?", opts:["Теплопроводность через стальные конструкции здания","Излучение от холодных поверхностей","Конвекция — восходящий поток горячих газов","Испарение антифриза"], re:"Конвекция (всплывающий поток горячих газов, образующий потолочную струю) оказывает наибольшее влияние на срабатывание спринклера; потолочная струя нагревает термочувствительный элемент. Источник: NFSA 'Fire Dynamics and Sprinkler Activation.'"},
  {id:6, q:"Теплопередача путём прямого контакта через твёрдый материал (например, горячая труба нагревает соседний элемент) называется:", opts:["Конвекция","Излучение","Теплопроводность","Сублимация"], re:"Теплопроводность — это теплопередача внутри твёрдых тел или между твёрдыми телами в контакте. Конвекция переносит тепло движением жидкости/газа; излучение — электромагнитными волнами. Источник: основы поведения пожара и теплопередачи (Warren Forensics; Adaston)."},
  {id:7, q:"Теплопередача электромагнитными волнами, которые могут воспламенить материалы через воздушный зазор без контакта, называется:", opts:["Конвекция","Теплопроводность","Излучение","Диффузия"], re:"Излучение передаёт тепло в виде электромагнитных волн и может воспламенить материалы на расстоянии (например, разбивая окна, поджигая соседние здания). Источник: основы теплопередачи (Warren Forensics; Ark-FP)."},
  {id:8, q:"Пожар класса A связан с каким типом топлива?", opts:["Электрооборудование под напряжением","Обычные горючие материалы, такие как дерево, бумага и ткань","Легковоспламеняющиеся жидкости, такие как бензин","Горючие металлы, такие как магний"], re:"Класс A = обычные горючие материалы (дерево, бумага, ткань, многие пластмассы); вода хорошо подходит для пожаров класса A. Источник: определения классов пожара NFPA 10; классы пожара Pye-Barker."},
  {id:9, q:"Какой класс пожара связан с легковоспламеняющимися или горючими ЖИДКОСТЯМИ и газами (бензин, масло, растворители)?", opts:["Класс A","Класс C","Класс B","Класс D"], re:"Класс B = легковоспламеняющиеся жидкости и газы (бензин, масло, растворители). Чистая вода может распространять эти пожары, поэтому используются пена или другие агенты. Источник: определения классов пожара NFPA 10; Swartz Fire & Safety."},
  {id:10, q:"Какой класс пожара связан с электрооборудованием ПОД НАПРЯЖЕНИЕМ, где проводящий агент, такой как вода, опасен?", opts:["Класс B","Класс A","Класс C","Класс K"], re:"Класс C = пожары в электрооборудовании под напряжением; требуются непроводящие агенты. После снятия напряжения он может стать пожаром класса A или B. Источник: NFPA 10; классы пожара UCLA Health."},
  {id:11, q:"Пожары класса K, требующие специальных мокрых химических агентов, связаны с каким топливом?", opts:["Кулинарные масла и жиры (коммерческие кухни)","Горючие металлы","Электроника под напряжением","Бумага и дерево"], re:"Класс K = кулинарные масла/жиры; мокрые химические агенты омыляют жир, охлаждая и герметизируя его от повторного воспламенения. Источник: NFPA 10; NFPA 17A / классы пожара Pye-Barker."},
  {id:12, q:"Когда вода поглощает тепло и превращается в пар, большое расширение в объёме помогает тушению за счёт:", opts:["Добавления топлива в огонь","Вытеснения кислорода вокруг огня и поглощения тепла","Усиления химической цепной реакции","Повышения температуры топлива"], re:"Превращение в пар поглощает большое количество тепла (скрытая теплота парообразования), а расширение пара вытесняет кислород вблизи очага пожара, помогая контролю. Источник: основы пожаротушения; вода как агент класса A (NFPA)."},
  {id:13, q:"Температура, при которой материал выделяет достаточно паров, чтобы воспламениться на мгновение при наличии источника воспламенения, называется его:", opts:["Точкой кипения","Точкой замерзания","Температурой вспышки","Удельной теплоёмкостью"], re:"Температура вспышки — это наименьшая температура, при которой жидкость выделяет пар в достаточной концентрации для вспышки (мгновенного воспламенения) вблизи источника воспламенения. Источник: NFPA 30 / основы науки о пожаре (легковоспламеняющиеся и горючие жидкости)."},
  {id:14, q:"«Объёмная вспышка» (flashover) при пожаре в помещении означает:", opts:["Появление первого видимого пламени","Электрическое короткое замыкание","Мгновенное превращение воды в пар у спринклера","Почти одновременное воспламенение всех открытых горючих материалов в помещении при достижении полного охвата"], re:"Объёмная вспышка — это переход к полному охвату помещения, когда лучистое тепло воспламеняет почти все открытые поверхности одновременно. Бытовые спринклеры (NFPA 13D) нацелены на предотвращение объёмной вспышки для обеспечения эвакуации. Источник: основы динамики пожара; цель безопасности жизни NFPA 13D."},
  {id:15, q:"По сравнению с простым «контролем» пожара, «подавить» пожар означает:", opts:["Только подать сигнал тревоги","Резко снизить скорость тепловыделения и предотвратить повторное разрастание, работая в направлении полного тушения","Поддерживать размер огня постоянным","Удалять дым из здания"], re:"Контроль ограничивает рост пожара и предварительно смачивает окружение; подавление резко снижает тепловыделение и предотвращает повторное разрастание (цель спринклеров ESFR). Источник: концепции контроля и подавления NFPA 13; замысел проектирования ESFR."},
  {id:16, q:"Почему чистая вода обычно НЕ рекомендуется в качестве основного агента при пожаре пролива легковоспламеняющейся жидкости класса B?", opts:["Она слишком быстро замерзает","Топливо легче воды может всплывать и распространяться, а вода может разбрызгивать горящую жидкость","Вода добавляет азот в огонь","Вода непроводящая"], re:"Многие легковоспламеняющиеся жидкости легче воды и не смешиваются с ней, поэтому струя воды может распространять горящее топливо; для таких пожаров используется пена (а не чистая вода). Источник: NFPA 10/11; выбор агентов по классу пожара."},
  {id:17, q:"С точки зрения пожаротушения, нанесение пенного покрытия на поверхность жидкого топлива работает в основном за счёт:", opts:["Электрического охлаждения цепной реакции","Отделения топлива от кислорода (и подавления паров)","Добавления кислорода","Увеличения лучистого тепла"], re:"Пена покрывает топливо, исключая кислород и подавляя легковоспламеняющиеся пары (она также охлаждает). Это воздействует на грани кислорода и паров топлива тетраэдра. Источник: основы пены NFPA 11; методы тушения тетраэдра огня."},
  {id:18, q:"В спринклерной системе с мокрым трубопроводом трубопровод обычно заполнен:", opts:["Только воздухом под давлением","Водой под давлением","Азотом под давлением","Газообразным антифризом"], re:"Система с мокрым трубопроводом имеет трубопровод, постоянно заполненный водой под давлением, поэтому вода поступает немедленно при открытии спринклера. Источник: определение системы с мокрым трубопроводом NFPA 13; NFPA 'Types of Sprinkler Systems.'"},
  {id:19, q:"Какое утверждение о скорости подачи воды верно для систем с мокрым трубопроводом?", opts:["Они самые медленные из всех типов систем","Они подают воду быстрее, чем сухотрубные, предварительного действия или дренчерные системы, потому что вода уже у спринклера","Они подают воду только после срабатывания извещателя","Им требуется ускоритель для подачи воды"], re:"Поскольку вода уже находится в трубопроводе без промежуточного срабатывания, системы с мокрым трубопроводом подают воду быстрее, чем любой другой тип системы, минимизируя рост пожара. Источник: NFPA 'Sprinkler System Basics: Types of Sprinkler Systems.'"},
  {id:20, q:"Какое единственное самое большое ограничение делает стандартную систему с мокрым трубопроводом непригодной для некоторых зон?", opts:["Её нельзя использовать выше 2 этажей","Она не может использовать спринклеры скрытого монтажа","Ей требуются генераторы азота","Вода в трубопроводе может замёрзнуть в неотапливаемых/морозных помещениях"], re:"Застойная вода в мокром трубопроводе делает его непригодным для зон, подверженных замерзанию, если они не защищены (например, антифризный контур или вместо этого сухотрубная/предварительного действия система). Источник: NFPA 13; различия мокрой и сухой систем Ryan F.P."},
  {id:21, q:"В системе с мокрым трубопроводом отдельный спринклер срабатывает (открывается), когда:", opts:["Дымовой извещатель посылает сигнал","Панель пожарной сигнализации даёт команду","Его термочувствительный элемент (стеклянная колба или плавкий замок) достигает номинальной температуры","Активируется ручной извещатель"], re:"Каждый закрытый спринклер открывается индивидуально, когда его собственный термочувствительный элемент достигает номинальной температуры; срабатывают только спринклеры над огнём. Источник: NFPA 13; руководство по термочувствительности QRFS."},
  {id:22, q:"Распространённое заблуждение — что «все спринклеры срабатывают одновременно» при пожаре. В типичной системе с мокрым трубопроводом:", opts:["Каждый спринклер в здании срабатывает вместе","Ни один спринклер не работает без панели сигнализации","Срабатывает половина спринклеров здания","Срабатывают только спринклер(ы), термочувствительный элемент которых достиг номинальной температуры"], re:"Стандартные спринклеры активируются индивидуально по теплу; обычно открываются только один или несколько над огнём, в отличие от дренчерной системы. Источник: материалы общественного просвещения NFPA; работа NFPA 13."},
  {id:23, q:"Какой клапан обычно используется на стояке с мокрым трубопроводом для обнаружения потока воды и подачи сигнала тревоги?", opts:["Сигнальный обратный клапан (alarm check valve)","Дренчерный клапан","Клапан сухотрубной системы","Редукционный клапан давления"], re:"Стояк с мокрым трубопроводом обычно использует сигнальный обратный клапан (или стояк типа «дробовик» с реле потока) для обнаружения потока и подачи сигнала тревоги по потоку воды. Источник: Code Red Consultants 'Alarm Check Valves'; компоненты стояка NFPA 13."},
  {id:24, q:"В системе с мокрым трубопроводом назначение КАМЕРЫ ЗАМЕДЛЕНИЯ (retard chamber), связанной с сигнальным обратным клапаном, состоит в том, чтобы:", opts:["Хранить антифриз","Снижать ложные срабатывания от кратковременных скачков давления воды","Ускорять подачу воды","Сливать всю систему"], re:"Камера замедления добавляет короткую механическую задержку, чтобы мгновенные скачки давления подачи не вызывали сигнал тревоги по потоку воды; она заполняется прежде, чем сработает сигнал. Источник: NFPA 13; обвязка сигнального обратного клапана Code Red Consultants."},
  {id:25, q:"Водяной гонг (механическая сигнализация) в мокрой системе приводится в действие:", opts:["Электропитанием здания","Только давлением/потоком воды","Только резервной батареей","Сжатым воздухом"], re:"Водяной гонг приводится в действие гидравлически потоком воды системы и не нуждается в электричестве, обеспечивая слышимую механическую сигнализацию. Источник: QRFS 'How Does a Water Motor Gong Work.'"},
  {id:26, q:"Что из перечисленного является ключевым ПРЕИМУЩЕСТВОМ систем с мокрым трубопроводом перед другими типами?", opts:["Простота, надёжность, низкое обслуживание и самая быстрая подача воды","Они наиболее механически сложны","Им никогда не нужны сливы","Они устраняют необходимость в водоснабжении"], re:"Системы с мокрым трубопроводом — самые простые и надёжные, с наименьшим количеством компонентов и самой быстрой подачей воды, поэтому они наиболее широко используются. Источник: NFPA 'Types of Sprinkler Systems'; техническое руководство Engineered Fire Systems."},
  {id:27, q:"Для небольшого, обычно отапливаемого офисного здания какой тип системы обычно является вариантом по умолчанию и наиболее экономичным выбором?", opts:["Дренчерная система","Система предварительного действия с двойной блокировкой","Система с мокрым трубопроводом","Сухотрубная система"], re:"В отапливаемых помещениях система с мокрым трубопроводом обычно является вариантом по умолчанию — самая простая, дешёвая, быстрая. Сухотрубные/предварительного действия/дренчерные резервируются для морозных условий или особых опасностей. Источник: руководство по выбору систем NFPA; руководство Engineered Fire Systems."},
  {id:28, q:"Что позволяет сделать технику основной слив (обычно 2 дюйма) на стояке с мокрым трубопроводом?", opts:["Добавить азот","Увеличить давление воздуха","Слить систему и выполнить испытание потока основного слива системы водоснабжения","Постоянно обойти предотвратитель обратного потока"], re:"Основной слив позволяет слить систему и используется для испытания основного слива, которое проверяет состояние водоснабжения. Источник: испытание основного слива NFPA 13/NFPA 25; компоненты стояка."},
  {id:29, q:"Если в отапливаемом здании есть небольшая неотапливаемая зона (например, навес погрузочной платформы), распространённым решением для мокрой системы только для этой зоны является:", opts:["Преобразование всего здания в дренчерное","Удаление всех спринклеров там","Антифризный контур или сухой скрытый/настенный спринклер от мокрой системы","Заполнение трубопровода зоны азотом"], re:"Небольшие зоны, подверженные замерзанию, от мокрой системы обычно обслуживаются сертифицированным антифризным контуром или сухими скрытыми/настенными спринклерами, которые удерживают воду в отапливаемом пространстве. Источник: положения NFPA 13 об антифризе и сухих спринклерах; руководство по сухим спринклерам QRFS."},
  {id:30, q:"Почему система с мокрым трубопроводом должна поддерживать непрерывное водоснабжение при достаточном давлении?", opts:["Чтобы поддерживать работу воздушного компрессора","Чтобы предотвратить замерзание стеклянных колб","Чтобы любой сработавший спринклер немедленно получал воду с требуемым расходом и давлением","Чтобы держать дренчерный клапан закрытым"], re:"Работа зависит от того, что система водоснабжения подаёт требуемый расход/давление к сработавшим спринклерам; гидравлические расчёты подтверждают, что водоснабжение удовлетворяет потребность. Источник: требования NFPA 13 к водоснабжению и гидравлическому проектированию."},
  {id:31, q:"В системе с мокрым трубопроводом испытательное соединение инспектора используется для:", opts:["Добавления антифриза в систему","Создания давления в системе воздухом","Имитации потока одного спринклера для проверки работы сигнализации по потоку воды","Испытания давления холостого хода пожарного насоса"], re:"Испытательное соединение инспектора выпускает воду с расходом, эквивалентным самому малому отверстию спринклера, чтобы подтвердить работу сигнализации по потоку воды. Источник: испытательное соединение инспектора NFPA 13/NFPA 25."},
  {id:32, q:"Какой термочувствительный элемент спринклера удерживается в закрытом состоянии заполненной жидкостью стеклянной капсулой, которая разрушается при расширении жидкости?", opts:["Спринклер с плавким замком","Устройство быстрого открытия","Открытый (дренчерный) спринклер","Спринклер со стеклянной колбой"], re:"В спринклере со стеклянной колбой нагретая жидкость расширяется, пока колба не разрушится, освобождая крышку. Типы с плавким замком вместо этого используют припойный сплав, который плавится. Источник: термочувствительность спринклеров QRFS; работа спринклеров NFSA."},
  {id:33, q:"«K-фактор» спринклера — это мера спринклера:", opts:["Цвета номинальной температуры","Размера резьбы трубы","Коэффициента расхода — связывающего расход с квадратным корнем давления","Коррозионной стойкости"], re:"K-фактор — это коэффициент расхода в формуле Q = K√P; больший K пропускает больше воды при заданном давлении. Источник: гидравлические принципы NFPA 13; определение K-фактора спринклера."},
  {id:34, q:"Стандартные вертикальные и скрытые распылительные спринклеры обычно имеют номинальный K-фактор около:", opts:["K=1000","K=200","K=0.5","K=5.6 (около 80 в семействе единиц США, например, K5.6/K8.0)"], re:"Спринклеры со стандартным отверстием обычно K5.6 (1/2 дюйма) или K8.0, намного ниже высокорасходных головок ESFR (K14.2-K25.2). Источник: таблицы спринклеров NFPA 13; K-факторы ESFR и стандартных спринклеров CA-FIRE."},
  {id:35, q:"В сухотрубной спринклерной системе трубопровод над клапаном сухотрубной системы обычно заполнен:", opts:["Водой под давлением","Воздухом или азотом под давлением","Раствором антифриза","Концентратом пены"], re:"Сухотрубные системы держат трубопровод под воздухом или азотом под давлением; воздух удерживает клапан сухотрубной системы закрытым, пока спринклер не откроется. Источник: определение сухотрубной системы NFPA 13; руководство по сухим системам QRFS."},
  {id:36, q:"ОСНОВНАЯ причина использования сухотрубной системы вместо системы с мокрым трубопроводом:", opts:["Чтобы подавать воду быстрее","Чтобы избежать необходимости в водоснабжении","Чтобы уменьшить количество спринклеров","Чтобы защитить помещения, подверженные замерзанию, где застойная вода была бы проблемой"], re:"Сухотрубные системы используются там, где морозные температуры заморозили бы воду в мокрой системе (неотапливаемые склады, парковки, морозильники и т. д.). Источник: NFPA 13; QRFS 'A Guide to Dry Sprinkler Systems.'"},
  {id:37, q:"В клапане сухотрубной системы относительно небольшое давление воздуха сдерживает гораздо большее давление воды. Это известно как клапана:", opts:["Потеря на трение","Остаточное давление","Скоростной напор","Дифференциал"], re:"Клапан сухотрубной системы использует дифференциальную конструкцию: большая площадь тарелки со стороны воздуха позволяет умеренному давлению воздуха сдерживать более высокое давление воды (например, соотношение ~5.5:1 или 6:1). Источник: NFSA 'Determining Differential for Dry Pipe Valves.'"},
  {id:38, q:"Если дифференциальный клапан сухотрубной системы имеет дифференциал примерно 6:1, то около 1 psi воздуха может сдержать приблизительно:", opts:["1 psi воды","0.6 psi воды","60 psi воды","6 psi воды"], re:"При дифференциале 6:1, 1 psi воздуха сдерживает около 6 psi воды (например, 30 psi воздуха сдерживают ~180 psi воды). Источник: дифференциальный клапан сухотрубной системы Construction-manuals; статья о дифференциале NFSA."},
  {id:39, q:"Когда спринклер в сухотрубной системе открывается, последовательность такова:", opts:["Вода течёт мгновенно без задержки","Извещатель должен сработать прежде, чем воздух сможет выйти","Сначала выходит воздух, клапан сухотрубной системы срабатывает, затем вода течёт к открытому спринклеру","Дренчерный клапан открывает все спринклеры"], re:"Открытый спринклер стравливает воздух, давление в системе падает, дифференциал теряется, тарелка срабатывает, и вода затем перемещается к открытому спринклеру — по своей природе медленнее, чем мокрый трубопровод. Источник: NFPA 13; работа сухих систем QRFS."},
  {id:40, q:"УСТРОЙСТВО БЫСТРОГО ОТКРЫТИЯ, такое как ускоритель, добавляется к сухотрубной системе, чтобы:", opts:["Ускорить срабатывание клапана сухотрубной системы за счёт ускорения падения давления воздуха у клапана","Замедлить подачу воды","Автоматически добавлять антифриз","Увеличить давление воздуха во время пожара"], re:"Ускоритель определяет падение давления воздуха и перенаправляет воздух в промежуточную камеру клапана, выравнивая давление, чтобы тарелка сработала раньше — сокращая время подачи воды. Источник: Code Red Consultants 'Quick-Opening Devices'; руководство по испытаниям срабатывания QRFS."},
  {id:41, q:"Согласно NFPA 13, сухотрубные системы обычно должны подавать воду к испытательному соединению инспектора в течение скольких секунд (с указанными исключениями для малых/оснащённых QOD систем)?", opts:["10 секунд","30 минут","5 минут","60 секунд"], re:"NFPA 13 устанавливает максимальное время подачи воды 60 секунд к испытательному соединению, с исключениями для систем =500 галлонов, или =750 галлонов с устройством быстрого открытия. Источник: NFPA 13 (2019) 8.2.3; Sprinkler Age 'Dry Pipe Water Delivery Time.'"},
  {id:42, q:"Без устройства быстрого открытия NFPA 13 ограничивает объём отдельной сухотрубной системы максимумом примерно:", opts:["100 галлонов","5,000 галлонов","500 галлонов","50 галлонов"], re:"NFPA 13 ограничивает отдельную сухую систему 500 галлонами без устройства быстрого открытия (и 750 галлонами с ним) для поддержания приемлемого времени подачи. Источник: NFPA 13 8.2.3.3/8.2.3.4; UpCodes 'Size of Systems.'"},
  {id:43, q:"С устройством быстрого открытия NFPA 13 допускает объём отдельной сухотрубной системы до максимума примерно:", opts:["2,000 галлонов","250 галлонов","750 галлонов","100 галлонов"], re:"С устройством быстрого открытия максимальный размер отдельной сухой системы — 750 галлонов; выше этого применяются таблицы времени подачи. Источник: NFPA 13 8.2.3.4; статья о QOD Code Red Consultants."},
  {id:44, q:"Почему сухотрубные системы более подвержены внутренней коррозии, чем системы с мокрым трубопроводом?", opts:["Захваченный воздух плюс остаточная вода/конденсат создают богатые кислородом условия, способствующие коррозии","Они используют только медь","Они работают при более высоком давлении воды","Они содержат антифриз"], re:"Смесь захваченного кислорода (воздуха) с остаточной влагой/конденсатом ускоряет внутреннюю коррозию; часто вместо воздуха используется азот для её снижения. Источник: руководство по коррозии ORR Protection; соображения о коррозии NFPA 13."},
  {id:45, q:"Использование АЗОТА вместо сжатого воздуха в сухой системе в основном помогает за счёт:", opts:["Снижения точки замерзания воды","Устранения необходимости в клапане сухотрубной системы","Увеличения давления воды","Снижения внутренней коррозии, потому что азот инертен (вытесняет кислород)"], re:"Азот инертен и беден кислородом, поэтому он замедляет окисление/коррозию, которую сжатый воздух способствует внутри сухих/предварительного действия трубопроводов. Источник: ORR Protection; техническая заметка об азоте United Fire Systems."},
  {id:46, q:"Поскольку остаточная вода может быть захвачена после срабатывания, сухотрубный трубопровод должен иметь уклон (наклон) так, чтобы:", opts:["Конденсат и вода стекали к клапану сухотрубной системы или к вспомогательным (нижним) сливам","Давление воздуха повышалось автоматически","Спринклеры были направлены вверх","Сигнализация не могла сработать"], re:"NFPA 13 требует, чтобы сухой/предварительного действия трубопровод имел уклон для стока к клапану или к вспомогательным нижним сливам, чтобы захваченная вода не замерзала. Магистрали ~1/4 дюйма/10 футов, ответвления ~1/2 дюйма/10 футов. Источник: требования NFPA 13 к уклону; руководство по уклону FPS-EG."},
  {id:47, q:"«Барабанный слив» (drum drip) или вспомогательный слив в нижней точке сухой системы предусмотрен для:", opts:["Добавления азота в стояк","Испытания пожарного насоса","Ускорения ускорителя","Периодического удаления накопленного конденсата/воды из захваченных нижних участков"], re:"Вспомогательные сливы нижних точек (барабанные сливы) позволяют техникам стравливать конденсат, который собирается в захваченных участках, предотвращая замерзание и коррозию. Источник: руководство по вспомогательным сливам AGF Mfg; вспомогательные сливы NFPA 13."},
  {id:48, q:"NFPA 13 обычно требует, чтобы подача воздуха или азота восстанавливала нормальное давление системы примерно за какое время после падения?", opts:["30 минут","5 секунд","8 часов","3 дня"], re:"Подача воздуха/азота должна быть способна восстановить нормальное давление системы в течение 30 минут; устройство поддержания давления воздуха регулирует подпиточное давление. Источник: NFPA 13 8.2.6; QRFS 'Air Compressors and Air Maintenance Devices.'"},
  {id:49, q:"Какова роль УСТРОЙСТВА ПОДДЕРЖАНИЯ ДАВЛЕНИЯ ВОЗДУХА в сухотрубной системе?", opts:["Оно открывает все спринклеры","Оно регулирует подпиточный воздух, чтобы система оставалась при надлежащем контрольном давлении без избыточного давления","Оно сливает систему после пожара","Оно заменяет клапан сухотрубной системы"], re:"Устройство поддержания давления воздуха (регулятор с дросселем/байпасом) подпитывает мелкие утечки, чтобы поддерживать правильное контрольное давление воздуха, предотвращая быструю дозаправку, которая могла бы замаскировать срабатывание. Источник: руководство по устройству поддержания давления воздуха QRFS; NFPA 13."},
  {id:50, q:"Ключевой компромисс (недостаток) сухотрубных систем по сравнению с системами с мокрым трубопроводом:", opts:["Они стоят меньше и проще","Задержанная подача воды и большая сложность/обслуживание (подача воздуха, сливы, коррозия)","Они не могут защищать морозные зоны","Они не используют клапанов"], re:"Сухие системы жертвуют скоростью и простотой: вода задерживается, и они добавляют подачу воздуха, сливы нижних точек и управление коррозией. Источник: NFPA 'Types of Sprinkler Systems'; руководство Engineered Fire Systems."},
  {id:51, q:"После того как сухотрубная система сработала и восстановлена, почему быстрый слив захваченной воды особенно важен в морозильнике или помещении ниже точки замерзания?", opts:["Потому что захваченная вода может замёрзнуть за минуты и повредить/заблокировать трубопровод","Чтобы перезарядить батарею","Чтобы сбросить дымовые извещатели","Чтобы снизить давление водоснабжения"], re:"В помещениях при/ниже 0°F захваченная вода может начать замерзать за минуты после срабатывания, поэтому нижние точки должны быть быстро слиты. Источник: предотвращение замерзания AGF Mfg; дренаж морозных зон NFPA 13."},
  {id:52, q:"Спринклерную систему предварительного действия можно рассматривать как комбинацию:", opts:["Мокрой системы и сухотруба (standpipe)","Сухотрубной системы плюс отдельной системы пожарообнаружения, которая управляет клапаном предварительного действия","Двух дренчерных клапанов последовательно","Антифризного контура и пожарного насоса"], re:"Системы предварительного действия используют закрытые спринклеры на трубопроводе, удерживаемом сухим (воздух/азот или под контролем), и отдельную систему обнаружения, которая открывает клапан предварительного действия, впуская воду. Источник: NFPA 13; NFPA 'Types of Sprinkler Systems.'"},
  {id:53, q:"ОСНОВНОЕ преимущество системы предварительного действия в том, что она:", opts:["Снижает риск случайного сброса воды там, где ущерб от воды был бы особенно дорогостоящим","Сбрасывает воду из всех головок одновременно","Устраняет необходимость в спринклерах","Подаёт воду быстрее, чем мокрая система"], re:"Требуя события (обнаружения и/или срабатывания спринклера) прежде, чем вода войдёт в трубопровод, предварительное действие защищает от случайного сброса в помещениях, таких как центры обработки данных, архивы и музеи. Источник: NFPA; обзор предварительного действия Impact Fire."},
  {id:54, q:"В системе предварительного действия с ОДИНАРНОЙ БЛОКИРОВКОЙ вода впускается в трубопровод, когда:", opts:["Срабатывает система пожарообнаружения (извещатель срабатывает)","Срабатывает И извещатель, И открывается спринклер","Только открывается спринклер без обнаружения","Открывается основной слив"], re:"Одинарная блокировка впускает воду при срабатывании системы обнаружения (одно событие); закрытые спринклеры затем сбрасывают воду по мере их открытия. Источник: NFPA 13; руководство по одинарной/двойной блокировке SF-Fire."},
  {id:55, q:"В системе предварительного действия с ДВОЙНОЙ БЛОКИРОВКОЙ вода впускается в трубопровод только когда:", opts:["Срабатывает извещатель ИЛИ спринклер (любой из них)","Панель сигнализации теряет питание","Запускается воздушный компрессор","ОБА: срабатывает система обнаружения И открывается спринклер"], re:"Двойная блокировка требует двух независимых событий — обнаружения И срабатывания спринклера (потери воздуха) — прежде чем войдёт вода, обеспечивая наивысшую защиту от случайного сброса (распространено в морозильниках). Источник: NFPA 13; руководство по двойной блокировке SF-Fire."},
  {id:56, q:"В системе предварительного действия БЕЗ БЛОКИРОВКИ вода впускается в трубопровод, когда:", opts:["Только сбрасывается панель сигнализации","Должны сработать И обнаружение, И спринклер","Срабатывает система обнаружения ИЛИ открывается спринклер","Система сливается"], re:"Система без блокировки впускает воду при срабатывании обнаружения ИЛИ спринклеров (любое событие), поэтому даже одно срабатывание спринклера (без обнаружения) впустит воду. Источник: NFPA 13; сравнение блокировок SF-Fire."},
  {id:57, q:"Какое применение является КЛАССИЧЕСКИМ для системы предварительного действия из-за чувствительности к ущербу от воды?", opts:["Центр обработки данных / серверная или архив редких книг","Открытая парковка","Наружная погрузочная платформа","Площадка у бассейна"], re:"Системы предварительного действия предпочтительны для центров обработки данных, телекоммуникационных помещений, архивов, библиотек и музеев, где случайный сброс был бы очень разрушительным. Источник: NFPA; применения предварительного действия Impact Fire."},
  {id:58, q:"Для целей подачи воды система предварительного действия с ДВОЙНОЙ БЛОКИРОВКОЙ обычно рассматривается как:", opts:["Сухотрубная система (подача задержана; большая расчётная площадь)","Система с мокрым трубопроводом","Дренчерная система с открытыми головками","Сухотруб (standpipe)"], re:"Поскольку трубопровод сухой и требуются оба события, системы с двойной блокировкой рассматриваются как сухотрубные системы по времени подачи и используют большую расчётную площадь. Источник: NFPA 13; обсуждение предварительного действия BERMAD/phcppros."},
  {id:59, q:"NFPA 13 ограничивает количество автоматических спринклеров, управляемых одним клапаном предварительного действия, приблизительно:", opts:["10 спринклеров","1,000 спринклеров","100,000 спринклеров","25 спринклеров"], re:"NFPA 13 ограничивает один (с блокировкой) клапан предварительного действия примерно 1,000 автоматических спринклеров. Источник: NFPA 13; заметки по проектированию предварительного действия NY-Engineers / NFSA."},
  {id:60, q:"ДРЕНЧЕРНАЯ система принципиально отличается от мокрых, сухих и предварительного действия систем, потому что она использует:", opts:["Только спринклеры со стеклянными колбами","Антифриз в каждой линии","ОТКРЫТЫЕ спринклеры/насадки (без термочувствительного элемента) на трубопроводе","Камеру замедления вместо клапана"], re:"В дренчерной системе все спринклеры/насадки ОТКРЫТЫ (без термочувствительного элемента); когда дренчерный клапан открывается, вода течёт из каждой головки одновременно. Источник: NFPA 13; NFPA 'Types of Sprinkler Systems.'"},
  {id:61, q:"Дренчерная система сбрасывает воду путём:", opts:["Открытия каждого спринклера индивидуально по мере нагрева","Стравливания воздуха через ускоритель","Плавления плавкого замка на одной головке","Открытия дренчерного клапана (через систему обнаружения), затопляя все открытые головки одновременно"], re:"Система обнаружения (тепло/пламя/дым) открывает дренчерный клапан, и поскольку все головки открыты, вода сбрасывается из всей системы одновременно. Источник: NFPA 13; обзоры дренчерных систем VFP/Oliver."},
  {id:62, q:"Дренчерные системы обычно используются в каком виде опасности?", opts:["Зоны высокой опасности с потенциалом быстрого распространения пожара (авиационные ангары, зоны легковоспламеняющихся жидкостей/химикатов, электростанции)","Офисы низкой опасности","Жилые спальни","Охлаждаемые архивы"], re:"Дренчерные системы подходят для пожаров высокой опасности с быстрым распространением — авиационные ангары (часто водопенные по NFPA 409), объекты легковоспламеняющихся жидкостей и химикатов, и электростанции. Источник: NFPA; применения дренчерных систем Oliver/Interstate."},
  {id:63, q:"Что в основном контролирует, когда дренчерная система сбрасывает воду?", opts:["Отдельная система пожарообнаружения, которая сигнализирует дренчерному клапану открыться","Номинальная температура отдельных головок","Точка замерзания воды","Уклон трубопровода"], re:"Поскольку у головок нет термочувствительного элемента, момент сброса полностью определяется отдельной системой обнаружения, открывающей дренчерный клапан. Источник: NFPA 13; основы дренчерной системы."},
  {id:64, q:"В авиационном ангаре дренчерная система часто комбинируется с каким агентом для контроля пожаров легковоспламеняющихся жидкостей?", opts:["Пожарная пена (водопенный дренчер)","Сухой химический порошок","Затопление углекислым газом","Газ чистого агента"], re:"Большие авиационные ангары обычно используют водопенные дренчерные системы (по NFPA 409) для борьбы с пожарами проливов топлива на больших площадях пола. Источник: NFPA 409; ссылки на водопенный дренчер (Security Fire / исследование ангаров DTIC)."},
  {id:65, q:"Почему системы предварительного действия и дренчерные считаются БОЛЕЕ сложными и требующими интенсивного обслуживания, чем системы с мокрым трубопроводом?", opts:["Они используют меньше деталей","Они зависят от отдельной системы обнаружения и специальных клапанов, которые должны испытываться и обслуживаться","У них совсем нет клапанов","Они никогда не требуют испытаний"], re:"Обе полагаются на оборудование обнаружения и специальные клапаны (предварительного действия/дренчерные), добавляя компоненты, проводку и периодические испытания сверх простой мокрой системы. Источник: NFPA 13/NFPA 25; ссылки на сравнение систем."},
  {id:66, q:"По сравнению с системой предварительного действия с одинарной блокировкой, система с двойной блокировкой обычно обеспечивает:", opts:["Более быструю подачу воды","Отсутствие требования обнаружения","Открытые спринклерные головки","Большую защиту от случайного сброса, но более медленную подачу воды"], re:"Требование как обнаружения, так и срабатывания спринклера максимизирует защиту от непреднамеренного потока воды, но задерживает подачу (рассматривается как сухотрубная). Источник: NFPA 13; сравнение блокировок SF-Fire."},
  {id:67, q:"В системе предварительного действия закрытые спринклеры обычно устанавливаются на трубопроводе, который:", opts:["Всегда заполнен водой в любое время","Заполнен концентратом пены","Обычно сухой / под контролем (мониторинг воздухом или под давлением), с водой, удерживаемой клапаном предварительного действия","Заполнен антифризом в каждом ответвлении"], re:"Трубопровод предварительного действия обычно сухой (часто под контролем с воздухом/азотом низкого давления), и вода удерживается клапаном предварительного действия, пока не произойдёт управляющее событие. Источник: NFPA 13; руководство по проектированию предварительного действия Reliable."},
  {id:68, q:"Открытые насадки дренчерной системы, расположенные для подачи воды на определённую площадь или объект, часто используются для:", opts:["Распределения питьевой воды","Охлаждения/защиты оборудования, такого как трансформаторы или окрасочные камеры","Обогрева здания","Замены пожарной сигнализации"], re:"Дренчерные/водораспылительные системы подают воду на поверхность или объект (трансформаторы, резервуары, окрасочные камеры) для контроля, охлаждения или защиты от воздействия. Источник: водяное распыление NFPA 15 / применения дренчеров NFPA 13."},
  {id:69, q:"Вертикальная труба у источника спринклерной системы, где обычно расположены главный управляющий клапан и устройства сигнализации, называется:", opts:["Ответвлением","Стояком","Поперечной магистралью","Опускным ниппелем (drop nipple)"], re:"Стояк — это вертикальная подающая труба, несущая воду вверх в систему; узел стояка обычно содержит главный управляющий клапан, обратный/сигнальный клапан, манометры и сливы. Источник: компоненты системы NFPA 13; Capitol Fire 'Fire Sprinkler Parts.'"},
  {id:70, q:"В компоновке спринклерного трубопровода трубы, к которым непосредственно прикреплены сами спринклеры, — это:", opts:["Поперечные магистрали","Ответвления","Питающие магистрали","Стояки"], re:"Ответвления — это трубы, несущие спринклеры; ответвления соединяются с поперечными магистралями, которые питаются от питающих магистралей со стояка. Источник: терминология трубопроводов NFPA 13."},
  {id:71, q:"Труба, которая подаёт воду к поперечным магистралям (которые, в свою очередь, питают ответвления), — это:", opts:["Питающая магистраль","Опуск (drop)","Стояк-отвод (sprig)","Поперечина (armover)"], re:"Питающие магистрали подают к поперечным магистралям; поперечные магистрали подают к ответвлениям; ответвления несут спринклеры. Источник: терминология трубопроводов / компоновка системы NFPA 13."},
  {id:72, q:"СОЕДИНЕНИЕ ПОЖАРНОЙ ОХРАНЫ (FDC) в спринклерной системе позволяет пожарной охране:", opts:["Сливать систему в канализацию","Испытывать дымовые извещатели","Перекрывать городскую водопроводную магистраль","Закачивать дополнительную воду/давление в систему со своей техники"], re:"FDC позволяет прибывающей технике повышать воду и давление в спринклерной/сухотрубной системе для дополнения водоснабжения. Источник: FDC NFPA 13/NFPA 14; руководство по компонентам QRFS."},
  {id:73, q:"ОБРАТНЫЙ КЛАПАН в спринклерной системе пожаротушения функционирует, чтобы:", opts:["Снижать температуру воды","Открывать все спринклеры","Пропускать поток воды только в одном направлении и предотвращать обратный поток","Добавлять воздух в систему"], re:"Обратный клапан пропускает поток в одном направлении и предотвращает обратный поток (например, не давая воде системы течь обратно в водоснабжение). Источник: QRFS 'Guide to Check Valves'; NFPA 13."},
  {id:74, q:"Главный управляющий клапан системы (например, индикаторный клапан OS&Y или дисковый затвор) должен быть:", opts:["Скрытым и немаркированным","Удалён во время пожара","Сертифицированным индикаторным клапаном, который показывает, открыт он или закрыт, и под контролем/зафиксирован открытым","Окрашенным в цвет стены"], re:"Управляющие клапаны должны быть сертифицированными индикаторными клапанами, положение открыто/закрыто которых видно, и они должны быть под контролем или заблокированы открытыми, чтобы водоснабжение не было непреднамеренно перекрыто. Источник: управляющие клапаны NFPA 13; контроль клапанов NFPA 25."},
  {id:75, q:"Сигнализатор потока воды/реле давления на стояке спринклера используется для:", opts:["Регулирования концентрации антифриза","Обнаружения движения воды в системе и отправки электрического сигнала тревоги","Создания давления в клапане сухотрубной системы","Снижения давления подачи"], re:"Реле потока воды (давления) определяет поток на стояке и передаёт электрический сигнал на панель сигнализации/звонок для индикации работы системы. Источник: сигнализация потока воды NFPA 13/NFPA 72; компоненты стояка."},
  {id:76, q:"Манометры спринклерной системы на стояке обычно отображают:", opts:["Наружную температуру","Количество установленных спринклеров","Цвет антифриза","Давление воды системы и подачи (и давление воздуха в сухих/предварительного действия системах)"], re:"Манометры стояка показывают давление подачи и системы (а на сухих/предварительного действия стояках — давление воздуха/азота над клапаном). Источник: манометры NFPA 13; компоненты узла стояка."},
  {id:77, q:"СКРЫТЫЙ (pendent) спринклер устанавливается так, чтобы он:", opts:["Указывал вверх над трубой ответвления","Не имел дефлектора","Распылял в сторону от стены","Висел ниже трубы/потолка и распылял воду вниз по круговому рисунку"], re:"Скрытый спринклер висит ниже трубопровода/потолка с дефлектором внизу, распределяя воду вниз и наружу по площади пола. Источник: QRFS 'Fire Sprinkler Head Types'; положение дефлектора NFPA 13."},
  {id:78, q:"ВЕРТИКАЛЬНЫЙ (upright) спринклер устанавливается так, чтобы он:", opts:["Сидел над трубой ответвления и распылял воду вверх к своему дефлектору, который перенаправляет её вниз","Висел ниже трубы","Монтировался горизонтально на стене","Сбрасывал только вверх"], re:"Вертикальный спринклер сидит над ответвлением; вода ударяет в установленный сверху дефлектор и перенаправляется вниз по полусферическому/веерному рисунку (полезно там, где труба открыта). Источник: типы спринклерных головок QRFS; NFPA 13."},
  {id:79, q:"НАСТЕННЫЙ (sidewall) спринклер используется, чтобы:", opts:["Сбрасывать только прямо вниз из центра помещения","Сливать систему","Заменять клапан сухотрубной системы","Монтироваться на стене и подавать воду горизонтально через помещение (полезно там, где верхний трубопровод непрактичен)"], re:"Настенные спринклеры монтируются на стене/балке и подают воду горизонтально с асимметричным дефлектором, используются там, где потолочный трубопровод непрактичен (коридоры, малые помещения). Источник: настенные спринклеры QRFS; NFPA 13."},
  {id:80, q:"ЦВЕТ спринклера со стеклянной колбой (например, красный, оранжевый, зелёный) в основном указывает его:", opts:["Номинальную температуру","Производителя","Размер резьбы трубы","Точный K-фактор"], re:"Цвет жидкости в стеклянной колбе указывает номинальную температуру (например, оранжевый ~135°F, красный ~155°F, зелёный ~200°F); типы с плавким замком используют цветовой код на рычаге рамки. Источник: номинальные температуры NFPA 13; цвета спринклеров NFSA."},
  {id:81, q:"Спринклер с «обычной» номинальной температурой обычно срабатывает в каком приблизительном диапазоне?", opts:["32°F до 60°F","500°F до 650°F","135°F до 170°F","1000°F и выше"], re:"Спринклеры обычного номинала срабатывают примерно при 135-170°F; промежуточный — ~175-225°F, с более высокими классами для более горячих сред. Источник: номинальные температуры NFPA 13; таблицы температур TPMC/Kord."},
  {id:82, q:"Трубопровод и компоненты спринклерной системы, установленные над землёй, обычно рассчитаны на максимальное рабочее давление не менее:", opts:["175 psi","50 psi","1,000 psi","10 psi"], re:"Надземные компоненты NFPA 13 обычно рассчитаны на рабочее давление 175 psi (компоненты более высокого давления требуются там, где давления превышают это). Источник: рейтинг компонентов NFPA 13; обсуждение давления Eng-Tips/NFPA 13."},
  {id:83, q:"Новый спринклерный трубопровод испытывается гидростатически по NFPA 13 при 200 psi, или на каком уровне, если рабочее давление выше?", opts:["Точно при рабочем давлении","При 500 psi независимо","При 10 psi ниже рабочего давления","При 50 psi выше максимального рабочего давления системы"], re:"NFPA 13 требует 2-часового гидростатического испытания при 200 psi, или при 50 psi выше максимального рабочего давления, когда оно превышает 150 psi, в зависимости от того, что больше. Источник: гидростатическое испытание NFPA 13; руководство по испытаниям Fire Safety Central."},
  {id:84, q:"Узел предотвращения обратного потока устанавливается на многих спринклерных системах в основном для того, чтобы:", opts:["Увеличить поток спринклера","Защитить общественное/питьевое водоснабжение от загрязнения водой системы","Ускорить клапан сухотрубной системы","Заменить функцию сигнализации обратного клапана стояка"], re:"Предотвратители обратного потока не дают потенциально застойной или обработанной воде системы течь обратно в питьевое водоснабжение, защищая здоровье населения (требуется многими водоснабжающими организациями/нормами). Источник: правила перекрёстного соединения NFPA 13 / местной водоснабжающей организации."},
  {id:85, q:"Каковы название и назначение NFPA 13?", opts:["Стандарт на переносные огнетушители","Стандарт на системы пожарной сигнализации","Национальный электротехнический кодекс","Стандарт на монтаж спринклерных систем — устанавливающий минимальные требования к проектированию и монтажу"], re:"NFPA 13 — это «Стандарт на монтаж спринклерных систем», дающий минимальные требования к проектированию/монтажу для защиты жизни и имущества. Источник: область применения/назначение NFPA 13; страница продукта NFPA."},
  {id:86, q:"NFPA 13 имеет САМУЮ ШИРОКУЮ область применения среди стандартов на монтаж, потому что он:", opts:["Применяется только к одноквартирным домам","Охватывает только высотные здания","Охватывает только склады","Может использоваться для оборудования спринклерами практически любого типа здания/помещения"], re:"Любое здание может быть защищено по NFPA 13; NFPA 13R и 13D — более узкие жилые стандарты. Источник: NFPA 'Differences Between NFPA 13, 13R, and 13D.'"},
  {id:87, q:"NFPA 13D — это стандарт на спринклерные системы в:", opts:["Одно- и двухсемейных жилищах и заводских жилых домах","Высотных офисных башнях","Авиационных ангарах","Химических заводах"], re:"NFPA 13D охватывает одно- и двухсемейные жилища и заводские жилые дома (и определённые таунхаусы), сосредоточен на безопасности жизни/эвакуации. Источник: область применения NFPA 13D; сравнение NFPA 13 vs 13R vs 13D."},
  {id:88, q:"NFPA 13R — это стандарт на спринклерные системы в жилых помещениях высотой до:", opts:["Сорока этажей","Четырёх этажей в высоту (и не более 60 футов)","Только одноквартирных домов","Только подземных"], re:"NFPA 13R применяется к жилым помещениям до и включая четыре этажа (не превышая 60 футов), например, малоэтажные многоквартирные дома. Источник: область применения NFPA 13R; статья сравнения NFPA."},
  {id:89, q:"Центральная ЦЕЛЬ безопасности жизни жилой системы NFPA 13D — это:", opts:["Помочь предотвратить объёмную вспышку в помещении возгорания, чтобы жильцы могли эвакуироваться","Защитить конструкцию в течение многих часов","Сбросить воду из всех спринклеров одновременно","Заменить дымовые извещатели"], re:"NFPA 13D нацелен на контроль пожара и предотвращение объёмной вспышки достаточно долго, чтобы жильцы эвакуировались, ставя приоритет безопасности жизни над защитой имущества. Источник: цели NFPA 13D; статья сравнения NFPA."},
  {id:90, q:"NFPA 13 классифицирует помещения по опасности. Три широких класса опасности помещений — это:", opts:["Мокрый, сухой и предварительного действия","Лёгкая опасность, обычная опасность и повышенная опасность","Класс A, B и C","Жилой, коммерческий и промышленный"], re:"Классы опасности помещений NFPA 13 — Лёгкая, Обычная и Повышенная опасность; Обычная и Повышенная каждая делится на Группу 1 и Группу 2. Источник: NFPA 13 Глава 4; NFPA 'Occupancy Classifications in NFPA 13.'"},
  {id:91, q:"Какое помещение является примером ЛЁГКОЙ ОПАСНОСТИ по NFPA 13?", opts:["Офис, церковь или школьный класс","Операция окраски/распыления","Завод по производству шин","Нефтеперерабатывающий завод"], re:"Лёгкая опасность = содержимое низкого количества/горючести: офисы, церкви, школы, больницы, музеи, большинство жилых помещений. Источник: примеры лёгкой опасности NFPA 13; статья о помещениях phcppros."},
  {id:92, q:"Помещения Обычной опасности (Группа 1 или 2) характеризуются:", opts:["Умеренной горючей нагрузкой/горючестью (например, прачечные, механические мастерские, торговые помещения)","Незначительными горючими материалами","Только легковоспламеняющимися жидкостями","Полным отсутствием содержимого"], re:"Обычная опасность охватывает умеренную горючесть/количество: OH-1 (например, парковки, прачечные, ресторанное обслуживание) и OH-2 (например, механические мастерские, торговые помещения, столярные). Источник: классы помещений NFPA 13; блог NFPA."},
  {id:93, q:"Помещения Повышенной опасности по NFPA 13 связаны с:", opts:["Наименьшей тяжестью пожара","Только пустыми чердаками","Высокой горючей/легковоспламеняющейся нагрузкой или процессами (например, окраска распылением, легковоспламеняющиеся жидкости, определённое производство)","Только офисными помещениями"], re:"Повышенная опасность = большие количества горючих материалов и/или легковоспламеняющихся жидкостей: EH-1 (например, печать, определённый текстиль) и EH-2 (например, окраска распылением, обращение с легковоспламеняющимися жидкостями). Источник: примеры повышенной опасности NFPA 13; блог NFPA."},
  {id:94, q:"Почему правильная классификация опасности помещения имеет значение для проектирования спринклеров?", opts:["Она устанавливает цвет краски трубопровода","Она не влияет на проектирование","Она определяет производителя колбы спринклера","Она определяет требуемую расчётную плотность/площадь и потребность в воде для системы"], re:"Опасность помещения определяет расчётную плотность и расчётную площадь (и, следовательно, потребность в воде); более высокая опасность требует больше воды на большей площади. Источник: подходы к проектированию NFPA 13; правила проектирования по классификации опасности."},
  {id:95, q:"В дополнение к опасности помещения, NFPA 13 отдельно классифицирует хранимые товары, используя:", opts:["Цветовые коды спринклеров","Классы сухотрубов","Номера сортамента труб","Классификации товаров (например, Класс I-IV и пластмассы)"], re:"Защита хранения использует классификации товаров (Класс I-IV и различные пластмассы/резина) в дополнение к опасности помещения для установления критериев складских спринклеров. Источник: глава NFPA 13 о классификации товаров; руководство по товарам Koorsen."},
  {id:96, q:"Спринклер ESFR (Раннее Подавление, Быстрый Отклик) предназначен в основном для того, чтобы:", opts:["Только контролировать пожары, никогда не подавлять","Защищать только офисы лёгкой опасности","Быстро подавлять сложные складские пожары, часто избегая внутристеллажных спринклеров","Управлять всеми головками одновременно, как дренчер"], re:"ESFR использует головки с высоким K-фактором и быстрым откликом, чтобы ПОДАВЛЯТЬ (не только контролировать) складские пожары, часто устраняя внутристеллажные спринклеры. Источник: проектирование ESFR NFPA 13; обзор ESFR Precision FP / CA-FIRE."},
  {id:97, q:"Система сухотрубов/пожарных стояков (NFPA 14) в основном обеспечивает:", opts:["Антифриз к спринклерам","Трубопровод и пожарные соединения, чтобы пожарные/жильцы могли применять рукавные струи внутри здания","Давление воздуха к сухим системам","Только предотвращение обратного потока"], re:"Сухотрубы/пожарные стояки — это вертикальный/горизонтальный трубопровод с пожарными соединениями, которые подают воду для ручного пожаротушения внутри зданий (особенно высотных). Источник: системы сухотрубов NFPA 14; блог по проектированию сухотрубов NFPA."},
  {id:98, q:"Сухотруб КЛАССА I (NFPA 14) обеспечивает какое пожарное соединение, предназначенное для пожарной охраны?", opts:["1-дюймовый садовый шланг","2½-дюймовые пожарные соединения","Нет пожарных соединений","½-дюймовое испытательное соединение"], re:"Сухотрубы Класса I обеспечивают 2½-дюймовые соединения для использования пожарной охраной; Класс II обеспечивает 1½-дюймовые для жильцов; Класс III обеспечивает оба. Источник: NFPA 14; классы сухотрубов CA-FIRE / J.F. Ahern."},
  {id:99, q:"По NFPA 13, антифриз, используемый в НОВЫХ спринклерных системах, должен быть:", opts:["Любой бытовой автомобильный антифриз","Солёная вода","Чистый глицерин любой концентрации","Сертифицированным, заводски предварительно смешанным раствором антифриза"], re:"NFPA 13 теперь требует сертифицированный, заводски предварительно смешанный антифриз для новых систем; старый смешиваемый на месте глицерин/пропиленгликоль может действовать как топливо при высоких концентрациях и больше не допускается для новых установок. Источник: антифриз NFPA 13 7.6; руководство по сертифицированному антифризу NFSA."},
  {id:100, q:"В Калифорнии какая классификация CSLB охватывает работы по водяной противопожарной защите (спринклеры и сухотрубы)?", opts:["C-10 Электротехническая","C-16 Подрядчик противопожарной защиты","C-36 Сантехника","C-20 ОВиК (HVAC)"], re:"Классификация C-16 «Противопожарная защита» охватывает разметку, изготовление и монтаж систем противопожарной защиты, включая водяные спринклерные системы и сухотрубы (электротехнические работы по сигнализации относятся к C-10). Источник: описание классификации C-16 CSLB; учебное руководство C-16 CSLB."},
  {id:101, q:"У подвесного спринклера (pendent), где расположен дефлектор относительно водяного канала и в каком направлении направлена струя?", opts:["Ниже отверстия, струя направлена вниз","Выше отверстия, струя направлена вверх","Сбоку от отверстия, струя направлена в сторону","Позади отверстия, струя направлена назад"], re:"Подвесной спринклер свисает вниз с трубы, дефлектор находится ниже водяного канала, поэтому выходящая вода ударяет по нему и формирует зонтообразную картину распыления вниз. Источник: определения спринклеров NFPA 13; справочники по типам спринклеров."},
  {id:102, q:"Спринклер распыления вертикального типа (SSU) устанавливается так, что вода выпускается в каком направлении до того, как она рассеивается дефлектором?", opts:["Вверх против дефлектора, затем рассеивается вниз","Сначала горизонтально вдоль потолка","Прямо вниз без действия дефлектора","В трубу для накопления давления"], re:"Вертикальный спринклер устанавливается над распределительной линией; вода выбрасывается вверх против дефлектора, который затем рассеивает её вниз по площади. Источник: NFPA 13; справочники по спринклерам SSU (Standard Spray Upright, стандартное распыление вертикальное)."},
  {id:103, q:"Боковой спринклер (sidewall) в основном используется в какой ситуации?", opts:["Где трубопровод нельзя проложить по потолку, выпуская воду из стены","В морозильных камерах для предотвращения замерзания головки","Только на стояке как испытательное соединение","Исключительно в складских применениях ESFR"], re:"Боковые спринклеры выбрасывают воду от стены и используются в помещениях (коридоры, гостиничные номера), где непрактично прокладывать распределительные линии по потолку. Источник: положения NFPA 13 о боковых спринклерах."},
  {id:104, q:"В скрытом спринклерном узле (concealed), что скрывает спринклер из вида и что с ним происходит при пожаре?", opts:["Стеклянный купол, который разрушается при 1000°F","Металлическая защита, которую снимает пожарная команда","Декоративная крышка, которая отпадает при более низкой температуре, чем спринклер","Пластиковый колпачок, который должен снять вручную сам человек"], re:"Скрытый спринклер скрыт декоративной крышкой, удерживаемой припоем, рассчитанным на срабатывание при температуре ниже собственного значения спринклера, поэтому крышка отпадает первой и позволяет головке сработать. Источник: NFPA 13; перечни скрытых спринклеров/декоративных крышек."},
  {id:105, q:"Декоративная крышка скрытого спринклера сертифицирована для срабатывания при температуре, которая является какой из следующих относительно рабочей температуры спринклера?", opts:["Ниже, чтобы крышка отпала прежде, чем сработает головка","Выше, чтобы головка сработала прежде, чем отпадёт крышка","Идентичной, чтобы они срабатывали в один и тот же момент","Не связанной и выбираемой монтажником случайно"], re:"Декоративные крышки рассчитаны на более низкое значение (обычно не менее чем примерно на 20°F ниже), чем спринклер, чтобы крышка отпала первой и не блокировала срабатывание; распространены значения 135°F и 165°F. Источник: NFPA 13; перечни температур декоративных крышек."},
  {id:106, q:"Что означает аббревиатура ESFR?", opts:["Early Suppression Fast Response (раннее подавление быстрый отклик)","Extended Spray Fire Response","Enhanced Storage Fire Resistance","Elevated Sidewall Flow Rate"], re:"ESFR = Early Suppression Fast Response (раннее подавление быстрый отклик) — спринклер, разработанный для подавления (а не только контроля) сложных складских пожаров с помощью капель с высоким импульсом и быстродействующего элемента. Источник: глава NFPA 13 о спринклерах ESFR."},
  {id:107, q:"Спринклеры ESFR чаще всего применяются в каком типе занятости?", opts:["Офисы и школы лёгкой опасности","Только открытые парковочные гаражи","Высокостеллажное складирование и складские занятости","Только односемейные жилые дома"], re:"Спринклеры ESFR предназначены для сложных пожаров, таких как склады с высокостеллажным/штабельным хранением, где они могут подавить пожар на уровне потолка без внутристеллажных спринклеров во многих компоновках. Источник: положения NFPA 13 о складировании/ESFR."},
  {id:108, q:"Сухой подвесной спринклер (сухого типа, dry-pendent) специально используется в каком применении?", opts:["Где головка выходит в неотапливаемое/морозильное пространство из отапливаемой мокрой трубы","Только в стеллажных складских помещениях ESFR","Как стандартная головка для офисов лёгкой опасности","На входе соединения пожарной команды"], re:"Сухой подвесной спринклер имеет герметичную опускную трубку, которая удерживает воду вдали от головки, позволяя спринклеру обслуживать морозильную камеру или неотапливаемую зону, будучи подключённым к мокрой системе в отапливаемом пространстве. Источник: NFPA 13; перечни сухих спринклеров."},
  {id:109, q:"Жилые спринклеры (по NFPA 13D/13R) должны быть какого типа отклика?", opts:["Быстрый (ускоренный) отклик","Только стандартный отклик","Только высокотемпературные","Несертифицированные любого типа"], re:"Жилые спринклеры — это сертифицированные устройства быстрого отклика, разработанные для смачивания стен и улучшения условий для эвакуации людей; головки стандартного отклика не соответствуют жилой сертификации. Источник: требования NFPA 13D/13R к жилым спринклерам."},
  {id:110, q:"Какова основная цель дефлектора у спринклера распыления?", opts:["Разбивать водяную струю на определённую картину распределения","Удерживать стеклянную колбу на месте при транспортировке","Чувствовать тепло и активировать спринклер","Соединять спринклер с распределительной линией"], re:"Дефлектор — это пластина, по которой ударяет выходящая струя; его форма и ориентация разбивают воду на сертифицированную картину распыления (зонт, боковая, ESFR и т. д.). Источник: определения спринклеров NFPA 13."},
  {id:111, q:"Утопленный спринклер (recessed) отличается от заподлицо (flush) или скрытого (concealed) спринклера тем, что:", opts:["Устанавливается с частью корпуса в утопленной розетке, но рабочий элемент остаётся открытым","Монтируется полностью над потолком без видимой головки","Всегда является вертикальной головкой в углублении","Является головкой без дефлектора"], re:"Утопленный спринклер частично заходит в утопленную розетку для эстетики, но теплочувствительный элемент остаётся в помещении (в отличие от скрытой головки, спрятанной декоративной крышкой). Источник: NFPA 13; перечни утопленных спринклеров/розеток."},
  {id:112, q:"Почему с утопленным или скрытым спринклером необходимо использовать правильную розетку или декоративную крышку?", opts:["Она должна быть частью сертифицированного узла, потому что влияет на активацию и распыление","Она чисто декоративная и не влияет на работу","Любую розетку можно заменить для экономии средств","Она требуется только для вертикальных спринклеров"], re:"Розетки и декоративные крышки являются частью сертифицированного спринклерного узла; использование несоответствующей детали может изменить тепловой отклик головки и распределение воды. Источник: требования NFPA 13 к принадлежностям/сертификации."},
  {id:113, q:"Вертикальный спринклер обычно предпочтительнее подвесного в какой ситуации?", opts:["Где распределительный трубопровод открыт под потолком и накопление пыли/препятствий является проблемой","Только в офисах с готовым гладким потолком","Где головку нужно скрыть из вида","Только в жилых системах"], re:"Вертикальные спринклеры предпочтительны на открытом трубопроводе (например, в машинных залах, на неотделанных потолках), где они располагаются над трубой и менее склонны к накоплению мусора, чем подвесной отвод. Источник: NFPA 13; рекомендации по ориентации спринклеров."},
  {id:114, q:"Подвесной спринклер, установленный в вертикальном положении (или наоборот), создаёт какую проблему?", opts:["Никакой проблемы, ориентация не имеет значения","Более быстрое и лучшее покрытие","Неправильную, несертифицированную картину распыления, которая может не защитить площадь","Автоматическое преобразование в головку ESFR"], re:"Дефлекторы рассчитаны на конкретную ориентацию; установка подвесного как вертикального (или наоборот) создаёт несертифицированную, искажённую картину и не допускается. Источник: требования NFPA 13 к монтажу спринклеров распыления."},
  {id:115, q:"Буквы 'SSU', нанесённые на спринклер, указывают на какой тип?", opts:["Standard Spray Upright (стандартное распыление вертикальное)","Sidewall Storage Unit","Special Suppression Unit","Standard Sidewall Upright"], re:"SSU = Standard Spray Upright (стандартное распыление вертикальное); сопутствующее обозначение SSP = Standard Spray Pendent (стандартное распыление подвесное). Источник: номенклатура производителей спринклеров/NFPA 13."},
  {id:116, q:"Открытый спринклер (используемый в дренчерной системе) отличается от стандартного автоматического спринклера тем, что он:", opts:["Имеет более крупную стеклянную колбу","Срабатывает только при высокой температуре","Не имеет теплочувствительного элемента и всегда открыт","Всегда бокового типа"], re:"У открытых спринклеров удалён плавкий замок/колба, поэтому все головки подают воду одновременно при открытии дренчерного клапана; они не активируются теплом по отдельности. Источник: положения NFPA 13 о дренчерных/открытых спринклерах."},
  {id:117, q:"Спринклеры расширенного покрытия сертифицированы для выполнения какого из следующего по сравнению со спринклерами стандартного распыления?", opts:["Покрывать меньшую площадь только при более высоком давлении","Работать только как вертикальные головки","Покрывать большую площадь пола на спринклер при установке согласно их сертификации","Устранять необходимость в любом гидравлическом расчёте"], re:"Спринклеры расширенного покрытия специально сертифицированы и испытаны для защиты большей площади на головку, чем спринклеры стандартного распыления, в пределах ограничений расстановки/давления их сертификации. Источник: положения NFPA 13 о спринклерах расширенного покрытия."},
  {id:118, q:"Согласно NFPA 13, обычная температурная классификация охватывает какой диапазон значений?", opts:["100°F – 130°F","175°F – 225°F","135°F – 170°F","250°F – 300°F"], re:"Спринклеры обычной температуры рассчитаны на 135°F–170°F (57°C–77°C) и используются в большинстве обычно занятых помещений. Источник: таблица температурных классификаций NFPA 13."},
  {id:119, q:"Промежуточная температурная классификация по NFPA 13 охватывает какой диапазон значений?", opts:["135°F – 170°F","250°F – 300°F","175°F – 225°F","325°F – 375°F"], re:"Спринклеры промежуточной температуры рассчитаны на 175°F–225°F (79°C–107°C), используются там, где окружающее тепло повышено (рядом со световыми люками, тепловыми пушками и т. д.). Источник: таблица температурных классификаций NFPA 13."},
  {id:120, q:"Стеклянная колба спринклера, заполненная ОРАНЖЕВОЙ жидкостью, соответствует какому температурному значению?", opts:["135°F","155°F","200°F","286°F"], re:"В цветовом коде NFPA для стеклянных колб: оранжевый = 135°F, красный = 155°F, жёлтый = 174°F, зелёный = 200°F, синий = 286°F, фиолетовый = 360°F. Источник: справочники по цветовому коду NFPA 13."},
  {id:121, q:"Стеклянная колба спринклера, заполненная КРАСНОЙ жидкостью, соответствует какому температурному значению?", opts:["135°F","200°F","155°F","360°F"], re:"Красная жидкость стеклянной колбы указывает на спринклер 155°F (68°C), наиболее распространённое значение обычной температуры. Источник: справочники по цветовому коду NFPA 13."},
  {id:122, q:"Спринклер с ЗЕЛЁНОЙ стеклянной колбой рассчитан примерно на какую температуру?", opts:["135°F","174°F","200°F","286°F"], re:"Зелёная жидкость колбы = 200°F (93°C), значение промежуточной температуры. Источник: цветовой код стеклянных колб NFPA 13."},
  {id:123, q:"Что представляет собой температурное значение спринклера?", opts:["Высоту потолка в футах","Давление воды в psi","Номинальную температуру, при которой срабатывает теплочувствительный элемент","Размер трубы в дюймах"], re:"Температурное значение — это номинальная рабочая температура плавкого замка или стеклянной колбы, выбранная с запасом выше ожидаемой максимальной температуры окружающей среды. Источник: выбор температурного значения NFPA 13."},
  {id:124, q:"Для спринклеров обычной температуры (135–170°F) NFPA 13 ограничивает максимальную окружающую температуру потолка примерно до:", opts:["100°F","150°F","225°F","300°F"], re:"Головки обычного класса ограничены максимальной температурой потолка 100°F; выше этого требуется промежуточное или более высокое значение во избежание ложного срабатывания. Источник: таблица максимальной температуры потолка NFPA 13."},
  {id:125, q:"Для спринклеров промежуточной температуры (175–225°F) максимально допустимая окружающая температура потолка составляет примерно:", opts:["100°F","250°F","150°F","350°F"], re:"Спринклеры промежуточного класса допускаются до максимальной температуры потолка 150°F. Источник: таблица максимальной температуры потолка NFPA 13."},
  {id:126, q:"Основное различие между спринклером быстрого отклика (QR) и стандартного отклика (SR) со стеклянной колбой одной и той же температуры заключается в том, что:", opts:["Колба QR тоньше (около 3 мм) для более быстрого теплового отклика","Головка QR подаёт больше воды","Головка SR не имеет дефлектора","Головка QR всегда рассчитана на высокую температуру"], re:"QR и SR могут иметь одинаковое температурное значение; колба QR меньше в диаметре (≈3 мм против ≈5 мм), поэтому она нагревается и срабатывает быстрее (более низкий RTI). Источник: NFPA 13; справочники по отклику/тепловой чувствительности спринклеров."},
  {id:127, q:"RTI (Индекс времени отклика) является мерой чего у спринклера:", opts:["Коэффициента расхода","Коррозионной стойкости","Тепловой чувствительности (как быстро он реагирует на тепло)","Максимального рабочего давления"], re:"RTI количественно определяет тепловую чувствительность рабочего элемента; более низкий RTI означает более быстрый отклик. Источник: NFPA 13; справочники по тепловой чувствительности спринклеров."},
  {id:128, q:"Спринклер обычно классифицируется как быстрого (ускоренного) отклика, когда его RTI составляет примерно:", opts:["50 (м·с)^1/2 или менее","Точно 100 (м·с)^1/2","200 (м·с)^1/2 или более","Не связан с RTI"], re:"Спринклеры быстрого/ускоренного отклика имеют RTI примерно 50 (м·с)^1/2 или менее; стандартный отклик — примерно 80 (м·с)^1/2 или выше. Источник: NFPA 13; справочники по классификации отклика спринклеров."},
  {id:129, q:"Спринклер стандартного отклика обычно имеет RTI примерно:", opts:["Менее 20 (м·с)^1/2","Точно 50 (м·с)^1/2","80 (м·с)^1/2 или более","Отрицательные значения"], re:"Спринклеры стандартного отклика имеют RTI примерно 80 (м·с)^1/2 или больше (более медленный тепловой отклик, чем у быстрого отклика). Источник: NFPA 13; справочники по классификации отклика спринклеров."},
  {id:130, q:"Спринклеры быстрого отклика чаще всего связаны с какой классификацией опасности?", opts:["Только высокостеллажное складирование","Только химзаводы повышенной опасности","Занятости лёгкой опасности (офисы, школы)","Только наружные погрузочные доки"], re:"Спринклеры QR преимущественно устанавливаются в занятостях лёгкой опасности, где их более быстрый отклик повышает безопасность жизни. Источник: NFPA 13; справочники по применению QR."},
  {id:131, q:"На спринклере с плавким замком (паяного типа) температурное значение обычно обозначается:", opts:["Цветом воды в колбе","Формой дефлектора","Цветовым кодом на рычагах рамки или на замке","Размером отверстия"], re:"Спринклеры с плавким замком/паяные несут свой температурный цветовой код на рычагах рамки (или на замке), поскольку у них нет жидкостной колбы. Источник: положения NFPA 13 о цветовом коде."},
  {id:132, q:"Почему спринклеры с более высоким температурным значением устанавливают рядом с тепловыми пушками, световыми люками или на чердаках?", opts:["Чтобы они срабатывали быстрее при пожаре","Потому что они подают меньше воды","Чтобы предотвратить ложное срабатывание от высокого окружающего тепла","Потому что нормы запрещают обычные головки в любом коммерческом здании"], re:"Там, где окружающая температура высока, головка с более высоким значением предотвращает случайное срабатывание от тепла, которое не является пожаром; значение подбирается под ожидаемую максимальную температуру потолка. Источник: положения NFPA 13 о выборе температуры."},
  {id:133, q:"Спринклер с СИНЕЙ стеклянной колбой соответствует какому приблизительному температурному значению?", opts:["155°F","200°F","286°F","360°F"], re:"Синяя жидкость колбы указывает на высокотемпературный спринклер 286°F (141°C). Источник: цветовой код стеклянных колб NFPA 13."},
  {id:134, q:"Высокотемпературная классификация по NFPA 13 охватывает какой диапазон значений?", opts:["135°F – 170°F","175°F – 225°F","250°F – 300°F","400°F – 475°F"], re:"Высокотемпературная классификация составляет 250°F–300°F (121°C–149°C). Источник: таблица температурных классификаций NFPA 13."},
  {id:135, q:"В формуле расхода спринклера Q = K√P что представляет собой Q?", opts:["Расход в gpm","Давление в psi","Диаметр трубы в дюймах","K-фактор"], re:"Q — это расход (поток) в галлонах в минуту; K — коэффициент расхода, а P — давление у спринклера в psi. Источник: гидравлическая формула расхода NFPA 13."},
  {id:136, q:"В Q = K√P член P представляет собой:", opts:["Расход в gpm","Температурное значение","Длину трубы","Давление у спринклера в psi"], re:"P — это давление у отверстия спринклера в psi; квадратный корень из P умножается на K-фактор для получения расхода Q. Источник: формула расхода NFPA 13."},
  {id:137, q:"K-фактор спринклера лучше всего описать как:", opts:["Коэффициент расхода отверстия, связывающий расход с давлением","Температурное значение, делённое на 10","Размер резьбы в миллиметрах","Шаг подвесов в футах"], re:"K-фактор — это номинальный коэффициент расхода, связывающий расход с квадратным корнем из давления (Q = K√P); больший K означает большее эффективное отверстие. Источник: определение K-фактора NFPA 13."},
  {id:138, q:"Наиболее распространённый спринклер распыления со стандартным отверстием имеет номинальный K-фактор:", opts:["2.8","25.2","14.0","5.6"], re:"K = 5.6 (единицы США) — это спринклер распыления со стандартным отверстием 1/2 дюйма, наиболее широко используемый K-фактор. Источник: NFPA 13; данные спринклеров со стандартным отверстием."},
  {id:139, q:"При заданном давлении спринклер с БОЛЬШИМ K-фактором будет:", opts:["Подавать меньше воды","Не подавать воду вообще","Подавать столько же воды","Подавать больше воды"], re:"Поскольку Q = K√P, увеличение K при том же давлении увеличивает расход; большие K-факторы означают большие отверстия и больший расход. Источник: формула расхода NFPA 13."},
  {id:140, q:"Спринклер K=5.6, подающий воду при 7 psi, выпускает примерно сколько воды? (Q = 5.6 × √7)", opts:["Около 8 gpm","Около 100 gpm","Около 56 gpm","Около 15 gpm"], re:"√7 ≈ 2.646, поэтому Q ≈ 5.6 × 2.646 ≈ 14.8 ≈ 15 gpm. Источник: формула расхода NFPA 13 (Q = K√P)."},
  {id:141, q:"NFPA 13 устанавливает минимальное рабочее давление для большинства спринклеров стандартного распыления на уровне:", opts:["1 psi","50 psi","25 psi","7 psi"], re:"Минимальное рабочее давление для спринклеров стандартного распыления по NFPA 13 составляет 7 psi. Источник: положения NFPA 13 о минимальном рабочем давлении."},
  {id:142, q:"Спринклеры ESFR доступны в каком наборе номинальных K-факторов?", opts:["2.8 и 4.2","Только 5.6 и 8.0","14.0, 16.8 и 25.2","0.5 и 1.0"], re:"Спринклеры ESFR используют большие отверстия с номинальными K-факторами 14.0, 16.8 и 25.2 (и больше) для подачи высоких расходов при складских пожарах. Источник: положения NFPA 13 об ESFR."},
  {id:143, q:"Если K-фактор спринклера удваивается, а давление остаётся прежним, расход Q будет:", opts:["Оставаться прежним","Увеличиваться вчетверо","Уменьшаться вдвое","Удваиваться"], re:"Q прямо пропорционален K (Q = K√P); удвоение K при постоянном P удваивает расход. Источник: формула расхода NFPA 13."},
  {id:144, q:"Чтобы УДВОИТЬ расход от одного спринклера только за счёт повышения давления, давление необходимо увеличить в:", opts:["2 раза","16 раз","8 раз","4 раза"], re:"Поскольку Q ∝ √P, удвоение Q требует учетверения P (√4 = 2). Источник: формула расхода NFPA 13."},
  {id:145, q:"Спринклер распыления со стандартным отверстием 1/2 дюйма соответствует номинальному размеру отверстия (резьбы):", opts:["1/4 дюйма","2 дюйма","1 дюйм","1/2 дюйма"], re:"Спринклер распыления со стандартным отверстием (K=5.6) имеет номинальное присоединение отверстия/резьбы 1/2 дюйма. Источник: NFPA 13; данные спринклеров со стандартным отверстием."},
  {id:146, q:"Спринклер распыления с большим отверстием обычно имеет номинальный K-фактор:", opts:["2.8","5.6","8.0","0.5"], re:"K = 8.0 — это распространённый спринклер распыления с большим отверстием, подающий больше воды, чем стандартное отверстие K=5.6, при том же давлении. Источник: NFPA 13; данные спринклеров с большим отверстием."},
  {id:147, q:"Почему спринклеры с большим K (большим отверстием) часто используются для снижения требуемого давления системы?", opts:["Они подают нужный расход при более низком давлении","Они дешевле в производстве","Они устраняют необходимость в дефлекторе","Они снижают температурное значение"], re:"Для целевого расхода больший K обеспечивает его при более низком давлении (P = (Q/K)^2), что может снизить потребность в насосе/водоснабжении. Источник: принципы гидравлического проектирования NFPA 13."},
  {id:148, q:"Спринклер K=8.0 должен подавать 24 gpm. Требуемое давление P = (Q/K)^2 составляет примерно:", opts:["Около 3 psi","Около 64 psi","Около 24 psi","Около 9 psi"], re:"(24/8)^2 = 3^2 = 9 psi. Источник: формула расхода NFPA 13, преобразованная, P = (Q/K)^2."},
  {id:149, q:"В дюймово-фунтовой (США) форме Q = K√P единицы измерения K-фактора:", opts:["gpm/psi","gpm·psi","psi/gpm","gpm/(psi)^1/2"], re:"K имеет единицы gpm на квадратный корень из psi, то есть gpm/(psi)^1/2, так что K√P даёт gpm. Источник: определения гидравлической формулы NFPA 13."},
  {id:150, q:"Два одинаковых спринклера на распределительной линии испытывают разное давление. По сравнению с головкой, ближайшей к источнику, наиболее удалённая головка будет:", opts:["Подавать больше воды","Не подавать воду вообще","Подавать точно столько же","Подавать меньше воды из-за более низкого доступного давления"], re:"Потери на трение снижают давление вдоль линии, поэтому наиболее удалённый спринклер обычно имеет самое низкое давление и самый низкий расход (Q = K√P). Именно поэтому удалённая зона определяет проект. Источник: принципы гидравлического расчёта NFPA 13."},
  {id:151, q:"Стальная труба Schedule 40 отличается от стальной трубы Schedule 10 в основном тем, что Schedule 40 имеет:", opts:["Более толстую стенку","Более тонкую стенку","Больший наружный диаметр при том же номинальном размере","Резьба не допускается"], re:"При заданном номинальном размере наружный диаметр одинаков; Schedule 40 имеет более толстую стенку (меньший внутренний диаметр), чем Schedule 10. Источник: классы труб NFPA 13; стандарты ASTM на стальные трубы."},
  {id:152, q:"Согласно NFPA 13, нарезка резьбы обычно допускается на какой стальной трубе?", opts:["Только Schedule 10","Только медная трубка","Любая толщина стенки без ограничений","Schedule 40 (или толще), если только более тонкая стенка специально не сертифицирована для нарезки резьбы"], re:"Резьба врезается в стенку, поэтому NFPA 13 допускает нарезку резьбы на Schedule 40 или толще; более тонкую трубу можно нарезать резьбой только если она специально сертифицирована. Источник: положения NFPA 13 о методах соединения."},
  {id:153, q:"Тонкостенная стальная труба Schedule 10 обычно соединяется:", opts:["Нарезной резьбой","Только компрессионными муфтами","Растворным цементом","Накатными муфтами (roll-grooved) или сваркой"], re:"Schedule 10 слишком тонкая для безопасной нарезки резьбы, поэтому её соединяют накаткой канавки (муфты с канавкой) или сваркой. Источник: методы соединения NFPA 13; справочники по стальным трубам."},
  {id:154, q:"Труба ХПВХ (CPVC), используемая в спринклерных системах пожаротушения, соединяется:", opts:["Пайкой твёрдым припоем (brazing)","Нарезкой резьбы","Сваркой растворным цементом","Накаткой канавки (roll grooving)"], re:"Сертифицированный ХПВХ (например, BlazeMaster) соединяется растворным цементом производителя; он не нарезается резьбой, не паяется твёрдым припоем и не накатывается канавкой. Источник: NFPA 13; инструкции по монтажу сертифицированного ХПВХ."},
  {id:155, q:"Сертифицированная спринклерная труба ХПВХ обычно ограничена каким типом системы?", opts:["Только системы с сухими трубами","Промышленные высокотемпературные системы","Только дренчерные системы","Системы с мокрыми трубами (с ограничениями сертификации)"], re:"Сертифицированный ХПВХ используется в системах с мокрыми трубами в пределах его сертификации; он не используется в сухих/предварительного действия системах, заполненных воздухом, и должен быть защищён от чрезмерных температур. Источник: NFPA 13; перечни продукции ХПВХ."},
  {id:156, q:"Типичная сертифицированная спринклерная труба ХПВХ рассчитана на эксплуатацию примерно до:", opts:["150°F","300°F","500°F","750°F"], re:"Сертифицированный ХПВХ (например, BlazeMaster) рассчитан на спринклерную эксплуатацию примерно до 150°F (65°C); выше этого его необходимо изолировать/вентилировать или использовать другой материал. Источник: характеристики сертифицированной продукции ХПВХ."},
  {id:157, q:"Медная трубка, используемая для спринклерного трубопровода, чаще всего соединяется:", opts:["Растворным цементом","Нарезной резьбой","Только накаткой канавки","Пайкой твёрдым или мягким припоем (мягкий припой допускается в мокрых системах лёгкой опасности)"], re:"Медная трубка паяется твёрдым припоем; NFPA 13 допускает паяные мягким припоем соединения для систем с мокрыми трубами лёгкой опасности. Растворным цементом она не соединяется. Источник: положения NFPA 13 о соединении меди."},
  {id:158, q:"Для медной водяной трубки какой тип имеет САМУЮ ТОЛСТУЮ стенку?", opts:["Тип M","Тип L","Тип K","Тип DWV"], re:"Среди медных водяных трубок Тип K имеет самую толстую стенку, Тип L — среднюю, а Тип M — самую тонкую. Источник: ASTM B88; типы медной трубки."},
  {id:159, q:"Переходная муфта в спринклерном трубопроводе используется для:", opts:["Изменения направления трубы на 90°","Обеспечения испытательного соединения","Закрытия конца линии","Соединения двух труб разного диаметра в линию"], re:"Переходник/переходная муфта соединяет два разных размера трубы на прямом участке; отводы изменяют направление, а заглушки закрывают концы. Источник: стандартная номенклатура трубных фитингов."},
  {id:160, q:"Фитинг 'тройник' (tee) в спринклерном трубопроводе используется для:", opts:["Закрытия конца распределительной линии","Допуска потока только в одном направлении","Соединения двух труб одного размера только в линию","Создания ответвления (отвод 90°) от участка трубы"], re:"Тройник обеспечивает боковой выход (ответвление) от основного участка; распространён в спринклерных магистралях для питания распределительных линий. Источник: стандартная номенклатура трубных фитингов."},
  {id:161, q:"В гидравлических расчётах NFPA 13 фитинги, такие как отводы и тройники, учитываются с использованием:", opts:["Только их фактически измеренной длины","Их цветового кода","Их веса в фунтах","Эквивалентных длин трубы (эквивалентов потерь на трение)"], re:"Фитинги добавляют потери на трение, представленные как 'эквивалентная длина' трубы, прибавляемая к фактической длине трубы в расчёте Хазена-Вильямса. Источник: таблицы эквивалентной длины NFPA 13."},
  {id:162, q:"Оцинкованная стальная труба иногда указывается для какой спринклерной системы для сопротивления коррозии?", opts:["Офисы лёгкой опасности с мокрыми трубами","Медные системы","Системы ХПВХ","Системы с сухими трубами и предварительного действия (внутри подвержены конденсации)"], re:"Оцинковка часто используется в системах с сухими трубами/предварительного действия, где запертый воздух и конденсат ускоряют внутреннюю коррозию. Источник: NFPA 13; практика борьбы с коррозией для сухих систем."},
  {id:163, q:"Коэффициент 'C' Хазена-Вильямса в спринклерной гидравлике представляет собой:", opts:["Внутреннюю шероховатость/гладкость трубы для потерь на трение","Температурное значение трубы","K-фактор спринклера","Сейсмическую нагрузку"], re:"Коэффициент C описывает внутреннюю гладкость трубы; более высокий C (например, медь/ХПВХ) означает меньшие потери на трение, чем у более шероховатой трубы (например, старой стали). Источник: значения C Хазена-Вильямса NFPA 13."},
  {id:164, q:"По сравнению со сталью, сертифицированная труба ХПВХ обычно имеет коэффициент C Хазена-Вильямса, который:", opts:["Ниже (более шероховатый)","Отрицательный","Идентичен стали","Выше (более гладкий), снижая потери на трение"], re:"ХПВХ и медь имеют более высокие значения C (более гладкий внутренний диаметр), чем сталь, поэтому они создают меньшие потери на трение при том же расходе. Источник: значения C Хазена-Вильямса NFPA 13."},
  {id:165, q:"Муфта с накатной канавкой (roll-grooved) соединяет стальную трубу путём:", opts:["Сплавления концов трубы вместе","Ввинчивания в муфту","Склеивания растворным цементом","Зацепления канавки, накатанной или вырезанной у конца трубы, корпусом с прокладкой"], re:"Муфты с канавкой зажимают двухсоставной корпус в канавку на каждом конце трубы, уплотняя прокладкой; распространены и быстры для стальной спринклерной трубы. Источник: NFPA 13; перечни фитингов с канавкой."},
  {id:166, q:"Соединительная муфта (union) или муфта с канавкой рядом с клапаном или устройством предусматривается в основном для:", opts:["Увеличения давления воды","Использования в качестве спринклерной головки","Изменения материала трубы","Возможности снять/обслужить устройство без разрезания трубы"], re:"Соединительная муфта/фланец/муфта с канавкой обеспечивают точку разъёма, чтобы клапаны, сигнальные устройства и т. д. можно было обслужить или заменить без разрезания трубопровода. Источник: стандартная практика монтажа; ремонтопригодность NFPA 13/25."},
  {id:167, q:"NFPA 13 требует, чтобы трубы, фитинги, клапаны и устройства, используемые в спринклерной системе, были:", opts:["Окрашены в красный цвет независимо от сертификации","Размером минимум 6 дюймов","Изготовлены только из меди","Сертифицированы/одобрены для пожарной защиты или соответствовали ссылочным стандартам"], re:"Компоненты должны быть сертифицированы/одобрены или соответствовать стандартам, на которые ссылается NFPA 13; произвольная замена несертифицированных деталей не допускается. Источник: требования NFPA 13 к материалам и сертификации."},
  {id:168, q:"Клапан OS&Y получил своё название от какой конструктивной особенности?", opts:["Outside Screw and Yoke (наружный винт и ярмо, выдвижной шток)","Open System and Yield","Orifice Sizing and Yaw","Overhead Sprinkler and Yard"], re:"OS&Y = Outside Screw and Yoke (наружный винт и ярмо); резьбовой шток выдвигается снаружи корпуса через ярмо, наглядно показывая открытое/закрытое положение. Источник: NFPA 13; справочники по клапанам OS&Y."},
  {id:169, q:"На задвижке OS&Y можно определить, что клапан ОТКРЫТ, потому что:", opts:["Маховик снят","Автоматически загорается зелёный индикатор","Клапан гудит","Резьбовой шток выступает (выдвигается) через ярмо"], re:"Когда клапан OS&Y открыт, выдвижной шток выходит через ярмо; втянутый шток означает закрыто. Это наглядное указание и есть причина, по которой он считается индикаторным клапаном. Источник: NFPA 13; работа OS&Y."},
  {id:170, q:"NFPA 13 требует, чтобы контрольные клапаны спринклерной системы были какого типа?", opts:["Только неиндикаторные","Только редукционные","Подпружиненные обратные клапаны","Индикаторного типа (открытое/закрытое состояние видно)"], re:"Контрольные клапаны должны быть индикаторными, чтобы персонал мог проверить, что водоснабжение открыто, не приводя клапан в действие (OS&Y, дисковый с указателем положения, PIV, настенный PIV). Источник: требования NFPA 13 к контрольным клапанам."},
  {id:171, q:"Дисковый (бабочка) клапан управляет потоком путём:", opts:["Поднятия и опускания затвора","Поворота диска на 90° внутри трубы","Расплавления плавкого замка","Открытия захлопки давлением воды"], re:"Дисковый клапан поворачивает диск на 90° для пуска/остановки потока; для пожарной службы это индикаторный клапан с указателем положения, и он контролируется. Источник: NFPA 13; справочники по дисковым клапанам."},
  {id:172, q:"Большинство дисковых контрольных клапанов пожарной защиты включают какую функцию для контроля?", opts:["Встроенную спринклерную головку","Встроенный контактный (контрольный) выключатель защиты от вмешательства","Только расходомер","Камеру задержки"], re:"Дисковые клапаны пожарной службы обычно поставляются с выключателем защиты от вмешательства/контрольным выключателем, который подаёт сигнал на панель, если клапан сдвинут из полностью открытого положения. Источник: NFPA 13/NFPA 72; контроль клапанов."},
  {id:173, q:"Основное назначение обратного клапана в спринклерной системе:", opts:["Указывать открытое/закрытое положение","Пропускать поток в одном направлении и предотвращать обратный поток","Снижать температурное значение","Дросселировать поток до заданного давления"], re:"Обратный клапан пропускает воду только в сторону системы и предотвращает обратный поток (например, назад в источник). Источник: NFPA 13; функция обратного клапана."},
  {id:174, q:"Сигнальный обратный клапан выполняет какую функцию в системе с мокрыми трубами?", opts:["Удерживает воздух в сухой системе","Пропускает поток в систему и включает сигнализацию потока воды","Снижает входное давление до 7 psi","Дренирует систему после использования"], re:"Сигнальный обратный клапан — это односторонняя захлопка на стояке; когда вода течёт, сигнальный порт направляет воду на реле давления и/или гидравлический гонг для сигнализации потока. Источник: NFPA 13; работа сигнального обратного клапана."},
  {id:175, q:"Камера задержки, связанная с сигнальным обратным клапаном, предусматривается для:", opts:["Хранения дополнительной воды для спринклеров","Предотвращения ложных тревог от кратковременных скачков давления","Увеличения K-фактора расхода","Удержания воздуха в сухой системе"], re:"Камера задержки заполняется и опорожняется медленно, так что кратковременные скачки давления источника не вызывают срабатывания сигнализации потока воды; устойчивый поток заполняет её и срабатывает реле. Источник: NFPA 13; функция камеры задержки."},
  {id:176, q:"Гидравлический гонг (водомоторная сигнализация) приводится в действие:", opts:["Только электродвигателем","Водой, отведённой сигнальным клапаном, ударяющей по лопастному колесу","Сжатым воздухом из сухого клапана","Насосом соединения пожарной команды"], re:"Когда сигнальный клапан срабатывает, вода направляется к гонгу, где она вращает лопастное колесо, приводящее в движение молоток для звона в колокол — чисто гидравлическая местная сигнализация. Источник: NFPA 13; работа гидравлического гонга."},
  {id:177, q:"Сухотрубный клапан в сухой системе удерживает воду с помощью:", opts:["Заблокированного штока OS&Y","Давления воздуха или азота со стороны системы","Растворного цемента","Только камеры задержки"], re:"Сухотрубный клапан использует сжатый воздух/азот со стороны системы для удержания большей силы со стороны воды; когда спринклер открывается, воздух стравливается и клапан срабатывает, впуская воду. Источник: положения NFPA 13 о сухих трубах."},
  {id:178, q:"Дренчерный клапан используется с какой компоновкой спринклеров?", opts:["Закрытые стандартные спринклеры в мокрой системе","Открытые спринклеры, подающие воду из всех головок одновременно при срабатывании","Одна жилая боковая головка","Только ESFR внутри стеллажей"], re:"Дренчерный клапан впускает воду в систему ОТКРЫТЫХ спринклеров, когда срабатывает приводящая (детекторная) система, одновременно смачивая всю площадь. Источник: положения NFPA 13 о дренчерных системах."},
  {id:179, q:"NFPA требует, чтобы контрольные клапаны, не контролируемые электрически, были:", opts:["Окрашены в зелёный цвет","Заблокированы в открытом положении и осматривались по установленному графику","Сняты во время занятости","Заменялись ежегодно"], re:"Там, где они не контролируются выключателем защиты от вмешательства, контрольные клапаны должны быть заблокированы/опломбированы в открытом состоянии и физически осматриваться (обычно еженедельно) для подтверждения, что они остаются открытыми. Источник: контроль клапанов NFPA 13/NFPA 25."},
  {id:180, q:"Столбовой индикаторный клапан (PIV) — это контрольный клапан, который:", opts:["Закопан без возможности определить его положение","Имеет надземный столб с окном указателя ОТКРЫТО/ЗАКРЫТО для подземного клапана","Является тем же, что и обратный клапан","Работает только на трубе ХПВХ"], re:"PIV выводит рабочую гайку и указатель ОТКРЫТО/ЗАКРЫТО над уровнем земли для закопанного магистрального клапана, удовлетворяя требованию индикаторного клапана. Источник: NFPA 13/24; справочники по PIV."},
  {id:181, q:"Предохранитель обратного потока устанавливается на пожарном вводе в основном для:", opts:["Увеличения давления расхода спринклера","Предотвращения обратного попадания потенциально загрязнённой воды системы в общественное водоснабжение","Чувствования тепла и срабатывания системы","Замены сигнального обратного клапана"], re:"Предохранители обратного потока защищают питьевое водоснабжение от перекрёстного загрязнения застойной или обработанной спринклерной водой; требуются органами водоснабжения/сантехники, а не самой NFPA. Источник: справочники по предотвращению обратного потока/перекрёстного соединения; контекст NFPA 13/25."},
  {id:182, q:"Узел обратного потока с зоной пониженного давления (RPZ) отличается от узла двойного обратного клапана (DCVA) добавлением:", opts:["Третьего обратного клапана","Дифференциального предохранительного клапана, который сбрасывает воду при отказе обратного клапана","Камеры задержки","Второго клапана OS&Y"], re:"RPZ добавляет гидравлически управляемый предохранительный клапан между двумя обратными клапанами; если обратный клапан протекает, предохранитель сбрасывает в дренаж, обеспечивая более высокую защиту для соединений повышенной опасности. Источник: справочники по узлам обратного потока (AWWA M14)."},
  {id:183, q:"Редукционный клапан (PRV) используется в высокой системе сухотрубного стояка/спринклеров для:", opts:["Увеличения давления на верхних этажах","Ограничения избыточного давления на нижних этажах/пожарных кранах","Чувствования потока воды","Удержания воздуха в сухой системе"], re:"В высотных системах статическое давление на нижних уровнях может быть избыточным; PRV снижают его до безопасных значений на пожарных кранах и трубопроводе нижней зоны. Источник: положения NFPA 14/NFPA 13 о регулировании давления."},
  {id:184, q:"Главный дренажный клапан на стояке используется для:", opts:["Подачи воды к спринклерам","Дренирования системы и выполнения испытания главного дренажа (водоснабжения)","Снижения входного давления","Удержания воздуха"], re:"Главный дренаж позволяет дренировать систему и используется для испытания главного дренажа, которое проверяет препятствия со стороны источника путём сравнения статического и остаточного давления. Источник: испытание главного дренажа NFPA 13/25."},
  {id:185, q:"Подвесы, используемые для поддержки трубопровода спринклерной системы, должны быть, согласно NFPA 13:", opts:["Сертифицированы для данного применения","Любая проволока, доступная на объекте","Изготовлены только из меди","Расставлены максимум через 50 футов"], re:"NFPA 13 требует, чтобы компоненты подвесов, поддерживающие трубопровод системы, были сертифицированы (с ограниченными исключениями для определённых изготовленных на месте деталей, отвечающих критериям MSS). Источник: положения NFPA 13 о подвеске/опоре."},
  {id:186, q:"Для стальной спринклерной трубы 1 дюйм максимальное расстояние между подвесами по NFPA 13 составляет:", opts:["6 футов","12 футов","20 футов","30 футов"], re:"NFPA 13 ограничивает шаг подвесов на стальной трубе 1 дюйм (и 1-1/4 дюйма) максимумом 12 футов; большие стальные размеры (2 дюйма и выше) допускают до 15 футов. Источник: таблица максимального расстояния между подвесами NFPA 13."},
  {id:187, q:"Для стальной спринклерной трубы 2 дюйма и больше максимальный шаг подвесов по NFPA 13 обычно составляет:", opts:["8 футов","10 футов","15 футов","25 футов"], re:"Стальная труба 2 дюйма и больше может поддерживаться с максимальным шагом подвесов до 15 футов согласно NFPA 13. Источник: таблица максимального расстояния между подвесами NFPA 13."},
  {id:188, q:"Спринклерная труба ХПВХ требует более частого шага подвесов, чем сталь, потому что ХПВХ:", opts:["Тяжелее стали","Более гибкий и больше провисает, особенно при нагреве","Не может удерживать воду","Лучше проводит тепло"], re:"ХПВХ более гибкий и теряет жёсткость при нагреве, поэтому он требует более частой опоры, чем сталь, для предотвращения провисания; следуйте сертифицированному шагу производителя. Источник: NFPA 13; рекомендации по подвесам сертифицированного ХПВХ."},
  {id:189, q:"Назначение сейсмического раскрепления от раскачивания на спринклерном трубопроводе:", opts:["Увеличить давление воды","Сопротивляться дифференциальному перемещению и сохранить трубопровод целым во время землетрясения","Снизить потери на трение","Изолировать трубу от тепла"], re:"Раскрепление от раскачивания удерживает трубопровод от поперечного/продольного перемещения, вызванного землетрясением, чтобы он не разрушился и не разъединился; требуется в зонах сейсмического проектирования. Источник: положения NFPA 13 о защите от землетрясений."},
  {id:190, q:"Поперечные раскрепления от раскачивания на питающих и поперечных магистралях расставляются с максимальным шагом:", opts:["20 футов по центрам","40 футов по центрам","80 футов по центрам","120 футов по центрам"], re:"NFPA 13 ограничивает поперечные раскрепления от раскачивания максимумом 40 футов по центрам на питающих/поперечных магистралях (и подходящих распределительных линиях). Источник: шаг поперечного раскрепления NFPA 13."},
  {id:191, q:"Продольные раскрепления от раскачивания на питающих и поперечных магистралях расставляются с максимальным шагом:", opts:["40 футов по центрам","60 футов по центрам","80 футов по центрам","160 футов по центрам"], re:"NFPA 13 ограничивает продольные раскрепления от раскачивания максимумом 80 футов по центрам на питающих и поперечных магистралях. Источник: шаг продольного раскрепления NFPA 13."},
  {id:192, q:"Гибкие муфты, используемые в сейсмическом проектировании, позволяют трубопроводу:", opts:["Транспортировать больше воды","Изгибаться в стыках, чтобы перемещение не разрушало жёсткие соединения","Устранить необходимость в любом раскреплении","Снизить температурное значение"], re:"Сертифицированные гибкие муфты обеспечивают контролируемую подвижность, чтобы сейсмическое перемещение воспринималось в стыке, а не перенапрягало трубу; их размещение координируется с раскреплением. Источник: положения NFPA 13 о сейсмической гибкости."},
  {id:193, q:"Соединение пожарной команды (FDC) позволяет пожарной команде:", opts:["Отключить спринклерную систему","Нагнетать дополнительную воду/давление в спринклерную систему или стояк","Дренировать систему","Только проверить сигнальный колокол"], re:"FDC — это ввод, куда техника пожарной команды может нагнетать воду и давление в систему для дополнения источника во время пожара. Источник: NFPA 13/14; назначение FDC."},
  {id:194, q:"Стандартный ввод FDC чаще всего использует какой размер соединения с пожарной резьбой?", opts:["1 дюйм","1-1/2 дюйма","2-1/2 дюйма","6 дюймов"], re:"FDC по умолчанию обеспечивает поворотные вводы с резьбой National Hose (NH) 2-1/2 дюйма (часто два, 'сиамское' соединение), если только местная юрисдикция не указывает соединение большого диаметра (Storz). Источник: требования NFPA 13/14 к вводам FDC."},
  {id:195, q:"NFPA требует размещать FDC на какой высоте над прилегающим уровнем земли?", opts:["Не менее 18 дюймов и не более 48 дюймов","Точно 6 дюймов","Не менее 8 футов","Под землёй в приямке"], re:"FDC должны размещаться между 18 дюймами и 48 дюймами над уровнем прилегающей земли/готового пола, чтобы можно было подсоединить рукава. Источник: NFPA 14 (6.4.6) / NFPA 13 размещение FDC."},
  {id:196, q:"Обратный клапан устанавливается на линии FDC для:", opts:["Снижения входного давления","Предотвращения вытекания воды системы через FDC при нормальной работе","Чувствования тепла","Указания положения клапана"], re:"FDC имеет обратный клапан, чтобы вода обычно текла только внутрь; он не даёт воде системы (и любому нагнетённому давлению) вытекать через вводы FDC. Источник: NFPA 13/14; требование обратного клапана FDC."},
  {id:197, q:"Каждый ввод FDC должен быть снабжён каким из следующего для защиты от мусора?", opts:["Манометром","Заглушкой, колпачком или ломкой крышкой","Спринклерной головкой","Камерой задержки"], re:"Вводы FDC снабжаются колпачками/заглушками (или ломкими крышками) для защиты от мусора и вандализма, оставаясь при этом быстро снимаемыми пожарной командой. Источник: положения NFPA 13/14 о FDC."},
  {id:198, q:"Автоматический шаровой слив (сливной клапан) на FDC предусматривается для:", opts:["Повышения давления системы","Слива остаточной воды из трубопровода FDC для предотвращения замерзания","Чувствования потока воды","Удержания воздуха в сухой системе"], re:"Автоматический слив/шаровой слив позволяет воде, запертой в трубопроводе FDC, стечь, чтобы она не замёрзла и не разорвала соединение в холодную погоду. Источник: положения NFPA 13/14 о дренаже FDC."},
  {id:199, q:"Подвес на распределительной линии должен располагаться в пределах ограниченного расстояния от каждого спринклера в основном для:", opts:["Увеличения давления воды у головки","Поддержки головки и предотвращения провисания или биения трубы","Изменения температурного значения","Использования в качестве сейсмического раскрепления"], re:"NFPA 13 требует подвес в пределах установленного расстояния от каждого спринклера, чтобы головка была должным образом поддержана, а труба не провисала, не опускалась и не двигалась чрезмерно. Источник: положения NFPA 13 о размещении подвесов на распределительных линиях."},
  {id:200, q:"FDC, обслуживающее комбинированную систему, обычно обозначается:", opts:["Зелёным индикатором","Знаком, указывающим систему/зону, которую оно обслуживает (например, 'AUTOSPKR' или 'STANDPIPE')","Никакой маркировкой","Температурным цветовым кодом"], re:"FDC должны обозначаться знаком или рельефными буквами, показывающими, какую службу они снабжают (спринклер, стояк или комбинированную), и любую информацию о давлении, чтобы спасатели подключались к правильному вводу. Источник: требования NFPA 13/14 к маркировке FDC."},
  {id:201, q:"Вертикальный столб воды создаёт статическое давление приблизительно:", opts:["5.0 psi на фут высоты","1.0 psi на фут высоты","2.31 psi на фут высоты","0.433 psi на фут высоты"], re:"Вода создаёт около 0.433 psi на каждый вертикальный фут высоты; эквивалентно, чтобы получить 1 psi, требуется 2.31 фута воды. Стандартная гидравлика противопожарной защиты (расчёты по высоте NFPA 13)."},
  {id:202, q:"Сколько футов водяного столба требуется, чтобы создать давление в 1 psi?", opts:["0.433 ft","1.0 ft","4.33 ft","2.31 ft"], re:"Поскольку вода создаёт 0.433 psi/ft, обратная величина (1 ÷ 0.433) составляет около 2.31 ft воды на psi. Стандартная гидравлическая константа, используемая в расчётах NFPA 13."},
  {id:203, q:"«Остаточное давление» при испытании водопитателя или расхода — это давление, остающееся:", opts:["Пока протекает требуемое количество воды","После остановки насоса","До открытия любой задвижки","Только у самого высокого спринклера"], re:"Остаточное давление — это давление, остающееся в системе во время протекания воды; падение от статического до остаточного отражает трение и потребность. Терминология испытаний гидрантов NFPA 291."},
  {id:204, q:"Три формы энергии, уравновешиваемые в гидравлическом расчёте противопожарной защиты (Бернулли), — это давление (напор), высота (отметка) и:", opts:["Магнетизм","Температура","Поверхностное натяжение","Скорость (скоростное давление)"], re:"Принцип Бернулли уравновешивает напор давления, напор по высоте и скоростной напор; гидравлика противопожарной защиты использует видоизменённую форму для расчётов потока в трубах. Гидравлическая теория Canute / NFPA 13."},
  {id:205, q:"Когда вода подаётся ВВЕРХ на более высокий этаж, изменение высоты приводит к тому, что давление:", opts:["Возрастает примерно на 0.433 psi на фут подъёма","Уменьшается примерно на 0.433 psi на фут подъёма","Остаётся точно таким же","Удваивается на каждом этаже"], re:"Каждый фут подъёма стоит около 0.433 psi давления, которое водопитатель должен преодолеть, поэтому давление уменьшается с набором высоты. Потери давления по высоте NFPA 13."},
  {id:206, q:"Расход из спринклера или насадки определяется по формуле:", opts:["Q = P + K","Q = P²","Q = K ÷ P","Q = K√P"], re:"Расход равен коэффициенту K, умноженному на квадратный корень из давления: Q = K√P, где Q в gpm, K — коэффициент расхода, а P в psi. Гидравлические основы NFPA 13."},
  {id:207, q:"В формуле Q = K√P символ «K» обозначает:", opts:["Длину трубы","Коэффициент расхода (K-фактор) отверстия","Количество спринклеров","Мощность насоса в лошадиных силах"], re:"K — это номинальный коэффициент расхода (K-фактор) отверстия спринклера или насадки, в единицах gpm/√psi. Определение K-фактора NFPA 13."},
  {id:208, q:"Стандартный распылительный спринклер с отверстием 1/2 дюйма имеет номинальный K-фактор приблизительно:", opts:["1.4","5.6","2.8","11.2"], re:"Стандартный распылительный спринклер 1/2 дюйма (DN15), используемый в большинстве коммерческих работ лёгкой пожароопасности, имеет номинальный K-фактор около 5.6 (gpm/√psi). Номинальные K-факторы NFPA 13."},
  {id:209, q:"Спринклер с K=5.6, работающий при 25 psi, выдаёт приблизительно сколько gpm? (Q = K√P)", opts:["14 gpm","56 gpm","28 gpm","112 gpm"], re:"Q = 5.6 × √25 = 5.6 × 5 = 28 gpm. Прямое применение Q = K√P (NFPA 13)."},
  {id:210, q:"Спринклер с K=5.6 должен обеспечить расход 22.4 gpm. Какое давление требуется? (P = (Q/K)²)", opts:["4 psi","16 psi","8 psi","32 psi"], re:"P = (Q/K)² = (22.4/5.6)² = (4)² = 16 psi. Преобразованная форма Q = K√P (NFPA 13)."},
  {id:211, q:"NFPA 13 устанавливает минимальное рабочее давление для стандартного распылительного спринклера не менее:", opts:["3 psi","15 psi","7 psi","25 psi"], re:"NFPA 13 требует минимум 7 psi на стандартном распылительном спринклере (если сертификация не требует большего); ниже этого значения распылительная картина ненадёжна. Минимальное рабочее давление NFPA 13."},
  {id:212, q:"Если давление на спринклере с K=5.6 увеличить в четыре раза (×4), расход (поток) будет:", opts:["Прежним","Вдвое больше (×2)","Втрое больше (×3)","Вчетверо больше (×4)"], re:"Поскольку расход изменяется как квадратный корень из давления (Q = K√P), четырёхкратное увеличение давления увеличивает расход лишь вдвое (√4 = 2). Зависимость K-фактора NFPA 13."},
  {id:213, q:"«Расчётная площадь» в гидравлически рассчитанной спринклерной системе — это:", opts:["Общая площадь этажей здания","Площадь, охватываемая одним спринклером","Гидравлически наиболее требовательная площадь, предполагаемая работающей при пожаре","Площадь помещения стояка"], re:"Расчётная (удалённая) площадь — это наиболее гидравлически требовательная группа спринклеров, предполагаемая работающей; система рассчитывается для обеспечения требуемой интенсивности на этой площади. Метод интенсивность/площадь NFPA 13."},
  {id:214, q:"В гидравлических расчётах «интенсивность орошения» выражается в единицах:", opts:["gpm на квадратный фут","psi на фут","только галлоны в минуту","футы в секунду"], re:"Расчётная интенсивность орошения — это скорость подачи воды на единицу площади, выраженная в gpm/ft² (галлоны в минуту на квадратный фут). Проектирование по интенсивности/площади NFPA 13."},
  {id:215, q:"Чтобы найти минимальный расход одного спринклера, защищающего 130 ft² при интенсивности 0.10 gpm/ft², нужно:", opts:["Сложить интенсивность + площадь","Умножить интенсивность × площадь = 13 gpm","Разделить площадь на интенсивность","Вычесть интенсивность из площади"], re:"Минимальный расход = интенсивность × площадь покрытия = 0.10 gpm/ft² × 130 ft² = 13 gpm для этого спринклера. Основа интенсивность × площадь NFPA 13."},
  {id:216, q:"В гидравлическом расчёте потери на трение в трубопроводе рассматриваются как:", opts:["Прирост давления","Потеря давления, которую водопитатель должен преодолеть","Несущественные для проекта","Равные приросту по высоте"], re:"Потери на трение (потока) — это штраф по давлению, который водопитатель должен преодолеть наряду с высотой и минимальным давлением спринклера. Гидравлический расчёт NFPA 13."},
  {id:217, q:"На гидравлическом графике (полулогарифмическая бумага N1.85) водопитатель наносится линией, а потребность системы — точкой; проект адекватен, когда точка потребности попадает:", opts:["Выше и правее линии водопитателя","На или ниже (левее) линии водопитателя","Точно на горизонтальной оси","Полностью за пределами графика"], re:"Если точка потребности лежит на или ниже/левее кривой доступного водопитателя, водопитатель может удовлетворить потребность. Графический гидравлический анализ NFPA 13."},
  {id:218, q:"Для ОФИСНОГО здания, классифицированного как лёгкая пожароопасность, классическая расчётная интенсивность NFPA 13 составляет около:", opts:["0.05 gpm/ft²","0.20 gpm/ft²","0.10 gpm/ft²","0.40 gpm/ft²"], re:"Помещения лёгкой пожароопасности (офисы, школы, церкви) используют классическую расчётную интенсивность около 0.10 gpm/ft². Интенсивность/площадь NFPA 13 (лёгкая пожароопасность)."},
  {id:219, q:"Классическая расчётная интенсивность NFPA 13 для обычной пожароопасности группы 1 составляет приблизительно:", opts:["0.10 gpm/ft²","0.30 gpm/ft²","0.15 gpm/ft²","0.60 gpm/ft²"], re:"Обычная пожароопасность группы 1 использует классическую интенсивность около 0.15 gpm/ft². Интенсивность/площадь NFPA 13 (OH-1)."},
  {id:220, q:"Классическая расчётная интенсивность NFPA 13 для обычной пожароопасности группы 2 составляет приблизительно:", opts:["0.10 gpm/ft²","0.20 gpm/ft²","0.15 gpm/ft²","0.50 gpm/ft²"], re:"Обычная пожароопасность группы 2 использует классическую интенсивность около 0.20 gpm/ft². Интенсивность/площадь NFPA 13 (OH-2)."},
  {id:221, q:"В методе интенсивность/площадь какие две величины определяют расчётную «точку» для классификации пожароопасности?", opts:["Интенсивность (gpm/ft²) и площадь действия (ft²)","Напряжение и сила тока","Температура и влажность","Размер трубы и длина трубы"], re:"Метод сочетает интенсивность подачи воды (gpm/ft²) с расчётной площадью действия (ft²), выбранной по классификации пожароопасности. Проектирование по интенсивности/площади NFPA 13."},
  {id:222, q:"Часто используемая расчётная ПЛОЩАДЬ действия для проектирования по интенсивности/площади обычной и лёгкой пожароопасности составляет:", opts:["1,500 ft²","500 ft²","100 ft²","25,000 ft²"], re:"Расчётная площадь действия 1,500 ft² — это классическая базовая величина для проектирования по интенсивности/площади лёгкой и обычной пожароопасности. Интенсивность/площадь NFPA 13 (расчётная площадь)."},
  {id:223, q:"На классических кривых интенсивность/площадь по мере увеличения предполагаемой РАСЧЁТНОЙ ПЛОЩАДИ требуемая ИНТЕНСИВНОСТЬ обычно:", opts:["Увеличивается","Падает до нуля","Остаётся постоянной","Уменьшается"], re:"Классические кривые позволяют проектировщику обменять большую расчётную площадь на меньшую требуемую интенсивность (или меньшую площадь на большую интенсивность). Компромисс кривой интенсивность/площадь NFPA 13."},
  {id:224, q:"Более высокая классификация пожароопасности (более горючее содержимое) обычно требует:", opts:["Более высокой интенсивности подачи воды","Меньшей интенсивности и меньшей площади","Полного отсутствия спринклеров","Только обнаружения дыма"], re:"Большая пожарная нагрузка и более быстрое тепловыделение требуют более высокой интенсивности подачи воды для контроля пожара. Основа классификации пожароопасности NFPA 13."},
  {id:225, q:"Что из перечисленного обычно классифицируется как помещение обычной пожароопасности (группа 2)?", opts:["Частный офис","Механический цех или торговое помещение с умеренным количеством горючих материалов","Молитвенный зал церкви","Открытая парковочная платформа без хранения"], re:"Помещения с умеренным-высоким содержанием горючих материалов (механические цеха, многие торговые/производственные применения) относятся к обычной пожароопасности группы 2. Классификация помещений NFPA 13."},
  {id:226, q:"В методе интенсивность/площадь общая минимальная потребность в воде для спринклеров определяется путём:", opts:["Сложения K-факторов","Интенсивность ÷ площадь","Площадь ÷ интенсивность","Интенсивность × расчётная площадь (плюс надбавка на пожарные стволы)"], re:"Потребность спринклеров ≈ интенсивность × расчётная площадь; затем для определения размера водопитателя добавляются надбавка на пожарные стволы и потери на трение/по высоте. Потребность по интенсивности/площади NFPA 13."},
  {id:227, q:"Надбавка на пожарные стволы (внутренние/наружные) ДОБАВЛЯЕТСЯ к потребности спринклеров в точке:", opts:["Основания стояка / точки подключения к водопитателю","Каждого отдельного спринклера","Только самого удалённого спринклера","Чердака"], re:"Надбавки на внутренние и наружные пожарные стволы добавляются к потребности системы у основания стояка или в точке подключения водопитателя, а не на каждом спринклере. Надбавка на пожарные стволы NFPA 13."},
  {id:228, q:"Требуемая продолжительность водоснабжения (в минутах) обычно УВЕЛИЧИВАЕТСЯ по мере того, как классификация пожароопасности:", opts:["Становится более лёгкой","Несущественна","Не влияет на продолжительность","Становится более высокой (более опасной)"], re:"Более высокая пожароопасность требует как более высокой интенсивности, ТАК И большей продолжительности водоснабжения (например, лёгкая ~30 мин против более длительной для обычной/повышенной). Продолжительность водоснабжения NFPA 13."},
  {id:229, q:"Когда сначала рассчитывается гидравлически наиболее удалённый спринклер, расчёт затем продолжается:", opts:["Обратно к водопитателю, накапливая потери","Только наружу к тупиковому концу","В случайном порядке","Только у насоса"], re:"Расчёты начинаются с наиболее удалённого спринклера и движутся обратно к водопитателю, складывая расходы и накапливая потери на трение и по высоте. Процедура гидравлического расчёта NFPA 13."},
  {id:230, q:"Редакции NFPA 13, начиная примерно с 2022 года, изменили подход интенсивность/площадь путём:", opts:["Ограничения многоточечных кривых интенсивность/площадь существующими системами и сделав одноточечную интенсивность стандартом по умолчанию для новых работ","Полного исключения спринклеров","Удвоения каждого значения интенсивности","Запрета гидравлических расчётов"], re:"NFPA 13 (2022) ограничила классические кривые интенсивность/площадь оценкой существующих систем и сделала одноточечную интенсивность (из таблицы пожароопасности) стандартом по умолчанию для нового проектирования. NFPA 13 (2022) гл. 19."},
  {id:231, q:"В «одноточечном» подходе к интенсивности проектировщик использует:", opts:["Любую точку на кривой по своему выбору","Фиксированные интенсивность и площадь, определённые таблицей классификации пожароопасности","Только заводскую табличку насоса","Только схему трубопроводов"], re:"Одноточечное проектирование фиксирует интенсивность и расчётную площадь по классификации пожароопасности (без свободного выбора вдоль кривой). Одноточечная интенсивность NFPA 13 (2022)."},
  {id:232, q:"По сравнению с лёгкой пожароопасностью, помещение обычной пожароопасности обычно требует спринклеров, обеспечивающих:", opts:["Меньше воды","Никакой воды","Больше воды (более высокая интенсивность)","То же самое независимо от пожароопасности"], re:"Обычная пожароопасность требует более высокой интенсивности подачи, чем лёгкая, поэтому каждый работающий спринклер должен подавать больше воды. Сравнение интенсивности NFPA 13."},
  {id:233, q:"Минимальный расход, который должен обеспечить каждый спринклер в рассчитанной системе, зависит от его:", opts:["Только цвета","Только размера резьбы","Логотипа производителя","Площади покрытия × требуемой интенсивности"], re:"Минимальный расход каждого спринклера = его защищаемая площадь покрытия × требуемая расчётная интенсивность. Расчёт интенсивность/площадь NFPA 13."},
  {id:234, q:"Выбор БОЛЬШЕЙ расчётной площади (больше работающих спринклеров), чем требуется, обычно делает рассчитанную потребность в воде:", opts:["Больше / более консервативной","Неизменной","Меньше","Нулевой"], re:"Больше работающих спринклеров означает больший общий расход и трение, что увеличивает потребность — более консервативный (и более дорогой) проект. Выбор интенсивности/площади NFPA 13."},
  {id:235, q:"Эмпирическая формула, принятая NFPA 13 для расчёта потерь на трение (потока) в спринклерном трубопроводе, — это:", opts:["Закон Бойля","Закон Ома","Формула Хазена-Вильямса","Закон Шарля"], re:"NFPA 13 использует формулу Хазена-Вильямса для расчёта потерь на трение в заполненных водой трубопроводах противопожарной защиты. Метод гидравлического расчёта NFPA 13."},
  {id:236, q:"В формуле Хазена-Вильямса значение «C» представляет:", opts:["Стоимость трубы","Внутреннюю шероховатость / гладкость трубы","Цветовую маркировку","Длину в футах"], re:"C-фактор (коэффициент) описывает внутреннюю шероховатость трубы — большее C означает более гладкую трубу и меньшие потери на трение. Хазен-Вильямс (NFPA 13)."},
  {id:237, q:"БОЛЕЕ ВЫСОКОЕ значение C Хазена-Вильямса указывает на трубу, которая создаёт:", opts:["Больше потерь на трение","Никакого потока","Меньше потерь на трение (более гладкий канал)","Большую высоту"], re:"Большее C = более гладкая внутренняя поверхность = меньшие потери на трение при заданном расходе. Значение C-фактора Хазена-Вильямса (NFPA 13)."},
  {id:238, q:"Значение C Хазена-Вильямса, обычно используемое для НЕФУТЕРОВАННОЙ чугунной / высокопрочной чугунной трубы, составляет:", opts:["150","120","130","100"], re:"Нефутерованному чугуну/высокопрочному чугуну присваивается C = 100 в таблице потерь на трение NFPA 13 (учитывает старение/образование бугорков). Таблица значений C NFPA 13."},
  {id:239, q:"Значение C Хазена-Вильямса, используемое для чёрной или оцинкованной стальной трубы в ВОДОЗАПОЛНЕННЫХ спринклерных системах, составляет:", opts:["80","100","150","120"], re:"Стальной трубе в водозаполненных (и дренчерных) системах присваивается C = 120; стали в сухотрубных/предварительного действия системах — C = 100. Таблица значений C NFPA 13."},
  {id:240, q:"Значение C Хазена-Вильямса, используемое для медной трубы и большинства сертифицированных пластиковых (CPVC) труб, составляет:", opts:["100","120","150","140"], re:"Медной трубе и сертифицированному пластику (CPVC) присваивается C = 150 — самые гладкие из распространённых материалов, дающие наименьшие потери на трение. Таблица значений C NFPA 13."},
  {id:241, q:"Стальной трубе в СУХОТРУБНОЙ системе или системе ПРЕДВАРИТЕЛЬНОГО ДЕЙСТВИЯ присваивается значение C Хазена-Вильямса:", opts:["120","100","130","150"], re:"Поскольку внутренняя коррозия больше в сухотрубных системах/системах предварительного действия, стальная труба в них использует C = 100 (против 120 для водозаполненной стали). Таблица значений C NFPA 13."},
  {id:242, q:"При заданных расходе и размере трубы потери на трение НАИБОЛЬШИЕ в трубе с каким значением C?", opts:["C = 150","C = 120","C = 140","C = 100"], re:"Наименьшее C (самая шероховатая труба) создаёт наибольшие потери на трение; C = 100 (например, нефутерованный чугун, сталь сухотрубной системы) — наихудший из перечисленных. Хазен-Вильямс (NFPA 13)."},
  {id:243, q:"В формуле Хазена-Вильямса потери на трение наиболее чувствительны к (наиболее круто возрастают с):", opts:["Резьбе спринклера","Цвету трубы","Температуре окружающей среды","Расходу Q"], re:"Потери на трение растут с расходом, возведённым примерно в степень 1.85, поэтому примерно удвоение расхода почти учетверяет потери. Показатель степени при Q в формуле Хазена-Вильямса (NFPA 13)."},
  {id:244, q:"В зависимости трения трубы по Хазену-Вильямсу потери на трение изменяются обратно пропорционально ДИАМЕТРУ трубы, возведённому в степень около:", opts:["4.87","1.85","1.0","10"], re:"Диаметр входит примерно в степени 4.87 в знаменателе, поэтому небольшое увеличение диаметра трубы резко снижает потери на трение. Хазен-Вильямс (NFPA 13)."},
  {id:245, q:"Если расход в трубе примерно удваивается (а размер трубы не меняется), потери на трение по Хазену-Вильямсу увеличатся приблизительно:", opts:["Без изменения","Примерно в 2 раза","Примерно в 4 раза (≈3.6×)","Примерно в 10 раз"], re:"Поскольку Q возводится в степень ~1.85, удвоение расхода умножает потери на трение примерно в 2^1.85 ≈ 3.6, то есть почти в 4×. Хазен-Вильямс (NFPA 13)."},
  {id:246, q:"Фитинги и арматура (колена, тройники, обратные клапаны) учитываются в гидравлических расчётах с помощью:", opts:["Количества болтов","Их веса в фунтах","Их цвета окраски","Эквивалентных длин трубы"], re:"NFPA 13 преобразует каждый фитинг/клапан в «эквивалентную длину» трубы, которая добавляется к фактической длине трубы перед расчётом потерь на трение. Метод эквивалентной длины NFPA 13."},
  {id:247, q:"Когда значение C трубы отличается от базового C = 120, используемого для табулирования эквивалентных длин фитингов, эквивалентные длины должны быть:", opts:["Проигнорированы","Обнулены","Всегда удвоены","Скорректированы (умножены) на поправку по C-фактору"], re:"Эквивалентные длины фитингов табулированы для C = 120 и должны быть умножены на поправочный коэффициент, когда фактическое значение C трубы отличается. Корректировка эквивалентной длины фитингов NFPA 13."},
  {id:248, q:"Самый эффективный способ СНИЗИТЬ потери на трение в длинном участке спринклерной трубы — это:", opts:["Использовать более шероховатую трубу","Добавить больше колен","Увеличить диаметр трубы","Снизить значение C"], re:"Поскольку потери изменяются обратно пропорционально диаметру в степени ~4.87, увеличение размера трубы — безусловно, самый эффективный способ сократить потери на трение. Чувствительность к диаметру по Хазену-Вильямсу (NFPA 13)."},
  {id:249, q:"Формула Хазена-Вильямса специально предназначена для течения:", opts:["Воды (турбулентный поток) в трубах","Сжатого воздуха","Пара","Электричества"], re:"Хазен-Вильямс — это эмпирическое уравнение для воды, текущей в трубах при турбулентных условиях, — именно тот случай в водяной противопожарной защите. Область применения Хазена-Вильямса (NFPA 13)."},
  {id:250, q:"По сравнению с новой чистой сталью, СТАРАЯ стальная труба с бугорчатой коррозией (корродированная) фактически ведёт себя так, как будто имеет значение C, которое:", opts:["Выше","Точно 150","Ниже","Без изменений"], re:"Внутренняя коррозия и образование бугорков делают канал шероховатым и снижают эффективное значение C, увеличивая потери на трение в течение срока службы трубы. Старение C-фактора по Хазену-Вильямсу (основа NFPA 13)."},
  {id:251, q:"Две одинаковые трубы несут одинаковый расход; труба A — медная (C=150), а труба B — стальная сухотрубной системы (C=100). У какой МЕНЬШИЕ потери на трение?", opts:["Труба A (медь, C=150)","Труба B (сталь, C=100)","Они идентичны","Невозможно определить"], re:"Более высокое значение C (медь, C=150) более гладкое и создаёт меньшие потери на трение при том же расходе. Сравнение C по Хазену-Вильямсу (NFPA 13)."},
  {id:252, q:"При испытании расхода гидранта «статическое давление» считывается на остаточном гидранте:", opts:["Только после окончания испытания","Пока испытательный гидрант полностью открыт","Без протекания через какие-либо гидранты","Внутри насоса"], re:"Статическое давление снимается на остаточном (с испытательным манометром) гидранте до открытия любого гидранта на проток. Процедура испытания расхода гидранта NFPA 291."},
  {id:253, q:"Во время испытания расхода гидранта «остаточное давление» считывается на остаточном гидранте:", opts:["До начала протока","Пока вода течёт из проточного гидранта(ов)","При всех закрытых гидрантах","У городского водохранилища"], re:"Остаточное давление — это показание манометра на остаточном гидранте, пока проточный гидрант(ы) сбрасывает воду; падение от статического до остаточного выявляет силу водопитателя. NFPA 291."},
  {id:254, q:"Трубка Пито, удерживаемая в струе на выходе протекающего гидранта, измеряет:", opts:["Статическое давление","Напор по высоте","Скоростное давление сбрасываемой струи (для расчёта расхода)","Давление воздуха"], re:"Пито считывает скоростное давление струи, которое преобразуется в расход (gpm) с использованием размера выходного отверстия и коэффициента расхода. Метод Пито NFPA 291."},
  {id:255, q:"Общая формула расхода из гидранта/насадки по показанию Пито — это Q = 29.83 × c × d² × √P, где «d» — это:", opts:["Расстояние до пожара","Количество выходов","Глубина магистрали","Диаметр выходного отверстия (отверстия) в дюймах"], re:"В Q = 29.83·c·d²·√P d — это диаметр выходного отверстия сброса (дюймы), c — коэффициент, а P — давление Пито (psi). Формула расхода гидранта NFPA 291 / IFSTA."},
  {id:256, q:"Испытание расхода водопитателя обычно используется для установления доступной воды при остаточном давлении:", opts:["0 psi","20 psi","100 psi","175 psi"], re:"Результаты обычно проецируются на расход, доступный при 20 psi остаточном — значении, используемом для цветовой маркировки гидрантов и проектирования. NFPA 291 (20 psi остаточное)."},
  {id:257, q:"Чтобы получить надёжные результаты испытания гидранта, NFPA 291 рекомендует пропускать достаточно воды, чтобы снизить остаточное давление как минимум на:", opts:["5%","10%","25%","75%"], re:"Падение давления как минимум на 25% от статического повышает точность при проецировании доступного расхода на другие давления. Рекомендуемое падение NFPA 291."},
  {id:258, q:"По шкале цветовой маркировки гидрантов NFPA 291 гидрант, обеспечивающий 1,500 gpm или более при 20 psi, окрашивается (с крышками) каким цветом КЛАССА?", opts:["Красным","Светло-голубым","Зелёным","Оранжевым"], re:"NFPA 291 маркирует гидранты класса AA (≥1,500 gpm при 20 psi) светло-голубым; зелёный = 1,000–1,499, оранжевый = 500–999, красный = ниже 500 gpm. Цветовые классы NFPA 291."},
  {id:259, q:"По шкале NFPA 291 КРАСНЫЙ колпак/крышка гидранта указывает на доступный расход при 20 psi:", opts:["1,500 gpm или более","500–999 gpm","1,000–1,499 gpm","Менее 500 gpm"], re:"Красный маркирует самые слабые гидранты — менее 500 gpm доступно при 20 psi остаточном. Цветовые классы NFPA 291."},
  {id:260, q:"Муниципальная (городская) водяная магистраль, подведённая к зданию, — это пример:", opts:["Источника общественного водоснабжения","Частного пожарного насоса","Гравитационного бака","Напорного бака"], re:"Городская/муниципальная магистраль — это общественный водопитатель; частные баки, резервуары и насосы дополняют его, когда он недостаточен. Источники водоснабжения NFPA 13."},
  {id:261, q:"Гравитационный (приподнятый) накопительный бак обеспечивает давление противопожарной защиты главным образом за счёт:", opts:["Сжатого воздуха над водой","Своей высоты/возвышения над системой (напор)","Электрического нагревателя","Дизельного двигателя"], re:"Гравитационный бак создаёт давление за счёт своей высоты — каждый фут возвышения добавляет около 0.433 psi у основания. Принцип гравитационного бака NFPA 22."},
  {id:262, q:"Напорный бак подаёт воду под давлением, поддерживая подушку из:", opts:["Пара","Сжатого воздуха над хранимой водой","Вакуума","Песка"], re:"Напорный бак частично заполнен водой и находится под давлением сжатого воздуха, чтобы вода сбрасывалась немедленно по требованию. Напорный бак NFPA 22."},
  {id:263, q:"Стандарт, регулирующий проектирование и строительство накопительных баков для воды для частной противопожарной защиты, — это:", opts:["NFPA 13","NFPA 14","NFPA 20","NFPA 22"], re:"NFPA 22 охватывает баки для воды (гравитационные, всасывающие, напорные, насыпные), используемые для частной противопожарной защиты. Область применения NFPA 22."},
  {id:264, q:"Стандарт, охватывающий монтаж ЧАСТНЫХ МАГИСТРАЛЕЙ ПРОТИВОПОЖАРНОГО ВОДОСНАБЖЕНИЯ и их принадлежностей (подземное снабжение объекта), — это:", opts:["NFPA 24","NFPA 13D","NFPA 25","NFPA 72"], re:"NFPA 24 регулирует частные магистрали противопожарного водоснабжения — подземные трубопроводы, арматуру и гидранты, подающие воду на объект. Область применения NFPA 24."},
  {id:265, q:"Требуемая ВМЕСТИМОСТЬ (объём) накопительного бака для противопожарной защиты определяется:", opts:["Цветом бака","Потребностью в пожарном расходе (gpm), умноженной на требуемую продолжительность (минуты)","Количеством болтов","Только мощностью насоса в лошадиных силах"], re:"Объём бака = требуемый пожарный расход (gpm) × требуемая продолжительность водоснабжения (минуты), задаваемые потребностью системы и пожароопасностью. Определение размера водопитателя NFPA 22 / NFPA 13."},
  {id:266, q:"Всасывающий бак на уровне земли отличается от гравитационного бака тем, что он:", opts:["Создаёт полное давление системы только за счёт высоты","Не нуждается в насосе или возвышении","Использует только сжатый воздух","Питает пожарный насос, который повышает давление"], re:"Всасывающий (наземный) бак хранит воду на низкой отметке и питает пожарный насос, который обеспечивает необходимое давление. Всасывающий бак NFPA 22 / NFPA 20."},
  {id:267, q:"Когда общественная магистраль не может обеспечить требуемые пожарный расход И давление, обычное решение — добавить:", opts:["Более толстое лакокрасочное покрытие","Второй водосток крыши","Трубу меньшего размера","Пожарный насос и/или накопительный бак"], re:"Недостаточный общественный водопитатель дополняется хранимым источником воды (бак/резервуар) и/или пожарным насосом для удовлетворения потребности. Положения о водоснабжении NFPA 13 / NFPA 20."},
  {id:268, q:"При испытании гидрантов, если падение давления от статического до остаточного очень МАЛО при протоке большого количества, водопитатель является:", opts:["Очень слабым","Сильным (обильным)","Замёрзшим","Отключённым"], re:"Малое падение давления при большом протоке указывает на сильный, обильный водопитатель; большое падение указывает на слабый водопитатель. Интерпретация результатов испытания NFPA 291."},
  {id:269, q:"Стандарт на монтаж стационарных насосов для противопожарной защиты — это:", opts:["NFPA 20","NFPA 14","NFPA 13","NFPA 25"], re:"NFPA 20 регулирует выбор и монтаж стационарных пожарных насосов, их приводов, контроллеров и принадлежностей. Область применения NFPA 20."},
  {id:270, q:"Наиболее распространённый тип пожарного насоса, используемый для водяной противопожарной защиты, — это:", opts:["Горизонтальный центробежный насос с раздельным корпусом","Поршневой насос объёмного действия","Ручной насос","Перистальтический насос"], re:"Центробежные насосы (обычно горизонтальные с раздельным корпусом) — это стандартный тип пожарного насоса; насосы объёмного действия ограничены особыми применениями, такими как пена/водяной туман. Типы насосов NFPA 20."},
  {id:271, q:"На рабочей характеристике пожарного насоса «churn» (закрытая задвижка) — это условие, при котором насос работает при:", opts:["Нулевом расходе (без сброса)","100% номинального расхода","150% номинального расхода","Максимальной перегрузке"], re:"Churn (закрытая задвижка) — это работа при нулевом расходе; насос рециркулирует внутри и создаёт свой максимальный напор. Характеристика насоса NFPA 20 (точка churn)."},
  {id:272, q:"При CHURN (нулевой расход) NFPA 20 ограничивает полный напор (давление) не более какого процента от номинального давления?", opts:["100%","121%","140%","175%"], re:"Давление churn (закрытой задвижки) не должно превышать 140% номинального давления для сертифицированного пожарного насоса. Предел давления churn NFPA 20."},
  {id:273, q:"При 150% номинального расхода (точка перегрузки) пожарный насос должен по-прежнему создавать полный напор не менее:", opts:["50% номинального напора","65% номинального напора","100% номинального напора","140% номинального напора"], re:"При 150% номинальной производительности насос должен обеспечивать не менее 65% своего номинального полного напора. Требование к точке перегрузки NFPA 20."},
  {id:274, q:"«Номинальная» точка пожарного насоса — это точка, в которой он обеспечивает:", opts:["Нулевой расход при максимальном напоре","Давление churn","150% расхода при 65% напора","100% номинальной производительности при 100% номинального напора"], re:"Номинальная (100%) точка — это сертифицированные расход и давление, которые насос выбран обеспечивать. Номинальная точка NFPA 20."},
  {id:275, q:"Три точки, проверяемые при приёмочном испытании расхода пожарного насоса, — это churn (нулевой расход), 100% номинального расхода и:", opts:["50% номинального расхода","125% номинального расхода","150% номинального расхода","200% номинального расхода"], re:"NFPA 20 требует испытания при churn, 100% и 150% номинальной производительности для проверки рабочей характеристики насоса. Точки расхода приёмочного испытания NFPA 20."},
  {id:276, q:"Небольшой насос, который поддерживает давление системы между заданными пределами, когда вода не течёт, называется:", opts:["Жокей-насос (насос поддержания давления)","Подпорный сбросной насос","Дренажный насос","Заливочный насос"], re:"Жокей-насос (насос поддержания давления) компенсирует мелкие утечки, чтобы основной пожарный насос не запускался при небольших падениях давления. Жокей-насос NFPA 20."},
  {id:277, q:"Жокей-насос должен быть подобран так, чтобы обеспечивать расход, который:", opts:["Больше, чем у пожарного насоса","Не менее 150% номинального расхода","Точно равен расходу пожарного насоса","Меньше расхода одного спринклера"], re:"Жокей-насос подбирается для компенсации допустимой утечки — меньше расхода одного спринклера — так, чтобы фактическое срабатывание спринклера заставило основной насос запуститься. Руководство по подбору жокей-насоса NFPA 20."},
  {id:278, q:"Типовые настройки реле давления устроены так, чтобы ЖОКЕЙ-насос запускался и останавливался:", opts:["При более высоких давлениях, чем пожарный насос (выше точки запуска пожарного насоса)","При более низких давлениях, чем пожарный насос","Только когда работает пожарный насос","Никогда автоматически"], re:"Настройки запуска/остановки жокей-насоса выше точки запуска пожарного насоса, чтобы жокей справлялся с мелкими утечками, а пожарный насос запускался только при реальной потребности. Иерархия настроек давления NFPA 20."},
  {id:279, q:"После того как ЭЛЕКТРОПРИВОДНОЙ пожарный насос автоматически запускается, его контроллер обычно обязан:", opts:["Остановить его через 10 секунд","Требовать ручной остановки (не останавливаться автоматически), если не предусмотрена автоматическая остановка с таймером минимального времени работы","Запускать его ровно на 1 минуту","Быстро включать и выключать его"], re:"NFPA 20 обычно требует ручной остановки пожарного насоса после автоматического запуска; там, где разрешена автоматическая остановка, применяется таймер минимального времени работы. Требования к контроллеру/остановке NFPA 20."},
  {id:280, q:"Пожарный насос, приводимый ДИЗЕЛЬНЫМ двигателем, должен быть обеспечен запасом топлива, рассчитанным как минимум на проектное время работы, а контроллер двигателя должен включать:", opts:["Только один аккумулятор","Никаких аккумуляторов","Два блока аккумуляторных батарей (двойные батареи)","Стартер только переменного тока"], re:"Контроллеры дизельных пожарных насосов требуют двух отдельных блоков аккумуляторных батарей, чтобы прокрутка двигателя была надёжной при отказе одного блока. Батареи дизельного контроллера NFPA 20."},
  {id:281, q:"Циркуляционный (корпусной) предохранительный клапан на пожарном насосе предусмотрен главным образом для:", opts:["Повышения давления сброса","Сброса накопления тепла за счёт допуска небольшого протока во время работы при churn (нулевом расходе)","Заливки насоса","Замены обратного клапана"], re:"Небольшой корпусной/циркуляционный предохранительный клапан сбрасывает немного воды во время churn, чтобы предотвратить перегрев насоса при работе на нулевом расходе. Циркуляционный предохранительный клапан NFPA 20."},
  {id:282, q:"ОСНОВНОЙ предохранительный клапан требуется на пожарном насосе, когда система может подвергнуться давлениям, которые:", opts:["Могут превысить расчётное давление компонентов системы (например, превышение оборотов дизеля)","Всегда безопасны","Никогда не возникают","Равны атмосферному давлению"], re:"Основной предохранительный клапан давления защищает компоненты, когда возможно избыточное давление (например, дизельный двигатель, работающий выше номинальных оборотов, или давления выше расчётного для системы). Основной предохранительный клапан NFPA 20."},
  {id:283, q:"Чтобы предотвратить частые пуски/остановки пожарного насоса (быстрый пуск/остановку) при мелких утечках, система полагается на:", opts:["Основной дренаж","Испытательный клапан инспектора","Жокей-насос и правильные настройки давления","Детектор дыма"], re:"Жокей-насос справляется с мелкими утечками, чтобы основной пожарный насос не запускался при незначительных падениях давления, предотвращая разрушительные короткие циклы. Функция поддержания давления NFPA 20."},
  {id:284, q:"Пожарный насос должен быть способен обеспечивать свой требуемый расход даже когда давление всасывающего водопитателя так низко, как минимальное значение, разрешённое AHJ, и NFPA 20 требует, чтобы давление на всасывании при 150% расхода оставалось не менее:", opts:["100 psi","50 psi","0 psi (не отрицательное)","175 psi"], re:"NFPA 20 обычно требует, чтобы давление по манометру на всасывании оставалось на уровне 0 psi или выше, когда насос работает при 150% номинального расхода (небольшое отрицательное значение допускается только для сертифицированных схем наземного всасывающего бака). Требование к давлению на всасывании NFPA 20."},
  {id:285, q:"Пожарный насос устанавливается главным образом для того, чтобы:", opts:["Охлаждать здание","Обнаруживать дым","Хранить воду в течение месяцев","Повышать (увеличивать) давление и/или расход воды для удовлетворения потребности системы"], re:"Пожарный насос повышает давление (и обеспечивает расход), когда доступный водопитатель не может удовлетворить потребность спринклеров/стояков. Назначение пожарных насосов NFPA 20."},
  {id:286, q:"Стандарт на монтаж систем стояков и пожарных кранов с рукавами — это:", opts:["NFPA 14","NFPA 13","NFPA 20","NFPA 24"], re:"NFPA 14 регулирует проектирование и монтаж систем стояков и пожарных кранов с рукавами в зданиях. Область применения NFPA 14."},
  {id:287, q:"Система стояков класса I обеспечивает рукавное соединение какого размера, предназначенное для использования пожарной охраной?", opts:["1 дюйм","2½ дюйма","1½ дюйма","4 дюйма"], re:"Класс I обеспечивает рукавные соединения 2½ дюйма для обученных пожарных / использования пожарной охраной. Класс I NFPA 14."},
  {id:288, q:"Система стояков класса II обеспечивает рукавные посты 1½ дюйма, предназначенные главным образом для использования:", opts:["Только пожарной охраной","Сантехниками","Обученными жильцами здания / первичного пожаротушения","Лифтовыми техниками"], re:"Класс II обеспечивает рукав 1½ дюйма (часто на стойке/катушке) для первичного пожаротушения жильцами. Класс II NFPA 14."},
  {id:289, q:"Система стояков класса III обеспечивает:", opts:["Только соединения 1 дюйм","Рукавные соединения как 2½ дюйма, так и 1½ дюйма (функции класса I + класса II)","Никаких рукавных соединений","Только спринклеры"], re:"Класс III сочетает функции класса I (2½ дюйма) и класса II (1½ дюйма), обслуживая как использование пожарной охраной, так и жильцами. Класс III NFPA 14."},
  {id:290, q:"Для стояка класса I или класса III NFPA 14 требует минимальное ОСТАТОЧНОЕ давление у самого верхнего (наиболее удалённого) выхода 2½ дюйма не менее:", opts:["100 psi","65 psi","150 psi","175 psi"], re:"NFPA 14 требует 100 psi остаточных у гидравлически наиболее удалённого выхода 2½ дюйма (при требуемом расходе). Давление класса I/III NFPA 14."},
  {id:291, q:"Для стояка класса II NFPA 14 требует минимальное остаточное давление у наиболее удалённого выхода 1½ дюйма не менее:", opts:["25 psi","100 psi","65 psi","175 psi"], re:"NFPA 14 требует 65 psi остаточных у наиболее удалённого рукавного соединения 1½ дюйма при требуемом расходе класса II. Давление класса II NFPA 14."},
  {id:292, q:"Минимальный расход, используемый для определения размера наиболее удалённого стояка класса I (первого/наиболее удалённого стояка), составляет:", opts:["500 gpm","250 gpm","100 gpm","1,000 gpm"], re:"Наиболее удалённый стояк класса I рассчитывается на 500 gpm (через два наиболее удалённых выхода 2½ дюйма). Расход класса I NFPA 14."},
  {id:293, q:"За каждый ДОПОЛНИТЕЛЬНЫЙ стояк сверх наиболее удалённого NFPA 14 обычно добавляет надбавку к расходу:", opts:["50 gpm","100 gpm","500 gpm","250 gpm"], re:"Каждый дополнительный стояк добавляет 250 gpm к потребности (для площадей этажей, не превышающих пороговое значение). Расход дополнительного стояка NFPA 14."},
  {id:294, q:"Минимальный расход для рукавного поста стояка класса II составляет:", opts:["50 gpm","500 gpm","250 gpm","100 gpm"], re:"Рукавный пост класса II рассчитывается на 100 gpm у наиболее удалённого соединения 1½ дюйма. Расход класса II NFPA 14."},
  {id:295, q:"NFPA 14 ограничивает общую требуемую потребность системы стояков для полностью оборудованного спринклерами здания значением:", opts:["1,000 gpm","500 gpm","1,250 gpm","2,000 gpm"], re:"Общая потребность класса I не должна превышать 1,000 gpm в здании, полностью защищённом спринклерами (1,250 gpm там, где не полностью оборудовано спринклерами). Максимальная потребность NFPA 14."},
  {id:296, q:"NFPA 14 ограничивает общую требуемую потребность стояков для здания, которое НЕ полностью оборудовано спринклерами, значением:", opts:["750 gpm","1,000 gpm","1,250 gpm","2,500 gpm"], re:"Для зданий, не защищённых полностью спринклерами, общая потребность стояка класса I не должна превышать 1,250 gpm. Максимальная потребность NFPA 14."},
  {id:297, q:"Там, где статическое давление у рукавного соединения ПРЕВЫСИЛО БЫ 175 psi, NFPA 14 требует использования:", opts:["Спринклера большего размера","Никакого специального устройства","Только обратного клапана","Редукционного клапана давления (PRV) или регулирующего давление устройства"], re:"Чтобы давления рукавных соединений оставались пригодными для использования и в пределах норм, регулирующие/редукционные устройства давления требуются там, где статическое давление превышает около 175 psi. Требование о регулировании давления NFPA 14."},
  {id:298, q:"«Водозаполненный» стояк отличается от «сухого» (или автоматического-сухого) стояка тем, что водозаполненная система:", opts:["Не имеет источника воды","Использует для воды только автонасос пожарной охраны","Заполнена водой постоянно","Не имеет рукавных соединений"], re:"Водозаполненный стояк содержит воду постоянно, поэтому проток немедленный; сухой стояк обычно пуст и заполняется при необходимости (вручную или автоматически). Водозаполненный против сухого стояка NFPA 14."},
  {id:299, q:"Соединение пожарной охраны (FDC) на системе стояков позволяет пожарной охране:", opts:["Нагнетать дополнительную воду/давление в стояк от автонасоса","Сливать систему","Отключать спринклеры","Проверять дымовые извещатели"], re:"FDC позволяет прибывшей технике нагнетать воду и давление в систему стояков/спринклеров для поддержки пожаротушения. Соединение пожарной охраны NFPA 14."},
  {id:300, q:"В высотном здании рукавные соединения стояков обычно требуется располагать:", opts:["Только в вестибюле","Только на крыше","В эвакуационных лестничных клетках (и по требованию на каждом уровне этажа)","В кабине лифта"], re:"Рукавные соединения стояков располагаются в эвакуационных лестничных клетках (и других требуемых точках), чтобы пожарные могли подключаться на каждом этаже в защищённом месте. Расположение рукавных соединений NFPA 14."},
  {id:301, q:"NFPA 25 — это стандарт по осмотру, испытанию и обслуживанию (ITM):", opts:["Систем противопожарной защиты на водной основе","Переносных огнетушителей","Только систем пожарной сигнализации","Аварийного освещения"], re:"NFPA 25 называется «Стандарт по осмотру, испытанию и обслуживанию систем противопожарной защиты на водной основе» и охватывает спринклерные системы, водопроводные стояки (standpipe), пожарные насосы и связанные системы (NFPA 25, гл. 1)."},
  {id:302, q:"Согласно NFPA 25, сторона, несущая конечную ответственность за ведение записей ITM и предоставление их AHJ, — это:", opts:["Подрядчик по спринклерным системам","Владелец объекта или его назначенный представитель","Пожарная служба","Страховая компания"], re:"NFPA 25, гл. 4 («Обязанности владельца») возлагает ответственность за ITM, ведение записей и предоставление записей AHJ на владельца объекта или его назначенного представителя."},
  {id:303, q:"NFPA 25 определяет «ежегодную» периодичность как происходящую раз в год в диапазоне:", opts:["Ровно 12 месяцев","Минимум 6 месяцев, максимум 18 месяцев","Минимум 9 месяцев, максимум 15 месяцев","Минимум 11 месяцев, максимум 13 месяцев"], re:"NFPA 25 определяет ежегодную периодичность как раз в год с минимумом 9 месяцев и максимумом 15 месяцев между мероприятиями (определения периодичности NFPA 25, гл. 3)."},
  {id:304, q:"Согласно NFPA 25, испытание основного дренажа (main drain test) на каждом стояке системы проводится не реже чем:", opts:["Еженедельно","Ежемесячно","Каждые 5 лет","Ежегодно"], re:"NFPA 25 (гл. 13) требует испытания основного дренажа не реже одного раза в год на каждом стояке системы на водной основе для обнаружения изменения в водоснабжении или контрольных клапанах."},
  {id:305, q:"Как часто согласно NFPA 25 необходимо проводить испытание прямого потока (forward flow test) обратного клапана (предотвращения обратного потока) в системе противопожарной защиты?", opts:["Ежегодно","Ежеквартально","Каждые 3 года","Каждые 5 лет"], re:"NFPA 25 (гл. 13) требует, чтобы узлы предотвращения обратного потока в противопожарном трубопроводе ежегодно испытывались прямым потоком при расходе, соответствующем потребности системы."},
  {id:306, q:"Испытание срабатывания при полном расходе (full-flow trip test) клапана сухотрубной системы должно проводиться не реже чем каждые:", opts:["Год","3 года","2 года","5 лет"], re:"NFPA 25 (гл. 13) требует испытания срабатывания при полном расходе клапанов сухотрубных систем не реже чем каждые 3 года, в дополнение к ежегодному частичному испытанию срабатывания (по линии заполнения)."},
  {id:307, q:"Согласно NFPA 25, манометры системы должны заменяться или испытываться путём сравнения с калиброванным манометром не реже чем каждые:", opts:["Год","3 года","5 лет","10 лет"], re:"NFPA 25 (гл. 13) требует заменять манометры или испытывать их сравнением с калиброванным манометром каждые 5 лет; манометры с отклонением более 3% от полной шкалы калибруются заново или заменяются."},
  {id:308, q:"С какой минимальной периодичностью согласно NFPA 25 проводится функциональное испытание устройств сигнализации потока воды на мокротрубных системах?", opts:["Еженедельно","Ежемесячно","Ежегодно","Ежеквартально"], re:"NFPA 25 (гл. 5) требует, чтобы устройства сигнализации потока воды на мокротрубных спринклерных системах испытывались ежеквартально через испытательное соединение инспектора."},
  {id:309, q:"Растворы антифриза в спринклерной системе должны испытываться на концентрацию не реже чем:", opts:["Ежегодно","Ежеквартально","Ежемесячно","Каждые 5 лет"], re:"NFPA 25 (гл. 5) требует, чтобы растворы антифриза испытывались не реже одного раза в год, до наступления морозной погоды, для подтверждения надлежащей защиты от замерзания."},
  {id:310, q:"Согласно NFPA 25, внутренний осмотр трубопровода на наличие препятствий (5-летний внутренний осмотр) проводится каждые:", opts:["Год","5 лет","3 года","10 лет"], re:"NFPA 25 (гл. 14) требует внутреннего осмотра трубопровода на наличие препятствующего материала каждые 5 лет для выявления инородных веществ, бугорчатой коррозии, отложений или MIC."},
  {id:311, q:"С какой периодичностью согласно NFPA 25 испытываются контрольные (антивандальные, tamper) переключатели клапанов на правильный сигнал?", opts:["Ежеквартально","Ежегодно","Раз в полгода","Каждые 5 лет"], re:"NFPA 25 (гл. 13) требует, чтобы контрольные переключатели клапанов испытывались раз в полгода (каждые 6 месяцев) для проверки выдачи сигнала при смещении клапана из его нормального положения."},
  {id:312, q:"Спринклеры стандартного срабатывания (изготовленные в 1920 году или позже) впервые требуют испытания репрезентативной выборки в каком возрасте, а затем каждые 10 лет после этого?", opts:["20 лет","100 лет","75 лет","50 лет"], re:"NFPA 25 (гл. 5) требует, чтобы спринклеры стандартного срабатывания испытывались по выборке в 50 лет и каждые 10 лет после этого; в 75 лет интервал сокращается до каждых 5 лет (или замена)."},
  {id:313, q:"Спринклеры сухого типа (с удлинённым сухим стволом) требуют испытания репрезентативной выборки начиная с какого возраста?", opts:["20 лет","10 лет","50 лет","75 лет"], re:"NFPA 25 (гл. 5) требует, чтобы спринклеры сухого типа испытывались по выборке через 10 лет после изготовления в более старых редакциях; широко цитируемый интервал — 20 лет после установки, затем каждые 10 лет (NFPA 25 2023)."},
  {id:314, q:"Согласно NFPA 25, записи ITM должны храниться не менее:", opts:["30 дней","1 года после следующего осмотра того же типа","6 месяцев","Вечно"], re:"NFPA 25, гл. 4 требует, чтобы записи хранились в течение 1 года после следующего мероприятия ITM того же типа (дольше, если местный кодекс, например IFC, требует большего)."},
  {id:315, q:"На мокротрубной системе манометр около клапана сигнализации осматривается (считывается) с какой минимальной периодичностью согласно NFPA 25?", opts:["Ежедневно","Еженедельно","Ежемесячно","Ежегодно"], re:"NFPA 25 (гл. 5/13) требует, чтобы манометры на мокротрубных системах осматривались ежемесячно для подтверждения нормального давления воды; сухотрубные/предварительного действия системы проверяются еженедельно."},
  {id:316, q:"Водяной гонг (механическая сигнализация потока воды) испытывается с какой минимальной периодичностью согласно NFPA 25?", opts:["Каждые 5 лет","Раз в полгода","Ежегодно","Ежеквартально"], re:"NFPA 25 (гл. 5) требует, чтобы механические устройства потока воды, такие как водяной гонг, испытывались ежеквартально; устройства с реле давления и лопастного типа (vane) испытываются раз в полгода."},
  {id:317, q:"Кто согласно NFPA 25 должен быть квалифицирован и компетентен для выполнения ITM систем противопожарной защиты на водной основе?", opts:["Персонал, развивший компетентность посредством обучения и опыта","Любой обитатель здания","Только зарегистрированный архитектор","Только пожарный маршал"], re:"NFPA 25, гл. 4 требует, чтобы ITM выполнялось квалифицированным персоналом, развившим компетентность посредством обучения и опыта; многие юрисдикции, включая Калифорнию, также требуют лицензирования/сертификации."},
  {id:318, q:"Новый спринклерный трубопровод должен испытываться гидростатически при каком минимальном давлении в течение 2 часов согласно NFPA 13?", opts:["100 psi","200 psi","150 psi","300 psi"], re:"NFPA 13 требует, чтобы новые спринклерные системы испытывались гидростатически при давлении не менее 200 psi в течение 2 часов (или на 50 psi выше максимального статического давления, когда оно превышает 150 psi)."},
  {id:319, q:"Когда нормальное статическое давление превышает 150 psi, давление приёмочного гидростатического испытания должно составлять не менее:", opts:["200 psi","Удвоенного статического давления","На 50 psi выше максимального статического давления","Такого же, как статическое давление"], re:"NFPA 13 требует, чтобы испытательное давление было на 50 psi выше максимального статического (системного) давления, когда этот максимум превышает 150 psi; в противном случае используется 200 psi."},
  {id:320, q:"Приёмочное гидростатическое испытание должно удерживать требуемое давление в течение минимальной продолжительности:", opts:["30 минут","1 часа","24 часов","2 часов"], re:"NFPA 13 требует, чтобы давление гидростатического испытания поддерживалось в течение 2 часов без видимых утечек и с допустимой потерей давления."},
  {id:321, q:"Гидростатическое испытание нового металлического спринклерного трубопровода считается успешным, когда через 2 часа имеется:", opts:["Отсутствие видимых утечек (и потеря давления не превышает 5 psi там, где измеряется)","Падение не более 10 psi","Любое падение менее 50 psi","Повышение давления"], re:"Критерии приёмки NFPA 13 требуют отсутствия видимых утечек; там, где применяются критерии потери давления, потеря ограничена примерно 5 psi за 2 часа для прохождения испытания."},
  {id:322, q:"Приёмочные гидростатические испытания спринклерного противопожарного трубопровода обычно проводятся с использованием:", opts:["Только сжатого воздуха","Воды","Азота","Пара"], re:"NFPA 13 требует, чтобы гидростатические испытания проводились водой; испытание на утечку воздуха (пневматическое) — это лишь дополнительная проверка для сухотрубных систем/систем предварительного действия, а не замена гидростатического испытания."},
  {id:323, q:"Сухотрубные системы и системы предварительного действия в дополнение к гидростатическому испытанию также проходят испытание на утечку воздуха под давлением:", opts:["200 psi в течение 2 часов","100 psi в течение 1 часа","40 psi в течение 24 часов","Испытание воздухом не допускается"], re:"NFPA 13 требует, чтобы сухотрубные системы/системы предварительного действия также испытывались воздухом при 40 psi в течение 24 часов с максимально допустимой потерей 1,5 psi за этот период."},
  {id:324, q:"При пневматическом испытании сухотрубной системы/системы предварительного действия при 40 psi в течение 24 часов максимально допустимая потеря давления составляет:", opts:["20 psi","5 psi","10 psi","1,5 psi"], re:"NFPA 13 ограничивает потерю при 24-часовом испытании воздухом при 40 psi величиной 1,5 psi; большая потеря указывает на утечки, которые должны быть найдены и устранены."},
  {id:325, q:"Ручные и полуавтоматические сухие водопроводные стояки (standpipe) повторно испытываются гидростатически согласно NFPA 25 с каким интервалом?", opts:["Каждые 5 лет","Каждые 3 года","Ежегодно","Каждые 10 лет"], re:"NFPA 25 (гл. 6) требует, чтобы ручные и полуавтоматические сухие водопроводные стояки испытывались гидростатически при 200 psi (или на 50 psi выше максимального давления) в течение 2 часов каждые 5 лет."},
  {id:326, q:"При приёмке подземная магистраль водоснабжения, питающая спринклерную систему, должна промываться (flush) перед подключением главным образом для того, чтобы:", opts:["Повысить давление воды","Удалить мусор, камни и инородные вещества, которые могут засорить спринклеры","Испытать обратный клапан","Хлорировать воду"], re:"NFPA 24/13 требуют, чтобы подземный ввод промывался при высокой скорости перед подключением системы, чтобы камни, грязь и мусор не могли попасть и засорить спринклеры или клапаны."},
  {id:327, q:"Сертификат подрядчика на материалы и испытания для надземной спринклерной системы заполняется и подписывается:", opts:["До установки любого трубопровода","Только если AHJ запрашивает его","После приёмочного испытания, документируя результаты испытания","Каждый год во время ITM"], re:"NFPA 13 требует, чтобы Сертификат подрядчика на материалы и испытания для надземного трубопровода заполнялся после приёмочного испытания для документирования гидростатического испытания, промывки и других результатов, и предоставлялся владельцу/AHJ."},
  {id:328, q:"Во время приёмочного гидростатического испытания манометры, устройства сигнализации и другое оборудование, не рассчитанное на испытательное давление, следует:", opts:["Оставить на месте, чтобы также их испытать","Покрасить","Установить на максимум","Изолировать или снять, чтобы они не повредились"], re:"Оборудование, не рассчитанное на повышенное испытательное давление (например, некоторые манометры, обвязка сухотрубного клапана, устройства сигнализации), изолируется или снимается во время гидростатического испытания во избежание повреждения, согласно практике NFPA 13."},
  {id:329, q:"Гидростатическое испытание следует проводить с помощью испытательного насоса, сбрасывая давление системы перед отсоединением, потому что:", opts:["Запертое высокое давление может вызвать травму или повреждение компонентов при внезапном сбросе","Вода пригодна для повторного использования","Это ускоряет испытание","Кодекс запрещает манометры"], re:"Накопленная гидростатическая энергия опасна; сброс давления перед разъединением соединений предотвращает травмы и повреждение оборудования. Это стандартная безопасная практика при испытаниях по NFPA 13/25."},
  {id:330, q:"После добавления или модификации более 20 спринклеров в существующей системе NFPA 13 обычно требует:", opts:["Никаких испытаний","Приёмочного гидростатического испытания новых работ","5-летнего исследования препятствий","Только визуальной проверки"], re:"NFPA 13 требует приёмочного (гидростатического) испытания нового или модифицированного трубопровода; модификации, затрагивающие более 20 спринклеров, обычно требуют полного приёмочного испытания затронутых работ и уведомления AHJ."},
  {id:331, q:"Перед проведением гидростатического испытания в условиях замерзания испытатель должен убедиться, что испытательная вода:", opts:["Нагрета до кипения","Содержит концентрат пены","Не замёрзнет в трубопроводе во время или после испытания","Является солёной водой"], re:"Испытательная вода должна быть защищена от замерзания; лёд может повредить трубопровод и сделать результаты недействительными. NFPA 13 предостерегает от гидростатического испытания там, где вода может замёрзнуть до её слива."},
  {id:332, q:"Приёмочное испытание рабочей (сигнальной) функции спринклерной системы во время ввода в эксплуатацию подтверждает, что:", opts:["Цвет трубы правильный","У владельца есть страховка","Спринклеры покрашены","Поток воды через систему приводит в действие сигнализацию потока воды"], re:"Приёмочное испытание включает эксплуатационное испытание, подтверждающее, что поток приводит в действие сигнализацию потока воды (водяной гонг/реле давления) в течение требуемого времени, демонстрируя, что путь сигнализации работает."},
  {id:333, q:"Исследование промывки/испытание потока подземного соединения и ввода при приёмке проводится со скоростью, достаточной для того, чтобы:", opts:["Вынести препятствующий материал (признанная минимальная скорость промывки)","Разорвать трубу","Наполнить накопительный бак","Испытать спринклерные оросители"], re:"NFPA 24 определяет минимальные расходы промывки по размеру трубы для достижения скорости (около 10 ft/s), которая вымывает мусор из магистрали до того, как он сможет попасть в систему."},
  {id:334, q:"Для трубопровода CPVC и другого неметаллического спринклерного трубопровода инструкции изготовителя по гидростатическому испытанию должны соблюдаться, потому что:", opts:["Пластик нельзя испытывать","Время отверждения и пределы давления отличаются от стали и должны соблюдаться","Он освобождён от NFPA 13","Испытание воздухом заменяет испытание водой"], re:"Сертифицированный неметаллический трубопровод (например, CPVC) требует времени отверждения растворителя-цемента перед подачей давления и имеет особые параметры испытания; NFPA 13 требует следовать сертификации и инструкциям изготовителя."},
  {id:335, q:"Основная цель испытания основного дренажа состоит в том, чтобы:", opts:["Осушить систему на зиму","Испытать спринклерные оросители","Обнаружить изменение в состоянии водоснабжения и основного контрольного клапана","Вымыть антифриз"], re:"NFPA 25 (гл. 13) гласит, что испытание основного дренажа обнаруживает изменение в трубопроводе водоснабжения и в основном контрольном клапане (например, частично закрытый клапан или ухудшение водоснабжения)."},
  {id:336, q:"Во время испытания основного дренажа вы записываете статическое давление, затем полностью открываете основной дренаж и записываете:", opts:["Давление воздуха","Диаметр трубы","Температуру спринклера","Остаточное (текущее) давление"], re:"Испытание сравнивает статическое давление с остаточным давлением при полностью открытом дренаже; остаточное показание сравнивается с предыдущими испытаниями и первоначальным приёмочным значением (NFPA 25, гл. 13)."},
  {id:337, q:"Согласно NFPA 25, какое снижение давления основного дренажа при полном расходе по сравнению с предыдущими результатами требует расследования?", opts:["10% или более","Любое снижение вообще","25% или более","50% или более"], re:"NFPA 25 (гл. 13) требует расследования при снижении на 10% или более давления при полном расходе (остаточного) по сравнению с первоначальным приёмочным испытанием или предыдущими результатами."},
  {id:338, q:"Резко сниженное остаточное давление при испытании основного дренажа чаще всего указывает на:", opts:["Слишком много спринклеров","Частично закрытый клапан или засорённое водоснабжение","Новый насос","Холодную погоду"], re:"Большое падение или низкое остаточное давление обычно указывает на частично закрытый контрольный клапан, препятствие или ухудшившееся водоснабжение, всё из которых должно быть расследовано и устранено (NFPA 25, гл. 13)."},
  {id:339, q:"Когда единственное водоснабжение системы проходит через обратный клапан или редукционный клапан давления, NFPA 25 требует проводить испытание основного дренажа:", opts:["Никогда","Только через 5 лет","Ежеквартально (на системе ниже по потоку)","Только при приёмке"], re:"NFPA 25 (гл. 13) требует ежеквартального испытания основного дренажа на системе ниже по потоку, где водоснабжение проходит через обратный клапан или PRV, для подтверждения того, что устройство и клапан не препятствуют потоку."},
  {id:340, q:"Испытание прямого потока обратного клапана подтверждает, что устройство может пропустить:", opts:["Нулевой поток","Обратный поток","Только 50 gpm","Полную потребность системы, включая любой запас на пожарный рукав"], re:"NFPA 25 (гл. 13) требует, чтобы испытание прямого потока продемонстрировало, что узел обратного клапана может обеспечить потребность системы (плюс запас на рукав, где он является частью потребности) без чрезмерной потери давления."},
  {id:341, q:"Когда измеряемое испытание прямого потока или испытание при полной потребности не может быть проведено, NFPA 25 допускает проведение испытания прямого потока путём:", opts:["Пропускания воды через основной дренаж системы или другое соединение при максимально достижимом расходе","Его пропуска","Закрытия клапана водоснабжения","Использования сжатого воздуха"], re:"NFPA 25 разрешает испытание прямого потока через основной дренаж системы или соединение, рассчитанное на пропуск потребности системы, когда измеряемое соединение недоступно, достигая максимально возможного потока."},
  {id:342, q:"Клапан основного дренажа, используемый для испытания, обычно расположен:", opts:["В самой высокой точке системы","На стояке системы, ниже по потоку от основного контрольного клапана","Только на соединении пожарной службы","На чердаке"], re:"Соединение основного дренажа находится на стояке ниже по потоку от основного контрольного клапана, чтобы испытание отражало водоснабжение через этот клапан; его открытие пропускает воду для оценки водоснабжения (NFPA 25, гл. 13)."},
  {id:343, q:"Перед закрытием основного дренажа в конце испытания клапан следует закрывать:", opts:["Как можно быстрее","Только наполовину","Медленно, чтобы избежать всплеска гидравлического удара","Никогда не закрывать"], re:"Медленное закрытие основного дренажа предотвращает гидравлический удар (всплеск давления), который может повредить трубопровод, манометры или фитинги; постепенная работа является стандартной безопасной практикой."},
  {id:344, q:"После испытания основного дренажа на сухотрубной системе или системе предварительного действия техник должен помнить о том, чтобы:", opts:["Оставить клапан открытым","Снять манометры","Слить антифриз","Восстановить систему в рабочее состояние (сбросить сухотрубный клапан, восстановить давление воздуха) и подтвердить готовность"], re:"На сухотрубных системах/системах предварительного действия испытание основного дренажа может вызвать срабатывание или частичную работу обвязки клапана; систему необходимо восстановить в её нормальное взведённое состояние и затем подтвердить её готовность к работе."},
  {id:345, q:"Результаты испытания основного дренажа наиболее полезны при сравнении с:", opts:["Данными первоначального приёмочного испытания и предыдущими ежегодными результатами","Соседним зданием","Манометром давления воздуха","Термометром"], re:"NFPA 25 подчёркивает отслеживание тенденций: сравнение текущих статических/остаточных показаний с приёмочными и предыдущими испытаниями выявляет постепенное ухудшение водоснабжения или ползущее закрытие клапана (гл. 13)."},
  {id:346, q:"Испытание прямого потока, которое не может достичь полной потребности системы, должно как минимум подтвердить:", opts:["Что труба красная","Что поток может быть установлен и устройство не засорено, с записью результатов","Что здание занято","Что насос выключен"], re:"Когда полная потребность недостижима, NFPA 25 всё равно требует установления потока для проверки того, что узел не заклинен/не засорён; достижимый поток и давления документируются для отслеживания тенденций."},
  {id:347, q:"Во время испытания основного дренажа ОТСУТСТВИЕ изменения или нормальное остаточное давление указывает на то, что:", opts:["Спринклеры сработали","Система отказала","Магистраль водоснабжения, вероятно, чиста и контрольный клапан открыт","Насос отказал"], re:"Остаточное давление, близкое к историческим значениям, указывает на то, что водоснабжение и контрольный клапан находятся в ожидаемом состоянии; значительное отклонение запускает расследование (NFPA 25, гл. 13)."},
  {id:348, q:"Сброс из основного дренажа во время испытания следует направлять в:", opts:["Электрощитовую","Спринклерные оросители","На крышу","Утверждённый дренаж или место, где он не вызовет повреждений"], re:"Сброс основного дренажа должен направляться в безопасную, утверждённую точку, чтобы большой поток не затопил занятое пространство и не повредил имущество; планирование пути сброса является частью процедуры испытания."},
  {id:349, q:"Испытание основного дренажа также проводится каждый раз, когда основной контрольный клапан был:", opts:["Закрыт и снова открыт (для проверки восстановления водоснабжения)","Покрашен","Осмотрен визуально","Маркирован"], re:"Каждый раз, когда основной контрольный клапан управляется/закрывается и снова открывается, испытание основного дренажа подтверждает, что полное водоснабжение восстановлено (клапан действительно полностью открыт), согласно практике NFPA 25."},
  {id:350, q:"Расход во время испытания прямого потока узла обратного клапана должен быть:", opts:["Минимально возможным потоком","Потребностью системы (расчётный расход, который узел должен пропустить)","Удвоенной потребностью системы","Нулевым"], re:"NFPA 25 (гл. 13) устанавливает расход испытания прямого потока на уровне потребности системы, чтобы испытание доказало, что обратный клапан не задушит расчётный расход при пожаре."},
  {id:351, q:"Обратный клапан устанавливается на спринклерном противопожарном вводе главным образом для того, чтобы:", opts:["Повысить давление","Фильтровать воду","Предотвратить обратный поток потенциально загрязнённой воды системы в питьевое водоснабжение","Измерять поток"], re:"Обратный клапан защищает общественную систему питьевой воды от перекрёстного загрязнения застоявшейся/обработанной спринклерной водой, текущей в обратном направлении; это устройство контроля перекрёстного соединения."},
  {id:352, q:"Согласно NFPA 25, как часто обратный клапан испытывается прямым потоком?", opts:["Ежеквартально","Раз в полгода","Каждые 5 лет","Ежегодно"], re:"NFPA 25 (гл. 13) требует ежегодного испытания прямого потока узлов предотвращения обратного потока при расходе, соответствующем потребности системы."},
  {id:353, q:"Внутренний осмотр обратных клапанов (check) и компонентов обратного клапана требуется согласно NFPA 25 каждые:", opts:["5 лет","2 года","Год","10 лет"], re:"NFPA 25 (гл. 13) требует внутреннего осмотра узлов обратного клапана каждые 5 лет для подтверждения того, что компоненты движутся свободно и сёдла/уплотнения находятся в хорошем состоянии (в соответствии с изготовителем/AHJ)."},
  {id:354, q:"В дополнение к испытанию прямого потока по NFPA 25 большинство юрисдикций требуют эксплуатационное испытание/испытание дифференциального давления узла обратного клапана сертифицированным испытателем обратных клапанов:", opts:["Никогда","Ежегодно","Только при установке","Каждые 10 лет"], re:"Программы контроля перекрёстных соединений (и правила Калифорнии/поставщика воды) обычно требуют ежегодного сертифицированного испытания обратного клапана дифференциального и обратных клапанов, отдельного от испытания прямого потока по NFPA 25."},
  {id:355, q:"Узел двойного обратного клапана (DCVA) обеспечивает защиту от обратного потока, используя:", opts:["Один обратный клапан","Только воздушный зазор (air gap)","Два независимо работающих обратных клапана, соединённых последовательно","Манометр давления"], re:"DCVA использует два подпружиненных обратных клапана, соединённых последовательно, с испытательными кранами и отсечными клапанами; он распространён там, где спринклерная вода не представляет опасности для здоровья (без добавок)."},
  {id:356, q:"Узел обратного клапана пониженного давления (RP/RPZ) обычно требуется, когда спринклерная система содержит:", opts:["Только чистую воду","Только воздух","Без воды","Антифриз, пену или другие добавки (перекрёстное соединение с опасностью для здоровья)"], re:"Там, где добавки, такие как антифриз или пена, создают опасность для здоровья, требуется узел принципа пониженного давления (со сбросным клапаном, выпускающим в атмосферу) для более высокой защиты."},
  {id:357, q:"Сбросной (выпускной) порт узла RPZ, выпускающий воду во время нормального режима ожидания, может указывать на:", opts:["Загрязнённый или протекающий обратный клапан, требующий обслуживания","Нормальный высокий поток","Всегда правильную работу","Что насос работает"], re:"Непрерывный сброс из сбросного клапана RPZ обычно сигнализирует о загрязнённых обратных клапанах или неисправном седле сбросного клапана и должен быть расследован; кратковременный сброс при колебании давления может быть нормальным."},
  {id:358, q:"Добавление обратного клапана к существующему спринклерному противопожарному вводу может снизить доступное давление, поэтому NFPA 13/25 требуют:", opts:["Игнорировать потерю","Учитывать потерю давления устройства в гидравлическом расчёте/проверке прямого потока","Удалить спринклеры","Всегда удваивать размер трубы"], re:"Узел обратного клапана добавляет потерю на трение; потребность системы всё равно должна удовлетворяться через него, что проверяют испытание прямого потока и гидравлические расчёты."},
  {id:359, q:"После внутреннего осмотра или ремонта обратного клапана узел должен быть:", opts:["Оставлен открытым для слива","Покрашен в красный цвет","Возвращён в эксплуатацию, и проведено испытание прямого потока/эксплуатационное испытание для подтверждения его функции","Удалён навсегда"], re:"После внутреннего осмотра или ремонта NFPA 25 требует, чтобы узел был возвращён в эксплуатацию и испытан (прямой поток плюс сертифицированное дифференциальное испытание) для подтверждения того, что он работает и пропускает расчётный расход."},
  {id:360, q:"Когда обратный клапан или PRV является единственным путём водоснабжения, ежеквартальное испытание основного дренажа в основном служит для того, чтобы:", opts:["Испытать спринклеры","Наполнить бак","Осушить систему","Проработать устройство и подтвердить, что оно не препятствует водоснабжению"], re:"Ежеквартальное испытание основного дренажа на системе, питаемой исключительно через обратный клапан/PRV, прорабатывает эти компоненты и проверяет, что они не заклинены или не загрязнены, удушая водоснабжение (NFPA 25, гл. 13)."},
  {id:361, q:"Отсечные клапаны узла обратного клапана обычно должны быть:", opts:["Контролируемыми (заперты/опломбированы или контролируются электрически), чтобы их не оставляли закрытыми","Неконтролируемыми и свободными для закрытия","Удалены","Заварены закрытыми"], re:"Поскольку закрытый отсечной клапан обратного клапана отключает всю систему, эти клапаны должны контролироваться теми же средствами, что и другие контрольные клапаны (требования к контрольным клапанам NFPA 25, гл. 13)."},
  {id:362, q:"Испытание прямого потока через обратный клапан документируется с какими ключевыми данными?", opts:["Только датой","Достигнутым расходом и давлениями на входе/выходе (и потерей давления на устройстве)","Цветом трубы","Обеденным перерывом техника"], re:"Запись испытания прямого потока должна фиксировать достигнутый поток и давления, чтобы потерю на устройстве и способность удовлетворить потребность можно было отслеживать с течением времени (NFPA 25, гл. 13)."},
  {id:363, q:"Узел обратного клапана, не прошедший сертифицированное испытание дифференциального давления, должен быть:", opts:["Проигнорирован до следующего года","Покрашен","Отремонтирован или заменён и повторно испытан перед тем, как на него полагаться","Оставлен в эксплуатации"], re:"Непройденное испытание обратного клапана означает, что устройство не обеспечивает защиту или может ограничивать поток; его необходимо отремонтировать/заменить и повторно испытать, прежде чем система будет считаться защищённой."},
  {id:364, q:"Расположение узла RPZ так, чтобы его сбросной выпуск дренировался надлежащим образом, важно, потому что узел:", opts:["Никогда не сбрасывает","Сбрасывает только воздух","Загерметизирован","Может сбросить значительное количество воды и должен дренироваться в утверждённую точку без затопления"], re:"RPZ может выбросить большой объём из сбросного порта при отказе обратного клапана или всплеске; достаточный воздушный зазор и напольный трап предотвращают затопление и противодавление на сбросной клапан."},
  {id:365, q:"Испытательные краны узла обратного клапана используются для того, чтобы:", opts:["Подключать испытательные манометры для проверки обратных клапанов и дифференциала сбросного клапана","Осушить здание","Добавить антифриз","Выпустить воздух из спринклеров"], re:"Испытательные краны — это точки подключения манометров, которые сертифицированный испытатель использует для измерения дифференциала на каждом обратном клапане и точки открытия сбросного клапана во время ежегодного эксплуатационного испытания."},
  {id:366, q:"По сравнению с DCVA узел RPZ обычно вызывает:", opts:["Отсутствие потери давления","Большую потерю давления, которую необходимо учитывать в потребности системы","Отрицательную потерю давления","Повышение давления"], re:"Сбросной механизм и дополнительные внутренние компоненты RPZ обычно создают большую потерю на трение, чем DCVA; эта дополнительная потеря должна учитываться, чтобы система всё равно удовлетворяла потребность."},
  {id:367, q:"Испытание сигнализации потока воды на мокротрубной системе проводится путём открытия:", opts:["Основного контрольного клапана","Соединения пожарной службы","Испытательного соединения инспектора","Контура антифриза"], re:"Испытательное соединение инспектора имеет отверстие, эквивалентное одному спринклеру; его открытие пропускает воду для приведения в действие сигнализации потока воды, имитируя работу одного спринклера (NFPA 25, гл. 5)."},
  {id:368, q:"После открытия испытательного соединения инспектора сигнализация потока воды должна сработать в течение максимум:", opts:["10 секунд","30 секунд","5 минут","90 секунд"], re:"NFPA 13/25 требуют, чтобы сигнализация потока воды срабатывала в течение 90 секунд при потоке, равном одному спринклеру, на испытательном соединении инспектора."},
  {id:369, q:"Отверстие испытательного соединения инспектора рассчитано на сброс эквивалента:", opts:["Одного спринклера (наименьшее отверстие в системе)","Пожарного рукава 2,5 дюйма","Всей системы сразу","Без потока"], re:"NFPA 13 требует, чтобы испытательное соединение инспектора имело отверстие, эквивалентное наименьшему спринклеру в системе, чтобы испытание сигнализации имитировало работу одного спринклера."},
  {id:370, q:"Лопастной переключатель потока воды (vane) НЕ допускается на какой системе, потому что поток срабатывания может сломать лопасть?", opts:["Мокротрубной","Сухотрубной","Мокротрубной сетчатой (gridded)","Мокротрубной кольцевой (looped)"], re:"NFPA 13/25 запрещают лопастные устройства потока воды на сухотрубных системах; всплеск при срабатывании сухотрубного клапана может срезать лопасть и отправить её в трубопровод. Вместо них используются переключатели давления."},
  {id:371, q:"Устройства сигнализации потока воды типа реле давления и лопастного типа (vane) функционально испытываются согласно NFPA 25 с какой минимальной периодичностью?", opts:["Ежеквартально","Ежегодно","Раз в полгода","Каждые 5 лет"], re:"NFPA 25 (гл. 5) требует, чтобы устройства сигнализации потока воды лопастного типа и типа реле давления испытывались раз в полгода, тогда как механические водяные гонги испытываются ежеквартально."},
  {id:372, q:"На сухотрубной системе открытие испытательного соединения инспектора для испытания сигнализации:", opts:["Ничего не сделает","Закроет основной клапан","Добавит антифриз","Снизит давление воздуха и вызовет срабатывание сухотрубного клапана, подавая воду (частичное/полное испытание срабатывания)"], re:"Поскольку сухие системы удерживают воздух, пропускание воды через испытательное соединение инспектора стравливает воздух и может вызвать срабатывание сухотрубного клапана; испытание сигнализации/срабатывания на сухих системах должно планироваться во избежание непреднамеренного полного срабатывания, когда предполагается только испытание сигнализации."},
  {id:373, q:"Контрольное устройство на спринклерной системе отслеживает такие условия, как:", opts:["Положение контрольного клапана, низкое давление воздуха или низкую температуру","Комнатную температуру для комфорта","Уровни освещения","Дверные замки"], re:"Контрольные сигналы указывают на ненормальные условия (закрытый клапан, низкое/высокое давление воздуха, низкая температура здания/корпуса, низкий уровень воды), которые могут нарушить работу системы (NFPA 25/72)."},
  {id:374, q:"Контрольные сигнализации низкого давления воздуха на сухотрубных системах/системах предварительного действия испытываются согласно NFPA 25:", opts:["Никогда","Ежегодно (или согласно изготовителю)","Каждые 10 лет","Только при приёмке"], re:"NFPA 25 (гл. 5/13) требует, чтобы устройства контрольного сигнала низкого давления воздуха (а также низкой температуры, низкого уровня воды) испытывались не реже одного раза в год или в соответствии с инструкциями изготовителя."},
  {id:375, q:"Когда сигнализация потока воды связана с панелью управления пожарной сигнализацией, передача сигнала тревоги на панель проверяется согласно какому сопутствующему стандарту?", opts:["Только NFPA 13","NFPA 10","NFPA 72","NFPA 30"], re:"NFPA 72 (Национальный кодекс пожарной сигнализации и оповещения) регулирует цепь инициирующего устройства и проверку сигнала, когда устройства потока воды/контроля спринклеров подключаются к системе пожарной сигнализации."},
  {id:376, q:"Камера задержки (retard chamber), установленная перед реле давления потока воды мокротрубной системы, используется для того, чтобы:", opts:["Повысить давление","Осушить систему","Фильтровать воду","Поглощать кратковременные всплески/колебания давления для предотвращения ложных тревог"], re:"Камера задержки задерживает срабатывание сигнализации при кратковременных всплесках (например, гидравлическом ударе), чтобы только устойчивый поток вызывал сигнализацию, уменьшая ложные тревоги; она всё равно должна позволять сигнализацию в течение 90 секунд при реальном потоке."},
  {id:377, q:"Во время испытания сигнализации потока воды техник должен сначала уведомить:", opts:["Станцию мониторинга/обитателей, чтобы сигнализация не была принята за реальный пожар","Мойщика окон","Отдел выставления счетов водоканала","Кровельного подрядчика"], re:"Поскольку испытание приводит в действие реальные сигналы тревоги, центральная станция мониторинга и обитатели здания должны быть уведомлены заранее, а система переведена в режим испытания во избежание ложного вызова (практика NFPA 25/72)."},
  {id:378, q:"Водяной гонг (механическая сигнализация) приводится в действие:", opts:["Электродвигателем","Потоком воды через небольшой водяной двигатель, который ударяет в гонг","Сжатым воздухом","Пружинным механизмом"], re:"Водяной гонг использует небольшой водяной двигатель типа Пелтона, приводимый в действие потоком по сигнальной линии, для механического удара в гонг; он не требует электричества и испытывается ежеквартально (NFPA 25, гл. 5)."},
  {id:379, q:"Инициирующие устройства потока воды и контрольные устройства осматриваются (визуально, на физические повреждения) с какой периодичностью согласно NFPA 25?", opts:["Ежедневно","Каждые 3 года","Ежеквартально","Каждые 5 лет"], re:"NFPA 25 (гл. 5) требует ежеквартального осмотра инициирующих устройств сигнала потока воды и контрольных устройств для подтверждения того, что они свободны от физических повреждений, в дополнение к функциональному испытанию."},
  {id:380, q:"После завершения испытания сигнализации/потока воды техник должен подтвердить, что:", opts:["Сигнализация оставлена звенящей","Манометры сняты","Клапан оставлен закрытым","Все устройства сброшены, система возвращена в эксплуатацию, и мониторинг снят с режима испытания"], re:"Восстановление эксплуатации означает проверку того, что устройства сброшены, клапаны открыты и контролируются, давления воздуха/воды нормальны, а станция мониторинга снята с режима испытания и снова включена."},
  {id:381, q:"Переключатель потока воды типа давления работает, ощущая:", opts:["Повышение давления в сигнальной/системной линии, вызванное потоком","Отклонение лопасти","Температуру","Дым"], re:"Переключатель потока воды, приводимый в действие давлением, замыкает свои контакты, когда давление в сигнальной линии повышается из-за потока; в отличие от лопастного переключателя у него нет подвижной лопасти в водяном тракте, поэтому он подходит для сухих систем."},
  {id:382, q:"Если сигнализация потока воды не срабатывает в течение 90 секунд во время испытания, техник должен:", opts:["Всё равно её принять","Расследовать и устранить причину (например, препятствие, неисправный переключатель, закрытый клапан сигнализации)","Удалить устройство","Подождать неделю"], re:"Несрабатывание сигнализации в течение требуемого времени является дефектом; причина (заблокированный порт сигнализации, заклинившая камера задержки, неисправный переключатель или закрытый клапан сигнализации) должна быть найдена и устранена, а устройство повторно испытано."},
  {id:383, q:"Испытательное соединение инспектора обычно расположено:", opts:["На основном клапане","В насосной пожарного насоса","В гидравлически самой удалённой точке системы","На FDC"], re:"Испытательное соединение инспектора размещается в самой удалённой точке или рядом с ней, чтобы его поток, эквивалентный одному спринклеру, представлял наихудший случай для приведения в действие сигнализации и проверки пути потока (NFPA 13)."},
  {id:384, q:"В терминах NFPA 25 «нарушение/деградация» (impairment) — это состояние, при котором:", opts:["Спринклер запылён","Манометр показывает слегка отклонённое значение","Краска выцвела","Система противопожарной защиты на водной основе (или её часть) вышла из строя/не способна функционировать, как предусмотрено"], re:"NFPA 25 (гл. 15) определяет нарушение как состояние, при котором система противопожарной защиты или её часть вышла из строя, что приводит к тому, что система не функционирует при возникновении пожара."},
  {id:385, q:"Плановое отключение спринклерной системы для запланированных работ классифицируется как:", opts:["Запланированное нарушение","Аварийное нарушение","Постоянное отключение","Приёмочное испытание"], re:"NFPA 25 (гл. 15) различает запланированные нарушения (плановые, например, для обслуживания/модификации) от аварийных нарушений (непредвиденные, например, разрыв или повреждение пожаром)."},
  {id:386, q:"Согласно NFPA 25, лицо, ответственное за управление нарушением, — это:", opts:["Мойщик окон","Координатор нарушений","Архитектор","Арендатор"], re:"NFPA 25 (гл. 15) требует, чтобы владелец назначил координатора нарушений, который контролирует шаги до, во время и при восстановлении любого нарушения."},
  {id:387, q:"Разрыв или случайное отключение, которое неожиданно выводит систему из эксплуатации, является:", opts:["Запланированным нарушением","5-летним исследованием препятствий","Аварийным нарушением","Испытанием прямого потока"], re:"NFPA 25 (гл. 15) классифицирует непредвиденные потери защиты (разрыв трубы, замёрзшая/лопнувшая труба, обнаруженный закрытым клапан, повреждение пожаром/водой) как аварийные нарушения, требующие немедленных действий."},
  {id:388, q:"Когда система нарушена, NFPA 25 требует размещения бирки, указывающей на нарушение:", opts:["Только в офисном файле","На каждом спринклере","На крыше","На каждом соединении пожарной службы и контрольном клапане системы (и в других точках, назначенных AHJ)"], re:"NFPA 25 (гл. 15) требует размещения бирки нарушения на каждом FDC, основном контрольном клапане и в других точках, назначенных AHJ, чтобы аварийные службы и персонал знали, что система выведена из эксплуатации."},
  {id:389, q:"Перед началом запланированного нарушения координатор нарушений должен определить масштаб и ожидаемую продолжительность и:", opts:["Осмотреть затронутые зоны на предмет повышенного риска и уведомить пожарную службу, компанию сигнализации и обитателей","Больше ничего не делать","Отключить электричество","Удалить спринклеры"], re:"NFPA 25 (гл. 15) перечисляет шаги до нарушения: оценить масштаб/продолжительность, осмотреть на предмет повышенных опасностей, уведомить пожарную службу/мониторинг сигнализации/страховщика/обитателей и подготовиться к смягчению (например, пожарный надзор)."},
  {id:390, q:"NFPA 25 требует смягчения, такого как пожарный надзор (fire watch), когда нарушение системы на водной основе превышает какую продолжительность в течение 24-часового периода?", opts:["1 час","10 часов","4 часа","48 часов"], re:"NFPA 25 (гл. 15) требует эвакуации или утверждённого пожарного надзора (или временной защиты), когда система на водной основе нарушена более 10 часов в течение любого 24-часового периода."},
  {id:391, q:"Пожарный надзор (fire watch), осуществляемый во время нарушения, состоит из:", opts:["Автоматической камеры","Запертой двери","Обученного персонала, патрулирующего затронутую зону для обнаружения пожара и уведомления пожарной службы","Дополнительного спринклера"], re:"Пожарный надзор — это один или несколько обученных человек, непрерывно патрулирующих нарушенную зону, оснащённых для вызова пожарной службы и оповещения/эвакуации обитателей при обнаружении пожара (NFPA 25, гл. 15)."},
  {id:392, q:"Когда нарушенная система восстановлена, координатор нарушений должен проверить, перед снятием бирки, что:", opts:["Бирка заламинирована","Здание перекрашено","Свет включён","Необходимые осмотры/испытания были проведены и система полностью работоспособна"], re:"NFPA 25 (гл. 15) требует подтверждения того, что водоснабжение восстановлено (испытание основного дренажа), утечек нет и все клапаны открыты/контролируются; только тогда бирка нарушения снимается и заинтересованные стороны уведомляются."},
  {id:393, q:"Восстановление спринклерной системы в эксплуатацию после нарушения должно включать испытание основного дренажа для подтверждения:", opts:["Что водоснабжение полностью восстановлено (контрольный клапан полностью открыт)","Концентрации антифриза","Цвета краски","Марки манометра"], re:"Испытание основного дренажа после восстановления проверяет, что контрольный клапан полностью открыт и доступно полное водоснабжение; низкое остаточное давление выявило бы клапан, оставленный частично закрытым (NFPA 25, гл. 13/15)."},
  {id:394, q:"Исследование препятствий согласно NFPA 25 запускается при обнаружении таких условий, как какие?", opts:["Чистый, незасорённый трубопровод","Инородный материал, бугорчатая коррозия, отложения или признаки MIC в трубопроводе","Свежая краска","Новый манометр"], re:"NFPA 25 (гл. 14) перечисляет условия (засорённые спринклеры, инородные вещества в дренаже, бугорки, MIC, необычный цвет/запах), которые требуют исследования препятствий для обнаружения и удаления блокировки."},
  {id:395, q:"MIC, проблема коррозии, которая может засорить спринклерный трубопровод, означает:", opts:["Кодекс механического осмотра","Максимальная пропускная способность притока","Микробиологически индуцированная коррозия","Основное входное соединение"], re:"Микробиологически индуцированная коррозия (MIC) — это коррозия, вызванная бактериями, которая образует узелки/бугорки и точечные утечки, ограничивая поток; её обнаружение запускает исследование препятствий согласно NFPA 25, гл. 14."},
  {id:396, q:"5-летний внутренний осмотр трубы на наличие препятствий обычно проводится путём:", opts:["Прослушивания трубы","Добавления антифриза","Покраски трубы","Открытия промывочного соединения и снятия спринклера около конца ответвления для осмотра изнутри"], re:"NFPA 25 (гл. 14) указывает осматривать внутреннюю часть в репрезентативных точках (например, промывочное соединение поперечной магистрали и снятый спринклер с конца ответвления) на наличие инородного материала, бугорчатой коррозии или MIC."},
  {id:397, q:"Если исследование препятствий обнаруживает материал в трубопроводе, требуемое корректирующее действие — это:", opts:["Промыть/очистить систему для удаления препятствия и определить/устранить источник","Игнорировать его","Закрасить его","Повысить давление воздуха"], re:"NFPA 25 (гл. 14) требует, чтобы система была промыта/очищена для удаления препятствующего материала, а источник (например, мусор из магистрали, MIC) был выявлен и устранён для предотвращения повторного возникновения."},
  {id:398, q:"Во время аварийного нарушения координатор нарушений должен реализовать смягчение и:", opts:["Подождать до следующего рабочего дня","Принять немедленные корректирующие меры и уведомить пожарную службу, обитателей и другие затронутые стороны","Удалить все указатели","Отключить сигнализации"], re:"NFPA 25 (гл. 15) требует, чтобы аварийные нарушения устранялись немедленно, с быстрыми корректирующими шагами и уведомлением пожарной службы, обитателей, компании сигнализации и других, плюс пожарный надзор при необходимости."},
  {id:399, q:"Записи о нарушении (время начала, причина, смягчение, восстановление) должны быть:", opts:["Немедленно уничтожены","Опубликованы публично онлайн","Задокументированы и сохранены как часть записей системы","Сохранены только устно"], re:"NFPA 25 (гл. 4/15) требует, чтобы нарушения документировались (даты, объём, смягчение, подтверждение восстановления) и сохранялись с записями системы для AHJ и для отслеживания тенденций."},
  {id:400, q:"После завершения 5-летнего внутреннего осмотра на наличие препятствий, при котором препятствие не обнаружено, техник должен:", opts:["Всё равно начать полное исследование препятствий","Слить антифриз навсегда","Оставить трубу открытой","Задокументировать результаты осмотра и восстановить систему в эксплуатацию"], re:"Если 5-летний внутренний осмотр обнаруживает незасорённый трубопровод, исследование препятствий не запускается; результаты документируются, и система восстанавливается в нормальную эксплуатацию (NFPA 25, гл. 14)."},
  {id:401, q:"В Калифорнии какая часть Title 24 является Пожарным кодексом Калифорнии (CFC)?", opts:["Часть 6","Часть 2","Часть 9","Часть 11"], re:"Пожарный кодекс Калифорнии — это Title 24, Часть 9 Свода нормативов Калифорнии. Строительный кодекс Калифорнии — это Часть 2. Источник: California Building Standards Code / DGS BSC, CFC 2022, Title 24 Часть 9."},
  {id:402, q:"На каком типовом кодексе основан Пожарный кодекс Калифорнии, дополненный поправками, специфичными для Калифорнии?", opts:["International Fire Code (IFC)","Uniform Plumbing Code","International Residential Code","National Electrical Code"], re:"CFC формируется на основе International Fire Code с необходимыми поправками Калифорнии. Источник: California Fire Code 2022, Title 24 Часть 9, Предисловие."},
  {id:403, q:"Какой раздел Свода нормативов Калифорнии содержит правила State Fire Marshal по обслуживанию, испытанию и техническому обслуживанию автоматических систем пожаротушения (спринклеров)?", opts:["Title 8","Title 16","Title 19","Title 22"], re:"CCR Title 19 (Общественная безопасность) содержит правила State Fire Marshal по обслуживанию, испытанию и техническому обслуживанию автоматических систем пожаротушения. Источник: CCR Title 19, Раздел 1; Кодекс H&S 13195."},
  {id:404, q:"Какой стандарт NFPA принимает по ссылке CCR Title 19 для инспекции, испытания и технического обслуживания водяных систем противопожарной защиты?", opts:["NFPA 13","NFPA 14","NFPA 72","NFPA 25"], re:"CCR Title 19, Секция 904 включает по ссылке NFPA 25 (стандарт ITM для водяных систем противопожарной защиты). Источник: CCR Title 19 §904; NFPA 25."},
  {id:405, q:"Какой стандарт NFPA является основным справочником для проектирования и монтажа автоматических спринклерных систем, принятым Пожарным кодексом Калифорнии?", opts:["NFPA 20","NFPA 13","NFPA 24","NFPA 291"], re:"NFPA 13, Стандарт на монтаж спринклерных систем, является основным справочником по проектированию/монтажу, принятым CFC (Глава 9). Источник: California Fire Code Глава 9 / Глава 80; NFPA 13."},
  {id:406, q:"Согласно Секции 903 Пожарного кодекса Калифорнии, автоматическая спринклерная система обычно требуется по всей пожарной зоне группы A-1, где пожарная зона превышает:", opts:["5,000 кв. футов","8,000 кв. футов","12,000 кв. футов","20,000 кв. футов"], re:"CFC §903.2.1.1 требует спринклеры для группы A-1, где пожарная зона превышает 12,000 кв. футов (среди прочих условий, таких как загрузка людьми). Источник: California Fire Code §903.2.1."},
  {id:407, q:"В Калифорнии агентство, которое принимает правила State Fire Marshal в CCR Title 19, входит в состав какого департамента?", opts:["Cal/OSHA","Division of the State Architect","Department of Consumer Affairs","Office of the State Fire Marshal (CAL FIRE)"], re:"Office of the State Fire Marshal в составе CAL FIRE принимает правила пожарной профилактики Title 19. Источник: Office of the State Fire Marshal; CCR Title 19."},
  {id:408, q:"Какой проектный документ подрядчик по спринклерам обычно должен подготовить и подать на экспертизу проекта перед монтажом спринклерной системы пожаротушения?", opts:["Рабочие чертежи (монтажные чертежи) и гидравлические расчёты","Только расчёт нагрузки","Однолинейную электрическую схему","План вертикальной планировки участка"], re:"NFPA 13 и CFC требуют, чтобы рабочие чертежи (монтажные чертежи) плюс гидравлические расчёты были поданы в уполномоченный орган на экспертизу перед монтажом. Источник: глава о чертежах/расчётах NFPA 13; CFC §901.2."},
  {id:409, q:"Орган в юрисдикции, обладающий законными полномочиями утверждать проекты спринклеров и проводить инспекцию монтажа, в кодексах называется:", opts:["Генеральный подрядчик","Зарегистрированный проектировщик","Сертифицирующая лаборатория","Уполномоченный орган (AHJ)"], re:"«Уполномоченный орган» (AHJ) — это термин кодексов для офиса/лица, ответственного за утверждение оборудования, монтажа и процедур. Источник: определения NFPA 13; California Fire Code Глава 2."},
  {id:410, q:"Какой документ является источником законных полномочий State Fire Marshal над обслуживанием и испытанием автоматических систем пожаротушения?", opts:["Кодекс о транспортных средствах","Кодекс о бизнесе и профессиях","Кодекс о здоровье и безопасности Калифорнии","Уголовный кодекс"], re:"Кодекс о здоровье и безопасности Калифорнии §13195 предписывает State Fire Marshal принять правила Title 19, регулирующие обслуживание и испытание автоматических систем пожаротушения. Источник: Кодекс H&S §13195."},
  {id:411, q:"Согласно CCR Title 19, стандартные таблички/формы, используемые для документирования инспекции автоматических систем пожаротушения, разрабатываются:", opts:["Местным водоканалом","Страховой компанией","Производителем труб","Office of the State Fire Marshal (формы AES)"], re:"CCR Title 19 предписывает использование форм AES (Automatic Extinguishing Systems) Office of the State Fire Marshal для документирования инспекции/испытания. Источник: CCR Title 19 §906.4."},
  {id:412, q:"Когда местная юрисдикция принимает Пожарный кодекс Калифорнии, она может:", opts:["Удалить все требования к спринклерам","Упразднить AHJ","Полностью игнорировать State Fire Marshal","Принять более строгие местные поправки на основе местных условий"], re:"Местные юрисдикции могут принимать поправки строже, чем типовой кодекс штата, на основе местных климатических, геологических или топографических условий. Источник: California Health & Safety Code §17958.7; процесс принятия California Fire Code."},
  {id:413, q:"Какая часть California Building Standards Code содержит общие требования к строительству по пожарной безопасности и безопасности жизни (например, тип занятости и тип конструкции), на которые ссылаются вместе с Пожарным кодексом?", opts:["Часть 9 (Пожарный кодекс)","Часть 4 (Механический кодекс)","Часть 2 (Строительный кодекс)","Часть 5 (Сантехнический кодекс)"], re:"Строительный кодекс Калифорнии — это Title 24, Часть 2, содержащий классификацию занятости и требования к типу конструкции, на которые ссылается Пожарный кодекс. Источник: California Building Standards Code, Title 24, Часть 2."},
  {id:414, q:"Полный комплект проекта спринклеров пожаротушения для экспертизы AHJ обычно должен включать всё перечисленное, КРОМЕ:", opts:["Гидравлических расчётов","Личной налоговой декларации подрядчика","Технических листов/сертификатов оборудования","Основы водоснабжения (испытания расхода)"], re:"Рабочие чертежи, гидравлические расчёты, основа водоснабжения и данные сертифицированного оборудования требуются для экспертизы; налоговая декларация подрядчика не входит в комплект проекта спринклеров. Источник: глава о чертежах/расчётах NFPA 13; CFC §901.2."},
  {id:415, q:"С какой общей периодичностью обновляется Пожарный кодекс Калифорнии в рамках процесса принятия кодекса Title 24?", opts:["Каждые 6 месяцев","Каждые 3 года (трёхлетний цикл)","Каждые 10 лет","Только при землетрясении"], re:"California Building Standards (Title 24), включая Пожарный кодекс, принимаются по трёхлетнему циклу (3 года). Источник: California Building Standards Commission / DGS BSC, цикл принятия кодекса."},
  {id:416, q:"NFPA 25, принятый CCR Title 19, в основном регулирует:", opts:["Инспекцию, испытание и техническое обслуживание установленных водяных систем","Проектирование новых спринклерных систем","Производство спринклерных оросителей","Прокладку пожарной сигнализации"], re:"NFPA 25 — это Стандарт на инспекцию, испытание и техническое обслуживание водяных систем противопожарной защиты; проектирование новых систем регулируется NFPA 13. Источник: область применения NFPA 25; CCR Title 19 §904."},
  {id:417, q:"Когда Пожарный кодекс Калифорнии и принятый стандарт NFPA расходятся, монтажник должен:", opts:["Всегда игнорировать стандарт NFPA","Использовать то, что дешевле","Усреднить два значения","Следовать более строгому требованию, согласовав с AHJ"], re:"Когда принимающий кодекс (CFC) и упомянутый стандарт расходятся, обычно действует более строгое положение, при условии указаний AHJ. Источник: California Fire Code Глава 1 (администрирование); полномочия AHJ."},
  {id:418, q:"Классификации пожарной опасности по занятости в NFPA 13 основаны главным образом на:", opts:["Количестве и горючести содержимого","Числе людей в здании","Высоте здания","Возрасте конструкции"], re:"NFPA 13 классифицирует пожарную опасность по занятости исходя из количества и горючести содержимого (и ожидаемого тепловыделения), в отличие от кодексов безопасности жизни, ориентированных на потребности людей. Источник: NFPA 13 Глава 4, Классификация занятости."},
  {id:419, q:"Занятость, где количество и горючесть содержимого низкие и ожидается, что пожары будут иметь относительно низкую скорость тепловыделения, классифицируется как:", opts:["Обычная опасность Группа 2","Лёгкая опасность","Повышенная опасность Группа 1","Повышенная опасность Группа 2"], re:"Занятости лёгкой опасности имеют низкое количество и горючесть содержимого и низкую ожидаемую скорость тепловыделения. Источник: определение лёгкой опасности NFPA 13 (Глава 4)."},
  {id:420, q:"Типичное офисное здание, церковь или школьный класс обычно классифицируются по NFPA 13 как какая пожарная опасность по занятости?", opts:["Повышенная опасность Группа 1","Обычная опасность Группа 1","Лёгкая опасность","Складирование"], re:"Офисы, церкви, школы и подобные занятости перечислены как лёгкая опасность в NFPA 13. Источник: примеры лёгкой опасности Приложения/Главы 4 NFPA 13."},
  {id:421, q:"NFPA 13 делит занятости обычной опасности на:", opts:["Только один класс","Только высокую и низкую","Группы от A до D","Группу 1 и Группу 2"], re:"Обычная опасность делится на Группу 1 и Группу 2, где Группа 2 представляет большее количество и горючесть содержимого. Источник: NFPA 13 Глава 4, обычная опасность."},
  {id:422, q:"В обычной опасности Группы 1 высота штабеля (складирования) содержимого обычно ограничена максимумом около:", opts:["8 футов","4 футов","16 футов","20 футов"], re:"Обычная опасность Группа 1 включает ограничение высоты штабеля около 8 футов (2.4 м). Источник: определение обычной опасности Группы 1 NFPA 13."},
  {id:423, q:"В обычной опасности Группы 2 высота штабеля для умеренно горючего содержимого может достигать примерно:", opts:["8 футов","12 футов","10 футов","30 футов"], re:"Обычная опасность Группа 2 допускает более высокий штабель, до примерно 12 футов (3.7 м) при той же горючести, что отражает большее количество, чем в Группе 1. Источник: определение обычной опасности Группы 2 NFPA 13."},
  {id:424, q:"Занятость с очень большим количеством горючих материалов, включая зоны, где присутствует пыль или ворс и могут происходить быстро распространяющиеся пожары, классифицируется как:", opts:["Повышенная опасность Группа 1","Обычная опасность Группа 1","Лёгкая опасность","Лёгкая опасность, малое помещение"], re:"Повышенная опасность Группа 1 охватывает помещения с очень большим количеством горючих материалов и потенциалом быстро распространяющегося пожара, такие как зоны с пылью или ворсом, но с малым количеством или отсутствием легковоспламеняющихся/горючих жидкостей. Источник: определение повышенной опасности Группы 1 NFPA 13."},
  {id:425, q:"Занятость, содержащая значительные количества легковоспламеняющихся или горючих жидкостей либо обширное экранирование горючих материалов, классифицируется как:", opts:["Лёгкая опасность","Повышенная опасность Группа 2","Обычная опасность Группа 2","Обычная опасность Группа 1"], re:"Повышенная опасность Группа 2 — это высший класс занятости с распылением, включающий значительные легковоспламеняющиеся/горючие жидкости и обширное экранирование горючих материалов. Источник: определение повышенной опасности Группы 2 NFPA 13."},
  {id:426, q:"Какая из следующих занятостей наиболее вероятно была бы классифицирована как обычная опасность Группа 2?", opts:["Механический цех или зона металлообработки","Читальный зал библиотеки","Палата пациента в больнице","Гостевой номер отеля"], re:"Механические цеха/металлообработка перечислены как примеры обычной опасности Группы 2; библиотеки (читальные залы), больничные палаты и номера отелей относятся к лёгкой опасности. Источник: примеры занятости Приложения NFPA 13."},
  {id:427, q:"Классификации товаров (commodities) NFPA 13 для складирования обозначаются как:", opts:["Класс от A до F","Сорт от A до D","Тип от 1 до 5","Класс с I по IV (плюс группы пластиков)"], re:"Складские товары классифицируются с Класса I по Класс IV (с отдельными группами пластиков/эластомеров), причём Класс IV представляет наибольшую опасность из четырёх пронумерованных классов. Источник: глава классификации товаров NFPA 13."},
  {id:428, q:"Из пронумерованных классов складских товаров какой представляет наибольшую пожарную опасность?", opts:["Класс I","Класс II","Класс III","Класс IV"], re:"Класс IV содержит более высокие уровни пластиков/горючих материалов, чем Класс III, и представляет наибольшую опасность из пронумерованных (без группы пластиков) классов. Источник: глава классификации товаров NFPA 13."},
  {id:429, q:"Товар Класса I в NFPA 13 лучше всего описывается как:", opts:["Свободнотекущие легковоспламеняющиеся жидкости","По существу негорючие продукты на горючих поддонах или в обычных картонных коробках","Открытые невспененные пластики","Аэрозоли, Уровень 3"], re:"Товары Класса I — это по существу негорючие продукты, которые могут храниться на деревянных поддонах или в однослойных гофрированных коробках. Источник: классификация товаров NFPA 13, Класс I."},
  {id:430, q:"Почему правильная классификация пожарной опасности по занятости критична для проектирования спринклеров?", opts:["Она задаёт цвет окраски труб","Она выбирает размер звонка сигнализации","Она определяет проектную плотность, проектную площадь и потребность в воде","Она не влияет на гидравлику"], re:"Классификация опасности определяет проектную плотность (галлонов/мин на кв. фут), проектную площадь и в конечном счёте потребность системы в воде. Неправильная классификация может оставить систему недопроектированной. Источник: подходы к проектированию NFPA 13; метод плотности/площади."},
  {id:431, q:"Типографское предприятие, использующее большие количества горючих красок и растворителей, наиболее вероятно было бы классифицировано как:", opts:["Повышенная опасность","Лёгкая опасность","Только обычная опасность Группа 1","Всегда лёгкая опасность"], re:"Технологические зоны с большими количествами легковоспламеняющихся/горючих жидкостей, таких как краски и растворители, относятся к повышенной опасности. Источник: примеры повышенной опасности NFPA 13 (печать, малярные цеха, использование растворителей)."},
  {id:432, q:"Когда занятость содержит складирование выше высот/количеств, охватываемых критериями распыления обычной или повышенной опасности, проектирование обычно переходит к:", opts:["Критериям проектирования защиты складирования","Критериям лёгкой опасности","Спринклеры не требуются","Жилым критериям"], re:"Высокостеллажное и насыпное складирование сверх пределов занятости с распылением проектируется с использованием критериев защиты складирования NFPA 13 (товар, высота складирования, расположение). Источник: главы складирования NFPA 13."},
  {id:433, q:"По сравнению с лёгкой опасностью занятости обычной и повышенной опасности обычно требуют:", opts:["Более высокой плотности воды и уменьшенной максимальной защищаемой площади на спринклер","Более низкой плотности воды и большего расстояния между спринклерами","Без изменений в проекте","Меньшего числа спринклеров"], re:"Классы более высокой опасности требуют большей проектной плотности и меньшей максимальной защищаемой площади на спринклер (больше спринклеров, более плотное расстояние). Источник: таблицы расстояний/покрытия и плотности NFPA 13."},
  {id:434, q:"Жилое помещение, защищённое по стандартам жилых спринклеров, наиболее связано с какой проектной группой?", opts:["Повышенная опасность Группа 2","Критерии складирования","Жилые критерии NFPA 13D/13R (упор на безопасность жизни)","Обычная опасность Группа 2"], re:"Жилые помещения обычно защищаются по NFPA 13D (одно- и двухсемейные) или 13R (жилые до четырёх этажей), которые ориентированы на безопасность жизни с жилыми спринклерами. Источник: область применения NFPA 13D / 13R."},
  {id:435, q:"Для стандартных спринклеров распыления (spray) в занятости лёгкой опасности максимальная защищаемая площадь на спринклер обычно составляет:", opts:["100 кв. футов","130 кв. футов","200 кв. футов","225 кв. футов"], re:"Стандартные спринклеры распыления лёгкой опасности имеют максимальную защищаемую площадь 225 кв. футов на спринклер. Источник: таблица защищаемой площади покрытия NFPA 13 (лёгкая опасность)."},
  {id:436, q:"Для стандартных спринклеров распыления в занятости обычной опасности максимальная защищаемая площадь на спринклер обычно составляет:", opts:["225 кв. футов","130 кв. футов","90 кв. футов","400 кв. футов"], re:"Стандартные спринклеры распыления обычной опасности имеют максимальную защищаемую площадь 130 кв. футов на спринклер. Источник: таблица защищаемой площади покрытия NFPA 13 (обычная опасность)."},
  {id:437, q:"Для стандартных спринклеров распыления в лёгкой опасности (гладкий потолок, негорючая/ограниченно горючая конструкция) максимальное расстояние между спринклерами обычно составляет:", opts:["15 футов","12 футов","18 футов","20 футов"], re:"Максимальное расстояние между стандартными спринклерами распыления в лёгкой опасности составляет 15 футов. Источник: требования к расстояниям NFPA 13 (лёгкая опасность)."},
  {id:438, q:"Для стандартных спринклеров распыления минимальное расстояние между двумя спринклерами (если не используется сертифицированный отбойник/перегородка) обычно составляет:", opts:["3 фута","4 фута","8 футов","6 футов"], re:"Минимальное расстояние от центра до центра между стандартными спринклерами распыления составляет 6 футов, если не установлена подходящая перегородка, чтобы предотвратить холодное запаивание. Источник: минимальное расстояние / перегородки NFPA 13."},
  {id:439, q:"Минимальное расстояние 6 футов между стандартными спринклерами распыления предназначено главным образом для предотвращения:", opts:["Коррозии трубы","Холодного запаивания (разбрызгивание одного спринклера охлаждает/пропускает соседний)","Чрезмерного расхода краски","Высокого давления воды"], re:"Минимум 6 футов предотвращает холодное запаивание, когда разбрызгивание от одного работающего спринклера смачивает/охлаждает соседний спринклер и задерживает или препятствует его срабатыванию. Источник: обоснование минимального расстояния NFPA 13."},
  {id:440, q:"Для стандартных спринклеров распыления максимальное расстояние от спринклера до стены обычно составляет:", opts:["Равно полному расстоянию между спринклерами","Половину допустимого расстояния между спринклерами","Всегда 10 футов","Всегда 2 фута"], re:"Максимальное расстояние от спринклера до стены равно половине максимально допустимого расстояния между спринклерами (например, 7.5 фута для раскладки в 15 футов). Источник: расстояние до стен NFPA 13."},
  {id:441, q:"Для раскладки обычной опасности с максимальным расстоянием 15 футов между спринклерами максимальное расстояние от спринклера до стены составляет:", opts:["7.5 фута","5 футов","10 футов","15 футов"], re:"Половина от 15 футов — это 7.5 фута, максимальное расстояние до стены для такой раскладки. Источник: расстояние до стен NFPA 13 (правило половины расстояния)."},
  {id:442, q:"Для стандартных спринклеров распыления в занятости повышенной опасности максимальная защищаемая площадь на спринклер обычно составляет:", opts:["100 кв. футов","130 кв. футов","225 кв. футов","300 кв. футов"], re:"Стандартные спринклеры распыления повышенной опасности имеют максимальную защищаемую площадь 100 кв. футов на спринклер (90 кв. футов для некоторых гидравлически рассчитанных проектов высокой плотности). Источник: защищаемая площадь покрытия NFPA 13 (повышенная опасность)."},
  {id:443, q:"Для стандартных спринклеров распыления повышенной опасности (и гидравлически рассчитанных высокой плотности) максимальное расстояние между спринклерами обычно составляет:", opts:["15 футов","12 футов","20 футов","18 футов"], re:"Раскладки повышенной опасности ограничивают максимальное расстояние до 12 футов между стандартными спринклерами распыления. Источник: расстояния NFPA 13 (повышенная опасность)."},
  {id:444, q:"Защищаемая площадь покрытия для стандартного спринклера распыления определяется умножением:", opts:["Диаметра трубы на длину","Коэффициента K спринклера на давление","Высоты потолка на ширину помещения","Расстояния вдоль распределительной линии (S) на расстояние между распределительными линиями (L)"], re:"Защищаемая площадь = S x L, где S — размер вдоль распределительной линии, а L — размер между распределительными линиями, и не должна превышать табличный максимум для данной опасности. Источник: метод защищаемой площади покрытия NFPA 13."},
  {id:445, q:"«Правило малого помещения» NFPA 13 применяется к отсеку, который является лёгкой опасностью, имеет конструкцию без препятствий и не больше:", opts:["400 кв. футов","800 кв. футов","600 кв. футов","1,200 кв. футов"], re:"«Малое помещение» — это отсек лёгкой опасности с конструкцией без препятствий и площадью пола не более 800 кв. футов. Источник: определение малого помещения NFPA 13."},
  {id:446, q:"Когда применяется правило малого помещения, на каком расстоянии от любой отдельной стены разрешается размещать спринклер?", opts:["6 футов","9 футов","7.5 фута","12 футов"], re:"По правилу малого помещения спринклеры могут размещаться на расстоянии до 9 футов от любой отдельной стены, что более свободно, чем стандартное расстояние 7.5 фута до стены для лёгкой опасности. Источник: правило малого помещения NFPA 13."},
  {id:447, q:"Спринклеры расширенного покрытия (EC) отличаются от стандартных спринклеров распыления тем, что они:", opts:["Не могут использоваться в помещениях","Всегда используют меньше воды","Не имеют требований к сертификации","Сертифицированы для защиты больших площадей пола при заданных расстояниях"], re:"Спринклеры расширенного покрытия специально сертифицированы для покрытия больших площадей (например, до 400 кв. футов в лёгкой опасности) при расстояниях, указанных в их сертификации. Источник: спринклеры расширенного покрытия NFPA 13."},
  {id:448, q:"Для спринклеров расширенного покрытия расстояние и покрытие, которые могут использоваться, регулируются:", opts:["Только стандартными таблицами распыления","Сортаментом труб","Предпочтением подрядчика","Индивидуальной сертификацией спринклера"], re:"Расстояние/покрытие спринклера EC должно соответствовать конкретной сертификации этого спринклера, которая может превышать стандартные максимумы распыления. Источник: расширенное покрытие / требования сертификации NFPA 13."},
  {id:449, q:"В раскладке лёгкой опасности максимальная защищаемая площадь на спринклер и максимальное расстояние в совокупности ограничивают покрытие приблизительно до:", opts:["Любой площади по выбору проектировщика","Площади 20 футов x 20 футов","Площади 25 футов x 25 футов","Площади 15 футов x 15 футов, не превышающей 225 кв. футов"], re:"Стандартные спринклеры распыления лёгкой опасности ограничены максимальным расстоянием 15 футов И максимальной защищаемой площадью 225 кв. футов, поэтому сетка 15x15 (225 кв. футов) находится на пределе. Источник: расстояния и покрытие NFPA 13 (лёгкая опасность)."},
  {id:450, q:"Если рассчитанная защищаемая площадь (S x L) для оросителя превышает табличный максимум для занятости, проектировщик должен:", opts:["Ещё больше увеличить расстояние","Игнорировать таблицу","Добавить спринклеры / уменьшить расстояние, чтобы каждый ороситель оставался в пределах максимальной площади","Использовать больший дренаж"], re:"Каждый спринклер должен защищать не больше своей табличной максимальной площади; если S x L слишком велико, расстояние нужно уменьшить (добавить больше спринклеров). Источник: пределы защищаемой площади покрытия NFPA 13."},
  {id:451, q:"Спринклеры должны располагаться так, чтобы их фактическое покрытие было в пределах как максимальной площади, ТАК И максимального расстояния, потому что:", opts:["Важна только площадь","Любой предел по отдельности может оставить разрыв в покрытии или перегрузить ороситель","Важно только расстояние","Ни один предел не применяется в помещениях"], re:"Оба предела применяются одновременно; соблюдение площади при превышении расстояния (или наоборот) может оставить незащищённые разрывы, поэтому контролирует более строгий. Источник: расстояния и защищаемая площадь покрытия NFPA 13."},
  {id:452, q:"NFPA 13 требует минимальный зазор между верхом складирования и дефлекторами спринклеров не менее:", opts:["6 in","12 in","36 in","18 in"], re:"Требуется минимальный зазор 18 in (457 мм) между верхом складирования и дефлекторами спринклеров, чтобы картины распыления могли развернуться и перекрыться. Источник: зазор до складирования NFPA 13."},
  {id:453, q:"Зазор 18 in от дефлектора до верха складирования существует главным образом для того, чтобы:", opts:["Позволить картине распыления развернуться и перекрыться для предварительного смачивания горючих материалов","Сэкономить стоимость материала","Освободить место для освещения","Уменьшить размер трубы"], re:"Свободное пространство позволяет разбрызгиванию спринклера развернуться веером и перекрыться, чтобы горючие материалы предварительно смачивались; слишком близкое складирование блокирует развитие картины. Источник: обоснование зазора до складирования NFPA 13."},
  {id:454, q:"Для складирования резиновых шин NFPA 13 обычно требует зазор до дефлекторов не менее:", opts:["18 in","24 in","12 in","36 in"], re:"Складирование резиновых шин требует большего зазора не менее 36 in (900 мм) до дефлекторов спринклеров. Источник: зазор до складирования NFPA 13 (резиновые шины)."},
  {id:455, q:"Для стандартных спринклеров распыления при конструкции без препятствий дефлектор должен располагаться ниже потолка в диапазоне:", opts:["от 6 in до 24 in","от 0 in до 4 in","от 1 in до 12 in","от 12 in до 36 in"], re:"При конструкции без препятствий дефлекторы стандартных подвесных/розеточных спринклеров распыления должны быть от 1 in до 12 in ниже потолка (скрытые/утопленные типы согласно их сертификации). Источник: расстояние ниже потолков / положение дефлектора NFPA 13."},
  {id:456, q:"«Правило трёхкратного расстояния» NFPA 13 для стандартных спринклеров распыления требует, чтобы спринклер располагался от препятствия на расстоянии не менее:", opts:["Двукратного размера препятствия","Половины размера препятствия","Трёхкратного максимального размера препятствия","Десяти футов независимо от размера"], re:"Правило трёхкратного расстояния располагает спринклер не менее чем на 3-кратный максимальный размер препятствия от него (с ограничением 24 in), чтобы разбрызгивание могло проходить с обеих сторон. Источник: препятствия для разбрызгивания NFPA 13 (расположение вдали от препятствий)."},
  {id:457, q:"По правилу трёхкратного расстояния для стандартных спринклеров распыления требуемый горизонтальный зазор от препятствия ограничен максимумом:", opts:["12 in","18 in","24 in","48 in"], re:"Правило трёхкратного расстояния не должно превышать 24 in горизонтального зазора для стандартных спринклеров распыления. Источник: препятствия NFPA 13 (правило 3x, максимум 24 in)."},
  {id:458, q:"Для непрерывных препятствий шире 4 футов (например, широких воздуховодов), расположенных ниже спринклеров, NFPA 13 обычно требует:", opts:["Ничего дополнительного","Установки спринклеров под препятствием","Удаления потолочных спринклеров","Удвоения размера трубы"], re:"Препятствия шире 4 футов обычно требуют дополнительных спринклеров, установленных под ними, с дефлекторами, расположенными согласно стандарту. Источник: препятствия NFPA 13 (спринклеры требуются под широкими препятствиями)."},
  {id:459, q:"Когда спринклеры устанавливаются под широким препятствием, NFPA 13 обычно требует, чтобы дефлектор располагался ниже нижней части препятствия в пределах:", opts:["12 in","24 in","36 in","48 in"], re:"Спринклеры, размещённые под широким препятствием, должны иметь дефлекторы, расположенные менее чем на 12 in ниже нижней части препятствия. Источник: препятствия NFPA 13 (дефлектор ниже широкого препятствия)."},
  {id:460, q:"«Правило четырёхкратного расстояния» в NFPA 13 — это расширение правила препятствий, которое применяется к:", opts:["Только стандартным спринклерам распыления","Спринклерам расширенного покрытия","Только сухим подвесным спринклерам","Только внутристеллажным спринклерам"], re:"Правило четырёхкратного расстояния распространяет концепцию расположения при препятствиях на спринклеры расширенного покрытия с большим максимальным зазором (до 36 in). Источник: препятствия NFPA 13 (расширенное покрытие, правило 4x)."},
  {id:461, q:"Препятствие, расположенное на 18 in или более ниже дефлектора и не шире 4 футов, обычно может быть:", opts:["Никогда не разрешено","Обязано иметь собственный стояк (riser)","Не учтено для целей препятствий","Причиной удаления всех потолочных спринклеров"], re:"Препятствие на 18 in или более ниже дефлектора и шириной до 4 футов обычно можно игнорировать, так как картина распыления развилась над ним. Источник: препятствия NFPA 13 (допуск ниже дефлектора)."},
  {id:462, q:"Препятствия, мешающие разбрызгиванию спринклера достичь защищаемой опасности (например, широкие верхние препятствия), рассматриваются NFPA 13, потому что они:", opts:["Улучшают покрытие","Уменьшают трение в трубе","Создают незащищённые теневые зоны под собой","Не имеют эффекта"], re:"Такие препятствия создают «теневые» зоны, которые потолочные спринклеры не могут достичь, требуя дополнительных спринклеров или перерасположения. Источник: препятствия NFPA 13 для развития картины разбрызгивания."},
  {id:463, q:"Минимальное свободное пространство 18 in ниже дефлекторов в зоне складирования лучше всего понимать как:", opts:["Только у одного спринклера","Вертикальную линию у стены","Горизонтальную плоскость, ниже которой должно оставаться всё складирование","Опциональное во всех случаях"], re:"Зазор 18 in трактуется как горизонтальная плоскость по всей зоне складирования; все хранимые материалы должны оставаться ниже этой плоскости. Источник: зазор до складирования NFPA 13 (горизонтальная плоскость)."},
  {id:464, q:"Материалы, хранимые на полках у стены, ниже потолочных спринклеров, трактуются иначе в отношении зазора 18 in, потому что они:", opts:["Не препятствуют перекрытию разбрызгивания от нескольких потолочных спринклеров","Всегда требуют 36 in","Всегда требуют внутристеллажных спринклеров","Никогда не являются горючими"], re:"Пристенное складирование не блокирует перекрытие разбрызгивания от нескольких потолочных спринклеров, как это делает островное складирование, поэтому правило 18 in применяется иначе. Источник: зазор до складирования NFPA 13 (пристенное складирование)."},
  {id:465, q:"Нижние пояса решётчатых ферм, балки и подобные конструктивные элементы — это примеры препятствий, оцениваемых с использованием:", opts:["Коэффициента K","Загрузки людьми","Формулы потерь на трение","Правила балки / правил расстояния до препятствия"], re:"Конструктивные элементы, такие как балки и нижние пояса ферм, оцениваются по правилам препятствий (правило балки) NFPA 13, регулирующим расстояние от спринклера до препятствия и высоту дефлектора. Источник: препятствия для разбрызгивания NFPA 13 (правило балки)."},
  {id:466, q:"Светильники, воздуховоды и подобные неконструктивные элементы, препятствующие разбрызгиванию, в NFPA 13 называются:", opts:["Сертифицированными приборами","Сейсмическими раскосами","Подвесами труб","Препятствиями для разбрызгивания спринклера"], re:"Неконструктивные элементы, блокирующие разбрызгивание, — это «препятствия для разбрызгивания спринклера», и они должны устраняться перерасположением спринклеров или добавлением покрытия. Источник: препятствия для разбрызгивания NFPA 13."},
  {id:467, q:"Поддержание требуемого зазора ниже дефлекторов и надлежащего расстояния от спринклера до препятствия — это в основном ответственность:", opts:["Только пользователя здания после заселения","Проектировщика/монтажника при монтаже и владельца во время эксплуатации","Водоканала","Подрядчика по сигнализации"], re:"Надлежащие зазоры должны проектироваться/монтироваться по NFPA 13, а владелец должен поддерживать их (например, не складировать слишком высоко) во время эксплуатации. Источник: правила зазора/препятствий NFPA 13; обслуживание зазоров NFPA 25."},
  {id:468, q:"Если новый антресольный этаж (mezzanine), воздуховод или перегородка добавляются ниже существующей спринклерной системы, монтажник должен:", opts:["Игнорировать это","Навсегда удалить затронутые спринклеры","Оценить препятствия и добавить или переместить спринклеры, как требует NFPA 13","Только увеличить давление в системе"], re:"Новые препятствия могут создавать теневые зоны; NFPA 13 требует оценить их и добавить/переместить спринклеры для восстановления покрытия. Источник: препятствия NFPA 13; модификации системы."},
  {id:469, q:"В зонах, подверженных землетрясениям, NFPA 13 требует защищать спринклерные трубопроводы от повреждений в основном с помощью:", opts:["Дополнительной окраски","Более крупных спринклерных оросителей","Раскосов от раскачивания, гибких муфт и зазоров","Более высокого давления воды"], re:"Сейсмическая защита использует раскосы от раскачивания, гибкие муфты, фиксацию распределительных линий и зазоры в проходках для сопротивления движению при землетрясении. Источник: сейсмическая защита NFPA 13 (Глава о защите трубопроводов от повреждений при подверженности землетрясениям)."},
  {id:470, q:"Раскосы от раскачивания, сопротивляющиеся движению перпендикулярно ходу трубы, называются:", opts:["Продольными раскосами","Поперечными раскосами","Вертикальными раскосами","Гибкими муфтами"], re:"Поперечные раскосы от раскачивания сопротивляются горизонтальному движению перпендикулярно трубе; продольные раскосы сопротивляются движению параллельно трубе. Источник: определения сейсмических раскосов NFPA 13."},
  {id:471, q:"Раскосы от раскачивания, сопротивляющиеся движению параллельно ходу трубы, называются:", opts:["Поперечными раскосами","Продольными раскосами","Хомутами стояка","Подвесами"], re:"Продольные раскосы сопротивляются движению вдоль (параллельно) хода трубы; поперечные раскосы сопротивляются перпендикулярному движению. Источник: определения сейсмических раскосов NFPA 13."},
  {id:472, q:"На питающих и распределительных магистралях (cross mains) NFPA 13 обычно требует поперечные раскосы от раскачивания с шагом не более:", opts:["40 футов по осям","20 футов","80 футов","100 футов"], re:"Поперечные раскосы от раскачивания размещаются с интервалом не более 40 футов (12 м) по осям вдоль магистралей. Источник: шаг сейсмических раскосов NFPA 13 (поперечные раскосы)."},
  {id:473, q:"На питающих и распределительных магистралях NFPA 13 обычно требует продольные раскосы от раскачивания с шагом не более:", opts:["40 футов","80 футов по осям","60 футов","120 футов"], re:"Продольные раскосы от раскачивания размещаются с интервалом не более 80 футов (24 м) по осям вдоль питающих и распределительных магистралей. Источник: шаг сейсмических раскосов NFPA 13 (продольные раскосы)."},
  {id:474, q:"В верхней части спринклерного стояка (riser) NFPA 13 обычно требует:", opts:["Без раскосов","Только гибкую муфту и ничего больше","Только подвес","Четырёхстороннее (комбинированное поперечное и продольное) раскрепление"], re:"Четырёхстороннее раскрепление (комбинированное поперечное и продольное) требуется в верхней части стояков и там, где стояки проходят через перекрытия. Источник: сейсмические раскосы NFPA 13 (четырёхстороннее раскрепление на стояках)."},
  {id:475, q:"Гибкие муфты на стояках обычно требуются в пределах какого расстояния от верха и низа стояка?", opts:["24 in","12 in","6 in","48 in"], re:"Гибкие муфты требуются в пределах 24 in (610 мм) от верха и низа стояков (с исключениями для очень коротких стояков). Источник: NFPA 13, сейсмика (гибкие муфты на стояках)."},
  {id:476, q:"Гибкие муфты устанавливаются в сейсмических спринклерных системах для того, чтобы:", opts:["Увеличить давление воды","Устранить необходимость в каких-либо раскосах","Допустить контролируемое движение в точках, где ожидается дифференциальное движение","Уменьшить диаметр трубы"], re:"Гибкие муфты компенсируют дифференциальное/относительное движение на стояках, сейсмических швах здания и подобных местах, работая совместно с жёсткими раскосами в других местах. Источник: NFPA 13, сейсмика (назначение гибких муфт)."},
  {id:477, q:"Там, где спринклерный трубопровод пересекает сейсмический деформационный (расширительный) шов здания, NFPA 13 требует:", opts:["Жёсткое сварное соединение","Гибкость/зазор для компенсации движения по обе стороны шва","Удаление трубы","Только удвоение раскрепления"], re:"Трубопровод, пересекающий сейсмические деформационные швы, должен включать средства (гибкие узлы/зазор), позволяющие независимое движение двух секций здания. Источник: узлы сейсмического разделения NFPA 13."},
  {id:478, q:"Зазор требуется вокруг спринклерной трубы там, где она проходит через стены, перекрытия или платформы в сейсмических зонах, чтобы:", opts:["Вода могла вытекать","Трубу можно было покрасить","Труба не была повреждена относительным движением элемента здания","Труба была скрыта"], re:"Зазор (или гибкая гильза) в проходках предотвращает срез или раздавливание трубы жёстким элементом здания при сейсмическом движении. Источник: NFPA 13, сейсмика (зазор в проходках)."},
  {id:479, q:"Требуемый номинальный зазор вокруг трубы от 1 in до 3-1/2 in, проходящей через стены/перекрытия в сейсмических проектах, обычно составляет:", opts:["Около 1 in","Без зазора","Около 2 in","Около 6 in"], re:"NFPA 13 обычно требует номинальный зазор 1 in вокруг трубы от 1 in до 3-1/2 in (и 2 in для 4 in и больше) в проходках, если не предусмотрены гибкие муфты/гильзы. Источник: сейсмический зазор в проходках NFPA 13."},
  {id:480, q:"Узел раскоса от раскачивания должен быть способен сопротивляться нагрузкам в:", opts:["Только направлении вниз","Только направлении вверх","Только горизонтальном потоке воды","Как растяжении, так и сжатии вдоль раскоса"], re:"Сейсмические раскосы от раскачивания должны сопротивляться горизонтальным нагрузкам, действующим в обоих направлениях (растяжение и сжатие) вдоль оси раскоса. Источник: сейсмические раскосы NFPA 13 (направления нагрузки)."},
  {id:481, q:"Участок трубопровода, сейсмическая нагрузка которого воспринимается данным раскосом от раскачивания, называется ___ раскоса:", opts:["Зоной влияния","Зоной трения","Зоной опасности","Ниппелем стояка"], re:"Каждый раскос от раскачивания воспринимает сейсмическую нагрузку определённой «зоны влияния» трубопровода; нагрузки суммируются в пределах этой зоны для расчёта раскоса. Источник: сейсмические раскосы NFPA 13 (зона влияния / расчёт нагрузки)."},
  {id:482, q:"Фиксация конца линии / распределительной линии в сейсмических проектах предназначена для того, чтобы:", opts:["Увеличить расход","Ограничить чрезмерное поперечное движение нераскреплённых концов распределительной линии","Заменить все подвесы","Снизить потребность в воде"], re:"Фиксация распределительной линии и концов ограничивает поперечное раскачивание трубы, которая иначе не раскреплена, снижая вероятность поломки на фитингах/спринклерах. Источник: NFPA 13, сейсмика (фиксация распределительных линий)."},
  {id:483, q:"Компоненты сейсмического раскрепления, такие как раскосы, крепёж и крепления к конструкции, должны быть:", opts:["Сертифицированы/одобрены и установлены к конструкции, способной нести нагрузку","Любой имеющийся под рукой крепёж","Изготовлены из дерева","Опциональны во всех юрисдикциях"], re:"Элементы раскосов, фитинги и крепления к конструкции должны быть сертифицированы/одобрены и закреплены к конструкции здания, способной сопротивляться расчётным сейсмическим нагрузкам. Источник: сейсмические раскосы NFPA 13 (компоненты и крепление к конструкции)."},
  {id:484, q:"В Калифорнии сейсмическая защита спринклерных трубопроводов требуется, потому что:", opts:["Она полностью опциональна везде","Только прибрежные города имеют землетрясения","Значительная часть штата находится в зонах высокого сейсмического риска, и кодексы это предписывают","Вода замерзает в Калифорнии"], re:"Высокая сейсмическая активность Калифорнии приводит к тому, что CFC/NFPA 13 требуют сейсмическую защиту спринклерных систем по всему штату в применимых зонах. Источник: сейсмическая глава NFPA 13; сейсмические положения California Building Standards."},
  {id:485, q:"В Калифорнии классификация CSLB для подрядчика по противопожарной защите — это:", opts:["C-10","C-36","C-16","C-20"], re:"C-16 — это классификация CSLB для подрядчика по противопожарной защите. Источник: CSLB Licensing Classifications, C-16 Fire Protection."},
  {id:486, q:"Классификация CSLB C-16 разрешает подрядчику разрабатывать, изготавливать и монтировать:", opts:["Только электропроводку пожарной сигнализации","Все типы систем противопожарной защиты (исключая электрические системы сигнализации)","Только бытовые дымовые извещатели","Только подземные газопроводы"], re:"Подрядчик C-16 разрабатывает, изготавливает и монтирует все типы систем противопожарной защиты и связанное оборудование, исключая электрические системы сигнализации. Источник: описание классификации C-16 CSLB (CCR Title 16 §832.16)."},
  {id:487, q:"Электропроводка систем пожарной сигнализации обычно выходит за рамки C-16 и вместо этого относится к какой классификации?", opts:["C-16","C-36 (Сантехника)","C-10 (Электрика)","C-4 (Котлы)"], re:"Электропроводка систем сигнализации исключена из C-16 и выполняется по электрической классификации C-10. Источник: описание C-16 CSLB (исключает электрические системы сигнализации); C-10 Electrical."},
  {id:488, q:"Персонал, монтирующий или ремонтирующий водяные системы противопожарной защиты по лицензии C-16 для коммерческих/многоквартирных проектов, обычно должен иметь:", opts:["Лицензию риелтора","Полномочия нотариуса","Сантехническую лицензию C-36","Сертификат монтажника спринклеров (Fire Sprinkler Fitter)"], re:"Квалификаторы C-16 и работники уровня подмастерья, монтирующие/ремонтирующие водяные системы противопожарной защиты для коммерческих или многоквартирных зданий, должны получить сертификат Fire Sprinkler Fitter. Источник: CSLB Industry Bulletin 24-02; требования к fire sprinkler fitter Кодекса H&S."},
  {id:489, q:"Сама CSLB входит в состав какого департамента Калифорнии?", opts:["Department of Consumer Affairs","CAL FIRE","Caltrans","Franchise Tax Board"], re:"Contractors State License Board (CSLB) входит в состав California Department of Consumer Affairs. Источник: CSLB / Department of Consumer Affairs."},
  {id:490, q:"Перед началом большинства коммерческих монтажей спринклеров пожаротушения подрядчик обычно должен получить:", opts:["Совсем ничего","Только испытание расхода гидранта","Только визитную карточку","Разрешение на строительство/пожарное разрешение и утверждённые проекты от AHJ"], re:"Разрешение и утверждённые AHJ проекты обычно требуются перед монтажом спринклерной системы пожаротушения; работа без разрешения может быть нарушением кодекса. Источник: California Fire Code §105 разрешения; CFC §901.2 экспертиза проекта."},
  {id:491, q:"Рабочие чертежи спринклеров (монтажные чертежи), подаваемые на утверждение, обычно подготавливаются/утверждаются:", opts:["Любым лицом без лицензии","Квалифицированными лицами и проверяются/утверждаются AHJ (и проектировщиком, где требуется)","Снимающим показания водомера","Пользователем здания"], re:"Рабочие чертежи подготавливаются квалифицированными лицами и должны быть проверены/утверждены AHJ перед монтажом; многие проекты также требуют зарегистрированного проектировщика. Источник: рабочие чертежи NFPA 13; CFC §901.2."},
  {id:492, q:"После монтажа и перед вводом спринклерной системы в эксплуатацию NFPA 13 требует, чтобы подрядчик выполнил и задокументировал:", opts:["Никаких испытаний","Только инспекцию окраски","Только визуальный осмотр","Приёмочные испытания, включая гидростатическое испытание и промывку (flushing)"], re:"Приёмочные испытания (гидростатическое испытание, промывка подземных трубопроводов/вводов, испытание главного дренажа и т. д.) должны быть выполнены и задокументированы перед приёмкой системы. Источник: приёмка системы NFPA 13 (гидростатическое испытание 200 psi / 50 psi выше статического в течение 2 часов)."},
  {id:493, q:"Стандартное гидростатическое приёмочное испытание новой спринклерной системы по NFPA 13 обычно составляет:", opts:["200 psi (или 50 psi выше статического, если статическое превышает 150 psi) в течение 2 часов","50 psi в течение 30 минут","1,000 psi в течение 24 часов","Без давления, только вода"], re:"Новый спринклерный трубопровод испытывается гидростатически при 200 psi в течение 2 часов (или 50 psi выше статического там, где статическое давление превышает 150 psi). Источник: гидростатическое испытание NFPA 13 (приёмка)."},
  {id:494, q:"По завершении NFPA 13 требует, чтобы монтирующий подрядчик предоставил владельцу:", opts:["Ничего","Только оригинал заказа на покупку","Только устное подтверждение","Сертификат на материалы и испытания подрядчика (Contractor's Material and Test Certificate)"], re:"Монтирующий подрядчик должен заполнить и предоставить Сертификат на материалы и испытания подрядчика, документирующий материалы, испытания и результаты. Источник: Contractor's Material and Test Certificate NFPA 13."},
  {id:495, q:"Ответственность подрядчика C-16 за спринклерную систему пожаротушения обычно включает:", opts:["Только продажу деталей","Проектирование/разработку, монтаж, испытание и предоставление требуемой документации согласно кодексу","Только окраску трубы","Только инспекцию работы других подрядчиков"], re:"Подрядчик C-16 разрабатывает/проектирует, изготавливает, монтирует, испытывает и предоставляет требуемую документацию для системы противопожарной защиты в рамках классификации. Источник: описание C-16 CSLB; монтаж и приёмка NFPA 13."},
  {id:496, q:"Монтаж спринклерных систем пожаротушения в Калифорнии без надлежащей лицензии подрядчика может привести к:", opts:["Дисциплинарным мерам, штрафам и неисполнимым договорам","Похвале","Автоматическому повышению лицензии","Ничему по закону"], re:"Подрядная деятельность без лицензии в Калифорнии незаконна и может привести к штрафам, дисциплинарным мерам и договорам, которые юридически неисполнимы стороной без лицензии. Источник: California Business & Professions Code §7028 и далее; правоприменение CSLB."},
  {id:497, q:"Общий установленный законом денежный порог, выше которого требуется лицензия подрядчика для отдельной строительной работы в Калифорнии, составляет:", opts:["$100 или более","$5,000 или более","$500 или более (работа и материалы)","$50,000 или более"], re:"Лицензия подрядчика CSLB обычно требуется, когда совокупная стоимость работы и материалов составляет $500 или более. Источник: California Business & Professions Code §7048; CSLB."},
  {id:498, q:"Системы сухотрубов/стояков (standpipe) (например, пожарные краны NFPA 14 для использования пожарной службой) относятся к области какой классификации как водяная противопожарная защита?", opts:["Только C-10","Только C-20","C-16 Противопожарная защита","Только B Общее строительство"], re:"Системы стояков (водяные) являются частью области противопожарной защиты C-16 по монтажу всех типов систем противопожарной защиты. Источник: описание C-16 CSLB; стояки NFPA 14."},
  {id:499, q:"Когда спринклерная система пожаротушения подключается к общественному водоснабжению, подрядчик также должен согласовать с поставщиком воды вопросы:", opts:["Цвета окраски стен","Выбора ковра","Предотвращения обратного потока (backflow) и сервисного присоединения","Кровельной черепицы"], re:"Подключение к общественному водоснабжению требует согласования предотвращения обратного потока и сервисного присоединения с поставщиком воды/AHJ. Источник: California Plumbing Code / требования AHJ к обратному потоку; присоединение водоснабжения NFPA 13."},
  {id:500, q:"Подрядчик C-16, выполняющий работу, которая требует лишь сопутствующих и вспомогательных задач другого ремесла для завершения проекта противопожарной защиты, может:", opts:["Выполнить эту сопутствующую и вспомогательную работу как часть проекта C-16","Никогда не касаться работы любого другого ремесла","Должен нанимать генерального подрядчика для каждого винта","Автоматически лишиться лицензии"], re:"Правила CSLB позволяют специализированному подрядчику брать и выполнять работу, которая является сопутствующей и вспомогательной по отношению к выполнению работы того ремесла, на которое выдана лицензия. Источник: CSLB CCR Title 16 §831 (сопутствующее и вспомогательное)."}
];
